UINT8  PicoType;                                // contain type of microcontroller used (TYPE_PICO or TYPE_PICOW).
UINT8  RowScan = 0;                             // current matrix row being scanned.
UINT8  TargetCallback = CALLBACK_1MS;           // target callback to evaluate its duration.
