UINT8  WinBot;                                  // currently active window for bottom of matrix.

UINT16 *ActiveCrcAddress[MAX_FLASH_SECTORS];     // address in RAM memory of each configuration sector CRC.
UINT16  AlarmBitMask;                            // bitmask of currently triggered alarms (when not already shut off by user).
UINT16  AmbientLight[BRIGHTNESS_HYSTERESIS_SECONDS];  // ambient light readings for the last seconds.
UINT16  AutoScrollScheduleMask;                  // bitmask of the auto-scrolls to be currently processed.
UINT16  AverageAmbientLight;                     // average ambient light value for the last "hysteresis" number of seconds.
UINT16  BrightnessLevel;                         // LED matrix current brightness level.
UINT16  CallbackCounter = 0;                     // counter to update callback timing report at regular intervals.
UINT16  CallbackDurationPointer;                 // pointer to the next slot in the circular buffer.
UINT16 *FlashCrcAddress[MAX_FLASH_SECTORS];      // address in flash memory of each configuration sector CRC.
UINT16  FunctionHiLimit;                         // one more than the last defined function.
UINT16  ServiceLightTimer;                       // count-down timer for Service Light (in seconds).
UINT16  TargetTime[MAX_CALLBACK_DURATION_UNITS];
UINT16  WatchDogCore0;                           // number being automatically incremented every second inside main core0 endless loop.
