UINT16  WatchDogCore0Miss;
UINT16  WatchDogCore1Miss;

UINT32  FlashConfigOffset[MAX_FLASH_SECTORS];    // offset in flash memory for each configuration sector.
UINT32  FlashTargetOffset;                       // target offset in flash for next flash operation.

INT64 CallbackDuration[MAX_CALLBACK_DURATION_UNITS];  // to check callback functions duration.
INT64 Dum1Int64;

UINT64 BlinkBuffer[MAX_ROWS];                 // temporary bitmask buffer of FrameBuffer LED positions being blinked.
UINT64 CheckBuffer[MAX_ROWS];                 // bitmask of active LED blinking area.
