/* Utility to convert a binary-coded-decimal value to a decimal value. */
UINT8 util_bcd2dec(UINT8 BCDValue);

/* Find the cyclic redundancy check of the specified data. */
UINT16 util_crc16(UINT8 *Data, UINT16 DataSize);

/* Utility to convert a decimal value to binary-coded-decimal value. */
UINT8 util_dec2bcd(UINT8 DecimalValue);

/* Display data whose pointer is sent in argument through external terminal. */
void util_display_data(UINT8 *Data, UINT32 DataSize, UINT8 FlagHeader);

/* Reverse the bit order of the UINT8 value given in argument. */
UINT8 util_reverse_8bits(UINT8 InputData);

/* Reverse the bit order of the UINT64 value given in argument. */
UINT64 util_reverse_64bits(UINT64 InputData);

/* Convert a string to lowercase. */
UCHAR *util_to_lower(UCHAR *String);

/* Return the string representing the uint64_t value in binary. */
void util_uint64_to_binary_string(UINT64 Value, UINT8 StringLength, UCHAR *BinaryString);

/* Setup blink parameters for specific window area. Blinking itself is managed by the 1-second callback. */
void win_blink(UINT8 WindowNumber, UINT8 StartRow, UINT8 StartColumn, UINT8 EndRow, UINT8 EndColumn);

/* Turn Off blinking on the specific window area. */
void win_blink_off(UINT8 WindowNumber, UINT8 StartRow, UINT8 StartColumn, UINT8 EndRow, UINT8 EndColumn);

/* Close the specified window and restore the backlink. */
void win_close(UINT8 WindowNumber, UINT8 FlagImplodeWindow);

/* Clear the specified window. */
void win_cls(UINT8 WindowNumber);

/* Initialize window structures. */
void win_init();

/* Explode / open the specified window. */
void win_open(UINT8 WindowNumber, UINT8 FlagExplodeWindow, UINT8 FlagRestore);

/* Clear the specified part of the specified window. */
void win_part_cls(UINT8 WindowNumber, UINT8 StartRow, UINT8 EndRow);

/* Print data in the specified window. */
UINT8 win_printf(UINT8 WindowNumber, UINT8 StartRow, UINT8 StartColumn, UINT8 FontType, UCHAR *Format, ...);

/* Scroll the text in the specified window, on the specified line. Return ScrollNumber that has been assigned. */
UINT8 win_scroll(UINT8 WindowNumber, UINT8 StartRow, UINT8 EndRow, UINT16 ScrollTimes, UINT8 ScrollSpeed, UINT8 FontType, UCHAR *Format, ...);

/* If there is currently a scroll going on, cancel it and add a few character spaces to introduce new scrolling. */
void win_scroll_cancel(UINT8 WindowNumber, UINT8 StartRow, UINT8 EndRow);

/* Housekeeping when a scroll has been completed. */
void win_scroll_off(UINT8 ScrollNumber);

/* Set the colors of the specified window. */
void win_set_color(UINT8 WindowNumber, UINT8 InsideColor, UINT8 BoxColor);




#ifdef REMOTE_SUPPORT
/* ------------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                          Infrared remote control related function prototypes
\* ------------------------------------------------------------------------------------------------------------------------------------------------------------- */
/* Function to decode an infrared remote control button keystroke received using the "Car MP3" RGB Matrix remote control. */
UINT8 ir_decode_button(UINT8 *IrButton);

/* Display timings of the last received infrared data stream. This function must not be used inside a callback function (would crash the Firmware). */
void ir_display_timings(void);
/* ------------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                              End of IR sensor-related function prototypes
\* ------------------------------------------------------------------------------------------------------------------------------------------------------------- */
#endif  // REMOTE_SUPPORT



#ifdef MQTT_SUPPORT
/* Broadcast current time to all SLASH devices. */
void mqtt_broadcast_time(void);

/* Receiving the result for a MQTT connection. */
void mqtt_connection_cb(mqtt_client_t *LocalClient, void *ExtraArgument, mqtt_connection_status_t Status);

/* Subscribe to all required MQTT topics. */
void mqtt_device_subscribe(void);

/* Processing the data received from a subscribed topic. */
void mqtt_incoming_data_cb(void *ExtraArgument, const UINT8 *Data, UINT16 DataLength, UINT8 Flags);

/* Receiving a topic for which we did subscribe. */
void mqtt_incoming_publish_cb(void *ExtraArgument, const char *Topic, UINT32 PayloadLength);

/* Initialize MQTT client and setup connection with MQTT broker. */
static void mqtt_initialization(void);

/* Process a <HScroll> topic received via MQTT protocol. */
void mqtt_process_hscroll(void);

/* Process a <set> topic received via MQTT protocol. */
void mqtt_process_set(void);

/* Process a <OutLight> topic received via MQTT protocol. */
void mqtt_process_outlight(void);

/* Process a <OutTemp> topic received via MQTT protocol. */
void mqtt_process_outtemp(void);

/* Callback in response to a publishing on a specific topic. */
void mqtt_pub_request_cb(void *ExtraArgument, err_t Result);

/* Callback in response to a subscribe request. */
void mqtt_sub_request_cb(void *ExtraArgument, err_t Result);
#endif  // MQTT_SUPPORT





/* $PAGE */
/* $TITLE=Main program entry point. */
/* ============================================================================================================================================================= *\
                                                                        Main program entry point.
\* ============================================================================================================================================================= */
int main(void)
{
  // UCHAR String[32];

  UINT16 Delay;
  UINT16 Dum1UInt16;
  UINT16 Loop1UInt16;
  UINT16 SlowFactor = 2000;  // delay (in msec) while debugging startup sequence.
  UINT16 WaitTime;

  datetime_t DateTime;



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                      Set DebugBitMask for logical sections of code to be debugged through an external terminal.
           NOTE: It is better to dynamically use the terminal menu to toggle a debug section instead of using this compile time option whenever possible.
                                                  (Must be hard-coded below if we want to debug startup sequence).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  DebugBitMask = DEBUG_NONE;            // initialize as no debug section on entry.

#ifdef DEVELOPER_VERSION                // leave debug section clean on release version, but it is still available for change in terminal menu.
  /* Uncomment sections for which we want debug information. DEVELOPER_VERSION must be defined for debug info to be displayed. */
  // DebugBitMask += DEBUG_ALARM;       // debug alarm algorithm.
  // DebugBitMask += DEBUG_BLINK;       // debug blinking mechanism.
  // DebugBitMask += DEBUG_BLUETOOTH;   // debug bluetooth communications (for later use).
  // DebugBitMask += DEBUG_BOX;         // debug exploding windows on LED display.
  // DebugBitMask += DEBUG_BRIGHTNESS;  // debug brightness algorithm.
  // DebugBitMask += DEBUG_BUTTON;      // debug local button handling.
  // DebugBitMask += DEBUG_CORE;        // debug Pico's core 1 thread.
  // DebugBitMask += DEBUG_DS3231;      // debug DS3231 real-time IC.
  // DebugBitMask += DEBUG_EVENT;       // debug calendar event algorithm.
  // DebugBitMask += DEBUG_FLASH;       // debug flash memory operations.
  // DebugBitMask += DEBUG_FLOW;        // debug program sequence flow.
  // DebugBitMask += DEBUG_FUNCTION;    // debug IR <Functions> operation.
  // DebugBitMask += DEBUG_INDICATORS;  // debug indicators on LED display.
  // DebugBitMask += DEBUG_IR;          // debug infrared remote control.
  // DebugBitMask += DEBUG_MATRIX;      // debug LED matrix display operations.
  // DebugBitMask += DEBUG_MQTT;        // debug MQTT protocol.
  // DebugBitMask += DEBUG_NTP;         // debug Network Time Protocol.
  // DebugBitMask += DEBUG_PWM;         // debug PWM mechanism.
  // DebugBitMask += DEBUG_REMINDER;    // debug reminder1 algorithm.
  // DebugBitMask += DEBUG_SCROLL;      // debug scrolling mechanism.
  // DebugBitMask += DEBUG_SERVICE;     // debug service light algorithm.
  // DebugBitMask += DEBUG_SOUND_QUEUE; // debug queue engines.
  // DebugBitMask += DEBUG_STARTUP;     // debug startup sequence.
  // DebugBitMask += DEBUG_DST_TIME;    // debug Daylight Saving Time related logic.
  // DebugBitMask += DEBUG_TEST;        // debug test section.
  // DebugBitMask += DEBUG_WATCHDOG;    // debug watchdog behavior.
  // DebugBitMask += DEBUG_WIFI;        // debug Wi-Fi communications.
  // DebugBitMask += DEBUG_WINDOW;      // debug window algorithm.
#endif  // DEVELOPER_VERSION



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                  Handling of special characters for languages other than English.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
#if FIRMWARE_LANGUAGE == LANGUAGE_FRENCH
  MonthName[2][1]  = 0x0F;  // Fevrier
  MonthName[8][2]  = 0x1C;  // Aout
  MonthName[12][1] = 0x0F;  // Decembre

  DayPeriod[1][3] = 0x10;  // apres-midi
#endif



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                            Initializations.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  DSTEnd = 0ll;                                // Daylight Saving Time: assign invalid value on entry.
  stdio_init_all();                            // initialize GPIOs.
  RGB_matrix_device_init();                    // RGB Matrix brightness will be set to 0%.
  memset(Separator, 0x3D, MAX_SCREEN_WIDTH);   // <=> for screen formatting.
  Separator[MAX_SCREEN_WIDTH] = '\n';          // add end-of-string.
  memset(Separator1, 0x2D, MAX_SCREEN_WIDTH);  // <-> for screen formatting.
  Separator1[MAX_SCREEN_WIDTH] = '\n';         // add end-of-string.
  sleep_ms(500);                               // let some time for UART to be properly setup before sending data to terminal.
  log_printf(__LINE__, __func__, "cls");       // clear terminal screen on entry.
  log_printf(__LINE__, __func__, "home");      // "home" terminal cursor on entry.
  log_printf(__LINE__, __func__, "LOG MASK %X", LOG_LINE + LOG_CORE + LOG_FUNCTION);  // turn Off time stamping of logged data until real-time clock has been initialized.
  if (DebugBitMask & DEBUG_STARTUP)
  {
    beep_tone(2);    // let user know we have a few seconds to start terminal emulator.
    log_printf(__LINE__, __func__, Separator);
    log_printf(__LINE__, __func__, "<120>Beginning of start-up sequence...\n");
    log_printf(__LINE__, __func__, Separator);
    log_printf(__LINE__, __func__, "RGB_matrix_device_init() has been completed\n");
    log_printf(__LINE__, __func__, "LED matrix brightness has been turned Off for startup sequence.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  
  ActiveConfig[0] = &ActiveConfig0;
  ActiveConfig[1] = &ActiveConfig1;
  if (sizeof(ActiveConfig0) != FLASH_SECTOR_SIZE)
  {
    log_printf(__LINE__, __func__, Separator);
    log_printf(__LINE__, __func__, "<120>FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL\n");
    log_printf(__LINE__, __func__, "<120>Size of ActiveConfig0 is different than flash sector size (%u VS %u)\n", sizeof(ActiveConfig0), FLASH_SECTOR_SIZE);
    log_printf(__LINE__, __func__, "<120>Fix the problem and start over again...\n");
    log_printf(__LINE__, __func__, Separator);
    sleep_ms(30000);
  }

  if (sizeof(ActiveConfig1) != FLASH_SECTOR_SIZE)
  {
    log_printf(__LINE__, __func__, Separator);
    log_printf(__LINE__, __func__, "<120>FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL   FATAL\n");
    log_printf(__LINE__, __func__, "<120>Size of ActiveConfig1 is different than flash sector size (%u VS %u)\n", sizeof(ActiveConfig1), FLASH_SECTOR_SIZE);
    log_printf(__LINE__, __func__, "<120>Fix the problem and start over again...\n");
    log_printf(__LINE__, __func__, Separator);
    sleep_ms(30000);
  }

  for (Loop1UInt16 = 0; Loop1UInt16 < MAX_FLASH_SECTORS; ++Loop1UInt16)
  {
    ActiveCrcAddress[Loop1UInt16]  = (UINT16 *)((UINT32)ActiveConfig[Loop1UInt16] + FLASH_SECTOR_SIZE - sizeof(Config1.Crc16));
    FlashConfig[Loop1UInt16]       = (UINT8 *)XIP_BASE + FLASH_FIRST_SECTOR - (FLASH_SECTOR_SIZE * Loop1UInt16);
    FlashConfigOffset[Loop1UInt16] = 0x1FF000 - (0x1000 * Loop1UInt16);  // offset in flash memory for each configuration sector.
    FlashCrcAddress[Loop1UInt16]   = (UINT16 *)((UINT32)FlashConfig[Loop1UInt16] + FLASH_SECTOR_SIZE - sizeof(Config1.Crc16));
  }


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                         Start 1 msec callback in charge of LED matrix scan.
     NOTE: The 1 msec callback is in charge of LED matrix scan. If the scan stops, two LED lines (one in the upper half and the other in the lower half) will
           be "overbright" because the scan won't switch the On time between all matrix lines. This could negatively affect the LED matrix life span. For this
           reason, the watchdog will make sute that the scan is always active (or restart the Firmware otherwise).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before launching 1 msec callback for LED matrix scan.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  add_repeating_timer_ms(-1, callback_1msec_timer, NULL, &Handle1MSecTimer);
  watchdog_enable(1000, false);  // device will restart after 1000 msec (1 second) if the 1 msec callback crashes (maximum watchdog delay is 8388 msec = 8.4 sec).



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                Now that matrix scan has started, check if user wants to toggle Pico in upload mode ("bootsel"). 
                    In this case, clear LED matrix, set brightness to zero, disable interrupts and toggle the Pico in upload mode ("bootsel").
                  1st pass -  Provide a failover method to trigger upload ("bootsel") mode in case there is a crash at the beginning of the code,
                                            before user has access to terminal menu and / or remote control commands.
                              This will prevent the need to disassemble the RGB Matrix to get access to the BootSel button on Pico.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before polling <Down>, <Set> and <Up> buttons a first time to toggle Pico in upload (bootsel) mode.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  if ((!gpio_get(BUTTON_UP_GPIO)) || (!gpio_get(BUTTON_SET_GPIO)) || (!gpio_get(BUTTON_DOWN_GPIO)))
  {
    log_printf(__LINE__, __func__, "One of <Down>, <Set> or <Up> button has been pressed during startup sequence. Toggle Pico in upload mode.\n");
    RGB_matrix_cls(FrameBuffer);
    RGB_matrix_set_brightness(0);
    pwm_on_off(PWM_ID_BRIGHTNESS, FLAG_OFF);
    sleep_ms(100);  // make sure message has been displayed on terminal before toggling Pico in upload mode.
    save_and_disable_interrupts();
    reset_usb_boot(0l, 0l); 
    sleep_ms(2000);
  }
  else
  {
    log_printf(__LINE__, __func__, "None of <Down>, <Set> or <Up> button has been pressed at the first checkpoint.\n");
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                            Initialize FrameBuffer structure to control LED matrix update from ShadowBuffer.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing LED matrix update structure.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  DisplayMatrix.FlagUpdate = FLAG_OFF;
  DisplayMatrix.RowMask    = 0ll;



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                         Display message to user to let him know that it is time to start an external terminal emulator prpogram if he wants
                                  to control many features / options / configuration of the RGB matrix through this external monitor.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before message on LED matrix asking to start terminal.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  sleep_ms(1000);
  if (DebugBitMask & DEBUG_BRIGHTNESS) log_printf(__LINE__, __func__, "Turn LED matrix brightness to temporary level for <Turn On terminal> message.\n");
  RGB_matrix_set_brightness(400);  // set temporary brightness level.
  RGB_matrix_set_color(0, 0, 31, 63, RED);
  sleep_ms(200);

  RGB_matrix_explode_box(0, 0, 31, 63, RED, ACTION_DRAW);
  RGB_matrix_printf(FrameBuffer,  3, 99, FONT_5x7, "%s", $START);
  RGB_matrix_printf(FrameBuffer, 12, 99, FONT_5x7, "%s", $TERMINAL);
  RGB_matrix_printf(FrameBuffer, 21, 99, FONT_5x7, "%s", $NOW);

  mem_display();

  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                      Wait for USB CDC connection of an external terminal emulator.
                                                    System will give up and continue after a few seconds waiting time.
                                                User may press the <DOWN>, <SET> or <UP> local buttons to bypass wait time.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Wait for USB CDC connection or for user to press one of the <DOWN>, <SET> or <UP> buttons to bypass the USB CDC connection. */
  log_printf(__LINE__, __func__, "Waiting for a USB CDC connection from an external terminal.\n");  // message will not show up on terminal if connection is not established.

  Delay    = 0;
  WaitTime = 1000;
  /* Set a special color for the endless loop pilot in upper matrix display to indicate that we are waiting for USB CDC terminal connection. */
  while ((!stdio_usb_connected()) && (gpio_get(BUTTON_DOWN_GPIO)) && (gpio_get(BUTTON_SET_GPIO)) && (gpio_get(BUTTON_UP_GPIO)))
  {
    if (Delay % 2)
    {
      RGB_matrix_set_color(0,  0,  0,  2, RED);  // left side indicator.
      RGB_matrix_set_color(0, 61,  0, 63, RED);  // right side indicator.
    }
    else
    {
      RGB_matrix_set_color(0,  0,  0,  2, BLUE);  // left side indicator.
      RGB_matrix_set_color(0, 61,  0, 63, BLUE);  // right side indicator.
    }
    sleep_ms(WaitTime);
    ++Delay;  // one more 1-second cycle waiting for USB CDC terminal connection.

    /* If we waited for more than this number of seconds for a USB CDC terminal connection, 
       get out of the loop and continue. Pico-SLASH-Display will run in stand-alone mode. */
    if (Delay > 30) break;
  }

  /* Check if USB CDC connection has been detected. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    /* Same as above is true here: message will not show-up if no terminal has been connected. */
    log_printf(__LINE__, __func__, "USB CDC connection has been established.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  /* Close the message box on LED matrix after wait time is over for terminal start. */
  RGB_matrix_implode_box(0, 0, 31, 63, RED);
  if ((DebugBitMask & DEBUG_STARTUP) == 0) RGB_matrix_cls(FrameBuffer);



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                      2nd pass - Provide another failover method to trigger upload mode in case there is a crash at the beginning of the code,
                                             before having access to terminal menu and / or remote control comnmands.
                              This will prevent the need to disassemble the RGB Matrix to get access to the BootSel button on Pico.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before polling <Down>, <Set> and <Up> buttons a second time to toggle Pico in upload (bootsel) mode.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  if ((!gpio_get(BUTTON_DOWN_GPIO)) || (!gpio_get(BUTTON_SET_GPIO)) || (!gpio_get(BUTTON_UP_GPIO)))
  {
    log_printf(__LINE__, __func__, "One of <Down>, <Set> or <Up> button has been pressed during startup sequence. Toggle Pico in upload mode.\n");
    RGB_matrix_cls(FrameBuffer);
    RGB_matrix_set_brightness(0);
    pwm_on_off(PWM_ID_BRIGHTNESS, FLAG_OFF);
    sleep_ms(100);  // make sure message has been displayed on terminal before toggling Pico in upload mode.
    save_and_disable_interrupts();
    reset_usb_boot(0l, 0l);
    sleep_ms(1000);
  }
  else
  {
    log_printf(__LINE__, __func__, "None of <Down>, <Set> or <Up> button has been pressed at the second checkpoint.\n");
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                Retrieve the current microcontroller type (Pico or PicoW), then read the Pico's Unique ID and find the corresponding Device Identifier
                                 NOTE: Pico2W (RP2350) is not considered for now since it does not provide an internal real-time clock.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before retrieving Pico type.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  get_pico_identifier(PicoUniqueId, PicoIdentifier, &PicoType);



#if 0
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                             Screen animation before starting the clock as is.
                                                                             To be completed.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  UCHAR String[65];

  UINT8 Center;
  UINT8 Width;

  INT64 DeltaTime;

  UINT16 LineOffset;

  RGB_matrix_set_color( 0,  0, 15, 63, BLUE);
  RGB_matrix_set_color(15,  0, 31, 63, RED);

  RGB_matrix_set_brightness(BRIGHTNESS_HI_LIMIT);
  Width  = MAX_COLUMNS / 2;
  Center = MAX_COLUMNS / 2;

  for (LineOffset = 0; LineOffset < HALF_ROWS; ++LineOffset)
  {
    if (LineOffset > 1) Width = (Center / LineOffset);

    log_printf(__LINE__, __func__, "Center: %2u   Width: %2u   LineOffset: %2u\n", Center, Width, LineOffset);
    log_printf(__LINE__, __func__, "HALF_ROWS - LineOffset - 1: %2u   Center - Width: %2d\n", HALF_ROWS - LineOffset - 1, Center - Width);
    log_printf(__LINE__, __func__, "Press <Enter>: ");
    input_string(String, 1, 60000l);
    printf("\n\n");

    
    /* Draw top butterfly. */
    for (Loop1UInt16 = 0; Loop1UInt16 < Width; ++Loop1UInt16)
    {
      /* Draw left part. */
      RGB_matrix_set_pixel(ShadowBuffer, HALF_ROWS - LineOffset - 1, Center - Width, HALF_ROWS - LineOffset - 1, Center + Width);
      
      /* Draw right part. */
      RGB_matrix_set_pixel(ShadowBuffer, HALF_ROWS - LineOffset - 1, Center - Width, HALF_ROWS, Center + Width);
      /// RGB_matrix_set_pixel(ShadowBuffer, 16 + Loop1UInt16, 0, 16, 63);
    }
    RGB_matrix_set_pixel(ShadowBuffer, HALF_ROWS - Loop1UInt16,     0, HALF_ROWS,     MAX_COLUMNS);
    RGB_matrix_set_pixel(ShadowBuffer, HALF_ROWS + Loop1UInt16 + 1, 0, HALF_ROWS + 1, MAX_COLUMNS);
    RGB_matrix_set_row_mask(&DisplayMatrix.RowMask, HALF_ROWS - Loop1UInt16, HALF_ROWS + Loop1UInt16 + 1);
    DisplayMatrix.FlagUpdate = FLAG_ON;
  }
#endif  // 0



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                        Initialize communication with DS3231 real-time clock IC and read current time from it.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing communication with DS3231.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  ds3231_init();
  ds3231_get_time(&CurrentTime);
  ds3231_get_time(&StartTime);  // keep track of most recent power-up cycle.

  /* Display the date and time values retrieved from DS3231 real-time clock IC to make sure they are all valid values.
     NOTE: If wrong values are read back from DS3231, they could crash the Firmware when trying to display an invalid day-of-week and / or month name later on. */
  Dum1UInt16 = get_days_in_year(CurrentTime.Year);

  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "Current date and time retrieved from DS3231 real-time clock IC:\n");
  log_printf(__LINE__, __func__, "DayOfMonth:          %2u   (1 to 31)\n", CurrentTime.DayOfMonth);
  log_printf(__LINE__, __func__, "Month:               %2u   (1 to 12)\n", CurrentTime.Month);
  log_printf(__LINE__, __func__, "Year:              %4.4u\n",             CurrentTime.Year);
  log_printf(__LINE__, __func__, " \n");
  log_printf(__LINE__, __func__, "Hours:               %2.2u\n", CurrentTime.Hour);
  log_printf(__LINE__, __func__, "Minutes:             %2.2u\n", CurrentTime.Minute);
  log_printf(__LINE__, __func__, "Seconds:             %2.2u\n", CurrentTime.Second);
  log_printf(__LINE__, __func__, " \n");
  log_printf(__LINE__, __func__, "DayOfWeek:          %3u   (0=SUN  1=MON  2=TUE  3=WED  4=THU  5=FRI  6=SAT)\n", CurrentTime.DayOfWeek);
  log_printf(__LINE__, __func__, "DayOfYear:          %3u   (1 to %u)\n",  CurrentTime.DayOfYear, Dum1UInt16);
  /// log_printf(__LINE__, __func__, "   FlagDst:           0x%2.2X\n",          CurrentTime.FlagDst);
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "<120>Other useful information:\n");
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "I'm alive indicator is CYAN for terminal handling endless loop (watchdog at the bottom of Time window)\n");
  log_printf(__LINE__, __func__, "I'm alive indicator is YELLOW for time steps endless loop (watchdog at the top of Time window)\n");
  log_printf(__LINE__, __func__, "Flash sector size: 0x%X     Flash page size: 0x%X\n", FLASH_SECTOR_SIZE, FLASH_PAGE_SIZE);
  log_printf(__LINE__, __func__, "Flash  configuration sector 0 at 0x%X\n", FlashConfig[0]);
  log_printf(__LINE__, __func__, "Flash  configuration sector 1 at 0x%X\n", FlashConfig[1]);
  log_printf(__LINE__, __func__, "Active configuration number 0 at 0x%X\n", ActiveConfig[0]);
  log_printf(__LINE__, __func__, "Active configuration number 1 at 0x%X\n", ActiveConfig[1]);
  log_printf(__LINE__, __func__, "MAX_ROWS: %2.2u     HALF_ROWS: %2.2u\n", MAX_ROWS, HALF_ROWS);
  log_printf(__LINE__, __func__, "MAX_COLUMNS: %2.2u\n", MAX_COLUMNS);
  log_printf(__LINE__, __func__, "FALSE: %u     TRUE: %u\n",  FALSE, TRUE);
  log_printf(__LINE__, __func__, Separator);


  /* Set Pico's internal real-time clock with date and time retrieved from DS3231 real-time clock IC. */
  DateTime.hour  = CurrentTime.Hour;
  DateTime.min   = CurrentTime.Minute;
  DateTime.sec   = CurrentTime.Second;
  DateTime.dotw  = CurrentTime.DayOfWeek;
  DateTime.day   = CurrentTime.DayOfMonth;
  DateTime.month = CurrentTime.Month;
  DateTime.year  = CurrentTime.Year;

  rtc_init();                   // initialize Pico's real-time clock.
  rtc_set_datetime(&DateTime);  // set current time on Pico's real-time clock.
  FlagTimeSet = FLAG_ON;        // indicate that time has been set on Pico-SLASH-Display.
  log_printf(__LINE__, __func__, "LOG MASK %X", LOG_ALL);  // allow all extra information (including time stamp) to be diaplayed in log file.
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "Now that Pico's real-time clock has been initialized from DS3231, logged data will be time stamped.\n");
  log_header();



  /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                       Display build options / configuration so that user can make sure they are as expected.
  \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
#ifdef NO_SOUND
  log_printf(__LINE__, __func__, "   - - - WARNING - WARNING - WARNING - WARNING - - - FIRMWARE BUILT WITH ALL LOCAL SOUNDS DISABLED.\n");
#endif  // NO_SOUND

  log_printf(__LINE__, __func__, "Firmware built with device <profile define file>:        <%s>.\n", PROFILE_DEFINE_FILE);
  log_printf(__LINE__, __func__, "Firmware built with device <profile configuration file>: <%s>.\n", PROFILE_CONFIG_FILE);
  log_printf(__LINE__, __func__, "Firmware built with <calendar event file>:               <%s>.\n", CALENDAR_FILE);

#ifdef RELEASE_VERSION
  log_printf(__LINE__, __func__, "Firmware built as <Release> version.\n");
#endif  // RELEASE_VERSION

#ifdef DEVELOPER_VERSION
  log_printf(__LINE__, __func__, "Firmware built as <Developer> version.\n");
#endif  // DEVELOPER_VERSION

#ifdef NEW_BOARD
  log_printf(__LINE__, __func__, "Firmware built for <NEW> electronic board (one Pico socket on each side of the control board).\n");
#endif  // NEW_BOARD

#ifdef OLD_BOARD
  log_printf(__LINE__, __func__, "Firmware built for <OLD> electronic board (two Pico sockets side-by-side on the control board).\n");
#endif  // OLD_BOARD

#if FIRMWARE_LANGUAGE == LANGUAGE_ENGLISH
  log_printf(__LINE__, __func__, "Firmware built with <English> language support.\n");
#endif

#if FIRMWARE_LANGUAGE == LANGUAGE_FRENCH
  log_printf(__LINE__, __func__, "Firmware built with <French> language support.\n");
#endif

#ifdef ALTERNATE_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built with <Alternate Display> support.\n");
#else  // ALTERNATE_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built WITHOUT <Alternate Display> support.\n");
#endif  // ALTERNATE_SUPPORT

#ifdef MQTT_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built with <Message Queueing Telemetry Transport> (MQTT) protocol support.\n");
#else  // MQTT_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built WITHOUT <Message Queueing Telemetry Transport> (MQTT) protocol support.\n");
#endif  // MQTT_SUPPORT

#ifdef MQTT_TIME_SERVER
  log_printf(__LINE__, __func__, "Firmware built to be the unique <MQTT Time Server> in SLASH Smart Home ecosystem.\n");
#else  // MQTT_TIME_SERVER
  log_printf(__LINE__, __func__, "Firmware will NOT be the <MQTT Time Server> in SLASH Smart Home ecosystem.\n");
#endif  // MQTT_TIME_SERVER

#ifdef NTP_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built to be the unique device using <Network Time Protocol> (NTP) synchronization.\n");
#else  // NTP_SUPPORT
  log_printf(__LINE__, __func__, "Firmware will NOT use the <Network Time Protocol> (NTP) synchronization.\n");
#endif  // NTP_SUPPORT

#ifdef PASSIVE_BUZZER_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built with <Passive Buzzer> support.\n");
#else  // PASSIVE_BUZZER_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built WITHOUT <Passive Buzzer> support.\n");
#endif  // PASSIVE_BUZZER_SUPPORT

#ifdef QUICK_START
  log_printf(__LINE__, __func__, "Firmware built with <Quick Start> option enabled.\n");
#endif  // QUICK_START

#ifdef REMOTE_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built with <Remote Control> support.\n");
#else  // REMOTE_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built WITHOUT <Remote Control> support.\n");
#endif  // REMOTE_SUPPORT

#ifdef SOUND_SERVER_DRIVE
  log_printf(__LINE__, __func__, "Firmware built to be the unique <Sound Server Drive> device in SLASH Smart Home ecosystem.\n");
#else  // SOUND_SERVER_DRIVE
  log_printf(__LINE__, __func__, "Firmware will NOT be the <Sound Server Drive> device in SLASH Smart Home ecosystem.\n");
#endif  // SOUND_SERVER_DRIVE

#ifdef WATCHDOG_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built with <Watchdog> support.\n");
#else  // WATCHDOG_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built WITHOUT <Watchdog> support.\n");
#endif  // WATCHDOG_SUPPORT

#ifdef WIFI_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built with <Wi-Fi> (Network) support.\n");
#else  // WIFI_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built WITHOUT <Wi-Fi> (Network) support.\n");
#endif  // WIFI_SUPPORT

#ifdef ZIGBEE_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built with <ZigBee> protocol support.\n");
#else  // ZIGBEE_SUPPORT
  log_printf(__LINE__, __func__, "Firmware built WITHOUT <ZigBee> protocol support.\n");
#endif  // ZIGBEE_SUPPORT

  log_printf(__LINE__, __func__, Separator);



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                        Initialize sound queue for active buzzer on entry (the buzzer already installed on Pico-RGB-Matrix control board).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing sound queue.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  for (Loop1UInt16 = 0; Loop1UInt16 < MAX_ACTIVE_SOUND_QUEUE; ++Loop1UInt16)
  {
    QueueActiveSound.Element[Loop1UInt16].MSec        = 0;
    QueueActiveSound.Element[Loop1UInt16].RepeatCount = 0;
  }
  QueueActiveSound.Head = 0;
  QueueActiveSound.Tail = 0;



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                               Initialize Service Light timer and ambient light history (hysteresis) with current ambient light value.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing ambient light history.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  Dum1UInt16 = get_light_value();
  for (Loop1UInt16 = 0; Loop1UInt16 < BRIGHTNESS_HYSTERESIS_SECONDS; ++Loop1UInt16)
    AmbientLight[Loop1UInt16] = Dum1UInt16;
  
  AverageAmbientLight = Dum1UInt16;

  ServiceLightTimer     = 0;    // initialize service light "Off" on entry.
  TimerLastServiceLight = 0ll;  // last time service light has been triggered.



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                              Initialize target callback duration history.
                   This part has been used to optimize callback functions. Code has been left for reuse if / when callback function are modified.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing target callback duration history.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  CallbackDurationPointer = 0;  // point to first slot in circular buffer.
  AbsoluteEntryTime = nil_time;
  AbsoluteExitTime  = nil_time;
  for (Loop1UInt16 = 0; Loop1UInt16 < MAX_CALLBACK_DURATION_UNITS; ++Loop1UInt16)
    CallbackDuration[Loop1UInt16] = 0ll;



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                           Initialize alarms.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing alarms.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  /* Parameters below are updated by the system for active alarms. Consequently, they must not be in alarm structure saved in flash. */
  AlarmBitMask = 0;
  for (Loop1UInt16 = 0; Loop1UInt16 < MAX_ALARMS; ++Loop1UInt16)
  {
    ActiveAlarm[Loop1UInt16].CountDown     = 0;       // assume no alarm is ringing on entry.
    ActiveAlarm[Loop1UInt16].PreviousTimer = 0x00ll;  // timer value of this alarm's last ring.
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                             Initialize active calendar events bitmask.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing calendar events.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  EventBitMask = 0ll;



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                   Initialize remote control functions.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing Pico-SLASH-Display functions.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  function_init();



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                     Initialize LED matrix buffers: "FrameBuffer", "BlinkBuffer", "CheckBuffer", "ShadowBuffer".
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing display buffers (FrameBuffer, BlinkBuffer, CheckBuffer, ShadowBuffer).\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  /* Initialize every row of all LED matrix buffers. */
  for (Loop1UInt16 = 0; Loop1UInt16 < MAX_ROWS; ++Loop1UInt16)
  {
    BlinkBuffer[Loop1UInt16]  = 0ll;
    FrameBuffer[Loop1UInt16]  = 0ll;
    ShadowBuffer[Loop1UInt16] = 0ll;
    CheckBuffer[Loop1UInt16]  = 0xFFFFFFFFFFFFFFFFll;
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                              Initialize LED display matrix windows.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing windows.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  win_init();



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                      Initialize critical section.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing critical section.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  critical_section_init(&ThreadLock);



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                        Initialize local buttons and remote control circular buffer.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Initialize local buttons buffer. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing circular buffer for local buttons and remote control.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  for (Loop1UInt16 = 0; Loop1UInt16 < BUTTON_BUFFER_SIZE; ++Loop1UInt16)
    ButtonBuffer[Loop1UInt16] = BUTTON_NONE;



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                       Seed random number generator.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing random generator seed.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  srand(time_us_64());



#ifdef REMOTE_SUPPORT
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                    Initialize infrared related data.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Initialize IR buffer. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before initializing IR buffer.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  IrFlagSuccess = 0x02;  // undefined result of IR data stream decoding.
  IrStepCount   = 0;
  IrTimer       = 0ll;

  memset((UINT8 *)IrBuffer, 0x00, IR_BUFFER_SIZE);
#endif  // REMOTE_SUPPORT



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                               Start 50 msec. callback managing sound queue and infrared data stream.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* 50 msec callback to handle active buzzer sound queue and remote control infrared data stream reception. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before launching 50 msec callback for remote control.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  add_repeating_timer_ms(-50, callback_50msec_timer, NULL, &Handle50MSecTimer);



#ifdef DEVELOPER_VERSION
#ifdef FLASH_ERASE
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                   If in DEVELOPER's mode and FLASH_ERASE is defined, force erasing flash configuration and generate a new default configuration.
                       Then, the configuration file associated with this device profile (if there is one) will be read to change / customize
                                                those settings that have been identified in the corresponding .c file.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  log_printf(__LINE__, __func__, "Erase both Pico-SLASH-Display configuration sectors from flash memory to force generation of a new default configuration.\n");
  sleep_ms(200);

  /* Erase both flash sectors containing Pico-SLASH-Display configurations 1 and 2. */
  log_printf(__LINE__, __func__, "Press <Enter> to proceed with flash_erase(0): ");
  input_string(String, 1, 0l);
  flash_erase(0);

  log_printf(__LINE__, __func__, "Press <Enter> to proceed with flash_erase(1): ");
  input_string(String, 1, 0l);
  flash_erase(1);
#endif  // FLASH_ERASE
#endif  // DEVELOPER_VERSION


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                          Retrieve RGB Matrix configuration from flash memory.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Read and check (validate) flash configurations 0 and 1. If they are corrupted, new default configurations will be saved, preventing flash_read_config() to crash. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before reading configuration from Pico's flash memory.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  flash_read_config(0);
  flash_read_config(1);



#if 0
  log_printf(__LINE__, __func__, "Press <Enter> to proceed with flash_display_config0(): ");
  input_string(String, 1, 0l);
  flash_display_config0();

  log_printf(__LINE__, __func__, "Press <Enter> to proceed with flash_display_config1(): ");
  input_string(String, 1, 0l);
  flash_display_config1();

  
  
  log_printf(__LINE__, __func__, "Press <Enter> to proceed with flash_check_config(0): ");
  input_string(String, 1, 0l);
  flash_check_config(0);

  log_printf(__LINE__, __func__, "Press <Enter> to proceed with flash_check_config(1): ");
  input_string(String, 1, 0l);
  flash_check_config(1);
#endif  // 0



  /*** Add here support for automatic flash configuration update from Firmware "version to version". */
  snprintf(ActiveConfig0.Version, sizeof(ActiveConfig0.Version), "%s", FIRMWARE_VERSION);
  snprintf(ActiveConfig1.Version, sizeof(ActiveConfig1.Version), "%s", FIRMWARE_VERSION);
  FlagFlashDone = FLAG_ON;  // indicate that device configuration has been read from flash.



  /*** For now, writing watchdog dirty flag to flash is not reliable since we can't be sure of software stability when something crashed. */
  if (ActiveConfig0.WatchdogFlag == FLAG_OFF)
  {
    if (DebugBitMask & DEBUG_WATCHDOG) log_printf(__LINE__, __func__, "ActiveConfig0.WatchdogFlag found to be OFF\n");
  }
  else
  {
    if (DebugBitMask & DEBUG_WATCHDOG) log_printf(__LINE__, __func__, "ActiveConfig0.WatchdogFlag found to be ON\n");
    ActiveConfig0.WatchdogFlag = FLAG_OFF;  // once restart is over, reset watchdog restart indicator.
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                    Now that flash configuration has been read, set brightness according to configuration settings.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before adjusting brightness according to flash configuration settings.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  if (ActiveConfig0.FlagAutoBrightness)
  {
    if (DebugBitMask & DEBUG_BRIGHTNESS) log_printf(__LINE__, __func__, "Set LED matrix brightness according to average ambient light.\n");
    set_auto_brightness(FLAG_ON);  // will use current ambient light value as the starting point for auto brightness.
  }
  else
  {
    if (DebugBitMask & DEBUG_BRIGHTNESS) log_printf(__LINE__, __func__, "Set LED matrix brightness to <steady> value.\n");
    RGB_matrix_set_brightness(ActiveConfig0.BrightnessLevel);  // use "steady brightness value" in configuration.
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                             Set all double-dots default color on entry.
                                                                  Will be modified if required by:
                                                             1) Golden age option.
                                                             2) Health status for: Wi-Fi / NTP / MQTT / ZigBee.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before setting default color for all double-dots clock separators.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  // log_printf(__LINE__, __func__, "Window[WIN_TIME].InsideColor: %2u (%s)     ", Window[WIN_TIME].InsideColor, ColorName[Window[WIN_TIME].InsideColor]);
  for (Loop1UInt16 = 0; Loop1UInt16 < 4; ++Loop1UInt16)
  {
    DoubleDotsCurrentColor[Loop1UInt16] = Window[WIN_TIME].InsideColor;
    double_dots_set_color(Loop1UInt16 + 1, RED);  // assume all network-related health is not setup on entry (all "bad" - red).
    // log_printf(__LINE__, __func__, "%2u   ", DoubleDotsCurrentColor[Loop1UInt16]);
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                Open WIN_DAY, WIN_DATE and WIN_TIME and display day, date and time for the first time on LED matrix.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before displaying day, date and time for the first time on LED matrix.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  if (DebugBitMask & DEBUG_BRIGHTNESS) log_printf(__LINE__, __func__, "Turn LED matrix brightness to high level for first day, date and time display.\n");
  RGB_matrix_set_brightness(400);  // set temporary brightness level.

  win_open(WIN_DAY, FLAG_ON, FLAG_OFF);
  RGB_matrix_display_time();  // display day-of-week.

  win_open(WIN_DATE, FLAG_ON, FLAG_OFF);
  RGB_matrix_display_time();  // display day-of-month, month, year.

  win_open(WIN_TIME, FLAG_ON, FLAG_OFF);
  RGB_matrix_display_time();  // display hour, minutes, seconds.

  /* WIN_TIME exploding box has been done on FrameBuffer, make sure ShadowBuffer also has a copy of box border. */
  RGB_matrix_box(ShadowBuffer, Window[WIN_TIME].StartRow, Window[WIN_TIME].StartColumn, Window[WIN_TIME].EndRow, Window[WIN_TIME].EndColumn, Window[WIN_TIME].BorderColor, Window[WIN_TIME].LastBoxState );



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
        Now that WIN_DAY, WIN_DATE and WIN_TIME have been opened, start the 1 sec. callback in charge of the following tasks:
            1) Reading the real-time clock IC to update current time internal variables.
            2) Manage LED display brightness if auto-brightness feature is turned On.
            3) Manage infrared indicator on LED matrix.
            4) Manage hourly chime.
            5) Manage half-hour light chime.
            6) Manage Reminders.
            7) Manage Calendar Events.
            8) Manage Alarms.
            9) Manage Auto-scrolls
           10) Manage blinking if there is one currently active on LED matrix.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* One second callback for date and time update on LED matrix. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before launching time update callback.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  add_repeating_timer_ms(-1000, callback_1000msec_timer, NULL, &Handle1000MSecTimer);



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                         Display code sections tagged for debug on startup.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* If user requested any section to be debugged, send a time stamp to the log screen when we start and display all code sections to be debugged. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Displaying code sections to be debugged.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  if (DebugBitMask)
  {
    log_printf(__LINE__, __func__, Separator);
    log_printf(__LINE__, __func__, "<120>%s %2.2u-%3s-%4.4u  %2.2u:%2.2u:%2.2u - PICO-SLASH-Display log sections. Sections below will be logged for debug purposes:\n",
               DayName[CurrentTime.DayOfWeek], CurrentTime.DayOfMonth, ShortMonth[CurrentTime.Month], CurrentTime.Year, 
               CurrentTime.Hour, CurrentTime.Minute, CurrentTime.Second);

    /* Display all debug sections that are under analysis. */
    for (Loop1UInt16 = 0; Loop1UInt16 < (sizeof(DebugBitMask) * 8); ++Loop1UInt16)
    {
      if (DebugBitMask & (0x01ll << Loop1UInt16))
      {
        switch (0x01 << Loop1UInt16)
        {
          case DEBUG_ALARM:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Alarm algorithm.\n", (0ll | DEBUG_ALARM));
          break;

          case DEBUG_BLINK:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Blinking mechanism.\n", (0ll | DEBUG_BLINK));
          break;

          case DEBUG_BLUETOOTH:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Bluetooth communications.\n", (0ll | DEBUG_BLUETOOTH));
          break;

          case DEBUG_BOX:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Exploding windows.\n", (0ll | DEBUG_BOX));
          break;

          case DEBUG_BRIGHTNESS:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Brightness algorithm.\n", (0ll | DEBUG_BRIGHTNESS));
          break;

          case DEBUG_BUTTON:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Local button handling.\n", (0ll | DEBUG_BUTTON));
          break;

          case DEBUG_CORE:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Pico's core 1 thread.\n", (0ll | DEBUG_CORE));
          break;

          case DEBUG_DS3231:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - DS3231 real-time IC.\n", (0ll | DEBUG_DS3231));
          break;

          case DEBUG_EVENT:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Calendar event algorithm.\n", (0ll | DEBUG_EVENT));
          break;

          case DEBUG_FLASH:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Flash memory operations.\n", (0ll | DEBUG_FLASH));
          break;

          case DEBUG_FLOW:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Program sequence logic flow.\n", (0ll | DEBUG_FLOW));
          break;

          case DEBUG_FUNCTION:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Functions operation.\n", (0ll | DEBUG_FUNCTION));
          break;

          case DEBUG_IR:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Infrared remote control.\n", (0ll | DEBUG_IR));
          break;

          case DEBUG_MATRIX:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Display matrix operations.\n", (0ll | DEBUG_MATRIX));
          break;

          case DEBUG_MQTT:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - MQTT (Message Queuing Telemetry Transport) protocol.\n", (0ll | DEBUG_MQTT));
          break;

          case DEBUG_NTP:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - NTP (Network Time Protocol).\n", (0ll | DEBUG_NTP));
          break;

          case DEBUG_PWM:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - PWM behavior.\n", (0ll | DEBUG_PWM));
          break;

          case DEBUG_REMINDER:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Reminder algorithm.\n", (0ll | DEBUG_REMINDER));
          break;

          case DEBUG_SCROLL:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Scroll algorithm.\n", (0ll | DEBUG_SCROLL));
          break;

          case DEBUG_SOUND_QUEUE:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Queue engines.\n", (0ll | DEBUG_SOUND_QUEUE));
          break;

          case DEBUG_STARTUP:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Startup sequence.\n", (0ll | DEBUG_STARTUP));
          break;

          case DEBUG_DST_TIME:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Daylight Saving Time related logic.\n", (0ll | DEBUG_DST_TIME));
          break;

          case DEBUG_TEST:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Test zone.\n", (0ll | DEBUG_TEST));
          break;

          case DEBUG_WATCHDOG:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Watchdog behavior.\n", (0ll | DEBUG_WATCHDOG));
          break;

          case DEBUG_WIFI:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Wi-Fi communications.\n", (0ll | DEBUG_WIFI));
          break;

          case DEBUG_WINDOW:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Window algorithm.\n", (0ll | DEBUG_WINDOW));
          break;

          default:
            log_printf(__LINE__, __func__, "Mask: [%16.16llX] - Undefined section #%u\n", (0ll | Loop1UInt16), Loop1UInt16);
          break;
        }
      }
    }
    log_printf(__LINE__, __func__, Separator);
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                              Display some debug information if required.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before displaying other debug information.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  if (DebugBitMask & DEBUG_BRIGHTNESS) pwm_display_parameters();



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                    Information to user, some on terminal and some on LED display.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before scrolling Firmware version number.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  /* Scroll Firmware Version number, Pico type, Pico's Unique ID and device ID when on startup. */
  function_firmware_version();
  function_pico_type();

#ifdef NO_SOUND
  win_scroll(WIN_DATE, 201, 201, 1, 1, FONT_5x7, "WARNING - This Firmware has been built WITH ALL LOCAL SOUNDS DISABLED");
#endif  // NO_SOUND

  printf("\n\n\n");
  log_printf(__LINE__, __func__, ">>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>><<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<\n");
  log_printf(__LINE__, __func__, "<120>NOTE: Press <Enter> at any time to display the main terminal menu...\n");
  log_printf(__LINE__, __func__, ">>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>>><<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<<\n");



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                             Wi-Fi setup.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before Wi-Fi setup.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  /* Country Code for Wi-Fi IC must be define in the "parameters" area at the top of source code. See Raspberry Pi Pico documentation for available countries. */
  StructWiFi.CountryCode = CYW43_COUNTRY_CODE;
  strcpy(StructWiFi.NetworkName,     ActiveConfig0.NetworkName);
  strcpy(StructWiFi.NetworkPassword, ActiveConfig0.NetworkPassword);



#ifdef NTP_SUPPORT
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                              NTP setup.
                                               Section below is used to make the minimum NTP related variable setup.
                              Wi-Fi connection will be done and check in the endless loop with the ntp_check_connection() function.
                                            If NTP_SUPPORT is defined, RGB Matrix' real-time clock IC will periodically
                      be synchronized through network time protocol over Internet. User must have encoded credentials to PicoW's flash before.
                                                                   (Refer to User Guide for details).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before NTP setup.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }

  /* Validation of DSTCountry retrieved from flash. User will need to configure the right value if different from default. */
  if (ActiveConfig0.DSTCountry >= MAX_DST_COUNTRIES) ActiveConfig0.DSTCountry = DST_NORTH_AMERICA;

  /* Set a few Struct NTP variables on entry. */
  StructNTP.DSTCountry           = ActiveConfig0.DSTCountry;
  StructNTP.DeltaTime            = ActiveConfig0.DeltaTime;
  StructNTP.FlagSummerTime       = ActiveConfig0.FlagSummerTime;
  StructNTP.HumanTime.Hour       = CurrentTime.Hour;
  StructNTP.HumanTime.Minute     = CurrentTime.Minute;
  StructNTP.HumanTime.Second     = CurrentTime.Second;
  StructNTP.HumanTime.DayOfMonth = CurrentTime.DayOfMonth;
  StructNTP.HumanTime.Month      = CurrentTime.Month;
  StructNTP.HumanTime.Year       = CurrentTime.Year;
  StructNTP.HumanTime.DayOfWeek  = CurrentTime.DayOfWeek;
  StructNTP.HumanTime.DayOfYear  = CurrentTime.DayOfYear;
  StructNTP.LocalTime            = ntp_convert_human_to_unix(&CurrentTime, 0);
  StructNTP.UTCTime              = ntp_convert_human_to_unix(&CurrentTime, -StructNTP.DeltaTime);
  ntp_display_info();
  sleep_ms(500);  // give some time for the callback to complete to prevent interference with MQTT initialization.


  /* Find specific daylight saving time (DST) parameters for target country. */
  ntp_dst_settings();
  ActiveConfig0.FlagSummerTime = StructNTP.FlagSummerTime;
  StructNTP.UTCTime = ntp_convert_human_to_unix(&CurrentTime, (-StructNTP.DeltaTime - (StructNTP.FlagSummerTime * StructNTP.ShiftMinutes)));
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "Unix time after accounting for DST period of the year:\n");
  log_printf(__LINE__, __func__, "   > Unix local time:    %12llu\n",  StructNTP.LocalTime);
  log_printf(__LINE__, __func__, "   > Unix UTC time:      %12llu\n",  StructNTP.UTCTime);
  log_printf(__LINE__, __func__, "   > Time difference:    %12lld   (%lld minutes)\n", (StructNTP.LocalTime - StructNTP.UTCTime), (StructNTP.LocalTime - StructNTP.UTCTime) / 60);


  /* Now that we retrieve current DST parameters, set UTC time from local time. */
  log_printf(__LINE__, __func__, "Local time parameters retrieved from real-time clock IC (DS3231):\n");
  log_printf(__LINE__, __func__, "StructNTP.LocalTime:   %12llu\n",              StructNTP.LocalTime);
  log_printf(__LINE__, __func__, "StructNTP.DeltaTime:         %6d minutes\n",   StructNTP.DeltaTime);
  log_printf(__LINE__, __func__, "StructNTP.FlagSummer:          0x%2.2X\n",     StructNTP.FlagSummerTime);
  log_printf(__LINE__, __func__, "StructNTP.ShiftMinutes:        %4d minutes\n", StructNTP.ShiftMinutes);
  log_printf(__LINE__, __func__, "StructNTP.UTCTime:     %12llu\n",              StructNTP.UTCTime);
  log_printf(__LINE__, __func__, Separator);
#endif // NTP_SUPPORT



#if 0
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                             Code block below for testing purposes.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 0;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 1;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 2;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 3;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 4;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 5;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 6;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 7;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 8;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 9;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 10;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 11;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 12;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 13;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 14;
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();

  ActiveConfig0.DSTCountry = 10;  // back to North America.
  log_printf(__LINE__, __func__, "DST country: %2u   DeltaTime: %4d\n", ActiveConfig0.DSTCountry, ActiveConfig0.DeltaTime);
  ntp_dst_settings();
#endif  // 0



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                         Temporary code section.
                                                        To display information before entry in the endless loop.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Optionally display complete list of DS3231 current parameters. */
  if (DebugBitMask & DEBUG_DS3231) ds3231_display_values();
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                       End of temporary code section.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                          Setup reminders of type 1.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before setting up reminders.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  reminder1_update();



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                            Start the thread to run on one of Pico's core to manage many duties of the RGB matrix in different time steps.
                                                Other core will be used mainly for external terminal operations handling.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before starting Pico's core managing time step duties.\n");
    sleep_ms(SlowFactor);  // slow down startup sequence for debug purposes.
  }
  multicore_launch_core1(time_steps_loop);
  FlagTwoCores = FLAG_ON;  // indicate that both cores are now running.
  sleep_ms(300);  // give some time to execute flash_safe_execute_core_init() by core1.

  terminal_handling_loop();
}





/* $PAGE */
/* $TITLE=alarm_check() */
/* ============================================================================================================================================================= *\
                                                                   Check if some alarms must be triggered.
\* ============================================================================================================================================================= */
void alarm_check(void)
{
#ifdef RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // must be turned OFF at all times.
#else  // RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // may be turned ON for debug purposes.
#endif  // RELEASE_VERSION

  // UINT8 TotalActiveAlarms;

  UINT16 Loop1UInt16;


  // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering alarm_check()\n");

  /* Initialize total number of new active alarms. */
  // TotalActiveAlarms = 0;


  /* Scan all alarms to find those matching current time and day-of-week. */
  for (Loop1UInt16 = 0; Loop1UInt16 < MAX_ALARMS; ++Loop1UInt16)
  {
    if (ActiveConfig0.Alarm[Loop1UInt16].FlagStatus != FLAG_ON)
    {
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u Off (%2.2u)\n", Loop1UInt16, ActiveConfig0.Alarm[Loop1UInt16].FlagStatus);
      continue;
    }
    else
    {
      /* Display alarm status for debug purpose. */
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u ON  (%2.2u)\n", Loop1UInt16, ActiveConfig0.Alarm[Loop1UInt16].FlagStatus);
    }


    /* Check if today is a target day for this alarm. */
    if ((ActiveConfig0.Alarm[Loop1UInt16].DayMask & (1 << CurrentTime.DayOfWeek)) == 0)
    {
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u - DayMask does not match\n", Loop1UInt16);
      continue;
    }
    else
    {
      /* Display alarm status for debug purpose. */
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u - DayMask does match\n", Loop1UInt16);
    }


    if (ActiveConfig0.Alarm[Loop1UInt16].Hour != CurrentTime.Hour)
    {
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u - Hour does not match (%u VS %u)\n", Loop1UInt16, ActiveConfig0.Alarm[Loop1UInt16].Hour, CurrentTime.Hour);
      continue;
    }
    else
    {
      /* Display alarm status for debug purpose. */
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u - Hour does match (%u VS %u)\n", Loop1UInt16, ActiveConfig0.Alarm[Loop1UInt16].Hour, CurrentTime.Hour);
    }


    if (ActiveConfig0.Alarm[Loop1UInt16].Minute != CurrentTime.Minute)
    {
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u - Minute does not match (%u VS %u)\n", Loop1UInt16, ActiveConfig0.Alarm[Loop1UInt16].Hour, CurrentTime.Hour);
      continue;
    }
    else
    {
      /* Display alarm status for debug purpose. */
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Alarm %u - Minute does match (%u VS %u)\n", Loop1UInt16, ActiveConfig0.Alarm[Loop1UInt16].Hour, CurrentTime.Hour);
    }

    AlarmBitMask |= ((UINT16)0x01 << Loop1UInt16);
    ActiveAlarm[Loop1UInt16].CountDown = ActiveConfig0.Alarm[Loop1UInt16].RingDuration;  // global time alarm will be ringing.
    if (FlagLocalDebug) log_printf(__LINE__, __func__, "Al: %u   Mask: 0x%2.2X   CD: %u   (%s)\n", Loop1UInt16, AlarmBitMask, ActiveAlarm[Loop1UInt16].CountDown, ActiveConfig0.Alarm[Loop1UInt16].Message);
  }

  // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting alarm_check()\n");

  return;
}




/* $PAGE */
/* $TITLE=alarm_ring() */
/* ============================================================================================================================================================= *\
                                                      Feed alarm ringer for currently active ("triggered") alarms.
\* ============================================================================================================================================================= */
void alarm_ring(void)
{
#ifdef RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // must be turned OFF at all times.
#else  // RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // may be turned ON for debug purposes.
#endif  // RELEASE_VERSION

  UINT16 Loop1UInt16;

  UINT64 CurrentTimer;


  // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering alarm_ring()\n");

  /* When an alarm becomes active, check_alarm() will raise its bit in AlarmBitMask. */
  if (AlarmBitMask)
  {
    /* If some alarms are active, we'll need current timer to evaluate if it is time to feed ringer. */
    CurrentTimer = time_us_64();

    /* Scan alarm to find those requiring ringer repeat. */
    for (Loop1UInt16 = 0; Loop1UInt16 < MAX_ALARMS; ++Loop1UInt16)
    {
      /* Check if this alarm is active (global ring duration). */
      if (ActiveAlarm[Loop1UInt16].CountDown > 0)
      {
        /* Display details for first active alarm number for debug purpose. */
        if (FlagLocalDebug) log_printf(__LINE__, __func__, "0x%2.2X - %u - %3u - %3u - %9llu - %9llu - %4u\n", AlarmBitMask, Loop1UInt16, ActiveConfig0.Alarm[Loop1UInt16].RepeatPeriod, ActiveAlarm[Loop1UInt16].CountDown, CurrentTimer, ActiveAlarm[Loop1UInt16].PreviousTimer, (UINT16)((CurrentTimer - ActiveAlarm[Loop1UInt16].PreviousTimer) / 1000000ll));

        if (((CurrentTimer - ActiveAlarm[Loop1UInt16].PreviousTimer) / 1000000ll) >= ActiveConfig0.Alarm[Loop1UInt16].RepeatPeriod)
        {
          if (FlagLocalDebug) log_printf(__LINE__, __func__, "1) %4u - %3u", (UINT16)((CurrentTimer - ActiveAlarm[Loop1UInt16].PreviousTimer) / 1000000ll), ActiveConfig0.Alarm[Loop1UInt16].RepeatPeriod);
          /* It is time to feed this ringer and repeat the scroll. */
          queue_add_active(ActiveConfig0.Alarm[Loop1UInt16].BeepMSec, ActiveConfig0.Alarm[Loop1UInt16].NumberOfBeeps);
          queue_add_active(2000, SILENT);
          win_scroll(WIN_DATE, 201, 201, 1, 1, FONT_5x7, "%s", ActiveConfig0.Alarm[Loop1UInt16].Message);


          if (ActiveConfig0.Alarm[Loop1UInt16].RepeatPeriod > ActiveAlarm[Loop1UInt16].CountDown)
          {
            /* Next ring would be beyond the global ringing period, reset it after current ring above. */
            ActiveAlarm[Loop1UInt16].CountDown     = 0;
            ActiveAlarm[Loop1UInt16].PreviousTimer = 0ll;
            AlarmBitMask &= ~((UINT16)(0x01 << Loop1UInt16));  // turn Off this alarm number in the bitmask of active alarms.
          }
          else
          {
            ActiveAlarm[Loop1UInt16].CountDown -= ActiveConfig0.Alarm[Loop1UInt16].RepeatPeriod;  // "ActiveConfig0.Alarm[Loop1UInt16].RepeatPeriod" seconds have elapsed since last pass.
            if (ActiveAlarm[Loop1UInt16].CountDown > 0)
            {
              /* There are more rings to come. */
              ActiveAlarm[Loop1UInt16].PreviousTimer = CurrentTimer;
            }
            else
            {
              /* This alarm is over now. */
              ActiveAlarm[Loop1UInt16].PreviousTimer = 0ll;
              AlarmBitMask &= ~((UINT16)(0x01 << Loop1UInt16));  // turn Off this alarm number in the bitmask of active alarms.
            }
          }
        }
      }
    }
  }

  // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting alarm_ring()\n");

  return;
}





/* $PAGE */
/* $TITLE=beep_tone() */
/* ============================================================================================================================================================= *\
                                                               Make a number of beeps through the buzzer.
                                   Function to be used until the passive buzzer circular buffer algorithm has been initialized.
\* ============================================================================================================================================================= */
void beep_tone(UINT8 RepeatCount)
{
	UINT8 Loop1UInt8;


  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Entering beep_tone()\n");

  for (Loop1UInt8 = 0; Loop1UInt8 < RepeatCount; ++Loop1UInt8)
  {
    gpio_put(BUZZER, 1);
    sleep_ms(50);
    gpio_put(BUZZER, 0);
    sleep_ms(50);
  }
  sleep_ms(1000);

  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting beep_tone()\n");

  return;
}





/* $PAGE */
/* $TITLE=callback_1msec_timer() */
/* ============================================================================================================================================================= *\
                                                        Callback in charge of LED matrix color setting and scanning.
\* ============================================================================================================================================================= */
bool callback_1msec_timer(struct repeating_timer *)
{
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                    Mechanism to evaluate the actual time spent in this callback.
                         Make an evaluation every 2 seconds so that the main endless system loop can process the data between each reading.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (TargetCallback == CALLBACK_1MS)
  {
    ++CallbackCounter;
    if (CallbackCounter >= 2000)
    {
      /* Take a reading every 2 seconds. */
      CallbackCounter   = 0;
      AbsoluteEntryTime = get_absolute_time();
    }
  }

#ifdef WATCHDOG_SUPPORT
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                             Watchdog counter.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  watchdog_update();
#endif  // WATCHDOG_SUPPORT


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                        Set (update) matrix color and scan two rows of LED matrix every msec (one row in top half and one row in bottom half).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  RGB_matrix_scan(FrameBuffer);


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                         Mechanism to find the actual time spent in this callback.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (TargetCallback == CALLBACK_1MS)
  {
    if (CallbackCounter == 0) AbsoluteExitTime = get_absolute_time();
  }

  return true;
}





/* $PAGE */
/* $TITLE=callback_50msec_timer() */
/* ============================================================================================================================================================= *\
                                                           Callback in charge of following activities:
                                                          - Remote control infrared reception.
                                                          - Text Scrolling.
                                                          - Text count-down.
                                                          - Active buzzer sound queue.
\* ============================================================================================================================================================= */
bool callback_50msec_timer(struct repeating_timer *)
{
#ifdef RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // must be turned OFF at all times.
#else  // RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // may be turned ON for debug purposes.
#endif  // RELEASE_VERSION

  UCHAR String[128];

  UINT8 IrButton;    // remote control button decoded from infrared data stream.
  UINT8 Loop1UInt8;

  // UINT64 Timer1;
  // UINT64 Timer2;

  // UINT64 CurrentTimer;

  static UINT8 IrCycleCount;
  static UINT8 FlagActiveSound;
  // static UINT8  FlagPassiveSound;

  static UINT16 ActiveMSeconds;
  static UINT16 ActiveMSecCounter;
  static UINT16 ActiveRepeatCount;
  static UINT16 CurrentRepeat;
  // static UINT16 Frequency;
  // static UINT16 PassiveMSeconds;
  // static UINT16 PassiveMSecCounter;


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                   Mechanism to evaluate the actual time spent in this callback.
                        Make an evaluation every 2 seconds so that the main endless system loop can process the data between each reading.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (TargetCallback == CALLBACK_50MS)
  {
     ++CallbackCounter;
    if (CallbackCounter >= 40)
    {
      /* Take a reading every 2 seconds. */
      CallbackCounter = 0;
      AbsoluteEntryTime = get_absolute_time();
    }
  }


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                 Manage infrared data stream reception.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
#ifdef REMOTE_SUPPORT
  if (IrStepCount)
  {
    /* If there is an infrared data stream now coming in, increment IrCycleCount, IR data stream will be decoded
       when IrCycleCount reaches the count of 3, to make sure data stream has been sent in its entirety. */
    ++IrCycleCount;

    /* If IrCycleCount reaches the value of 3, data stream began at least 100 msec ago, so it must be completed by now and ready to be processed. */
    if (IrCycleCount >= 3)
    {
      IrCycleCount = 0;  // reset IrCycleCount when infrared data stream has been entirely received to get ready for next IR data stream.

      /* Discard all spurious infrared bursts. */
      if (IrStepCount < 67)
      {
        IrStepCount = 0;  // received spurious IR burst, reset ir burst count.
      }
      else
      {
        /* If the number of IrStepCount seems valid, proceed with IR command decoding. */
        if (ir_decode_button(&IrButton) != IR_HI_LIMIT)
        {
          IrBuffer[0] = IrButton;  // put the button decoded in the IR buffer.
          ++IrCounter;
        }
      }
    }
  }
#endif  // REMOTE_CONTROL



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                  Manage active scrolling if there is one.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  for (Loop1UInt8 = 0; Loop1UInt8 < MAX_ACTIVE_SCROLL; ++Loop1UInt8)
  {
    if (ActiveScroll[Loop1UInt8])
    {
      /* This ActiveScroll structure has been allocated, check who's the owner. */
      if (ActiveScroll[Loop1UInt8]->Owner == WinTop)
      {
        if (FlagLocalDebug) log_printf(__LINE__, __func__, "<<< 1) WinTop: %u - %u >>>\n", Loop1UInt8, ActiveScroll[Loop1UInt8]->Owner);
        RGB_matrix_scroll(Loop1UInt8);
      }

      if (ActiveScroll[Loop1UInt8]->Owner == WinMid)
      {
        if (FlagLocalDebug) log_printf(__LINE__, __func__, "<<< 2) WinMid: %u - %u >>>\n", Loop1UInt8, ActiveScroll[Loop1UInt8]->Owner);
        RGB_matrix_scroll(Loop1UInt8);
      }

      if (ActiveScroll[Loop1UInt8]->Owner == WinBot)
      {
        if (FlagLocalDebug) log_printf(__LINE__, __func__, "<<< 3) WinBot: %u - %u >>>\n", Loop1UInt8, ActiveScroll[Loop1UInt8]->Owner);
        RGB_matrix_scroll(Loop1UInt8);
      }
    }
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                             Handling of active buzzer (the one integrated in the Pico-RGB-Matrix device)
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* If there is a sound on-going on the active buzzer, check if it is completed. */
  if (FlagActiveSound == FLAG_ON)
  {
    if (DebugBitMask & DEBUG_SOUND_QUEUE)
    {
      if (ActiveRepeatCount == SILENT)
        snprintf(String, sizeof(String), "- A-Silence     (%4u)\n", ActiveMSecCounter + 50);
      else
        snprintf(String, sizeof(String), "- A-Sounding    (%4u)\n", ActiveMSecCounter + 50);

      log_printf(__LINE__, __func__, String);
    }

    ActiveMSecCounter += 50;  // 50 milliseconds more since last callback.

    if (ActiveMSecCounter >= ActiveMSeconds)
    {
      if (DebugBitMask & DEBUG_SOUND_QUEUE)
        log_printf(__LINE__, __func__, "- A-Shutoff\n");

      /* Current sound is over on active buzzer. Turn sound off to make a cut with next sound. */
      gpio_put(BUZZER, 0);

      /* One more repeat count has been done. */
      ++CurrentRepeat;

      /* Check if we reached the total repeat count required. */
      if (CurrentRepeat > ActiveRepeatCount) CurrentRepeat = 0;

      /* No active sound for now. */
      FlagActiveSound = FLAG_OFF;

      /* Reset sound elapsed time for now. */
      ActiveMSecCounter = 0;
    }
  }
  else
  {
    if (CurrentRepeat)
    {
      /* There are some more sound repeats to be done. */
      /* If RepeatCount is 0 ("SILENT"), we wanted to wait for specified duration without any sound. */
      if (ActiveRepeatCount != SILENT) gpio_put(BUZZER, 1);

      FlagActiveSound   = FLAG_ON;
      ActiveMSecCounter = 0;
    }
    else
    {
      /* Check if there are more sounds to play on active buzzer. Request duration and repeat count for next sound. */
      if (queue_remove_active(&ActiveMSeconds, &ActiveRepeatCount) == 0xFF)
      {
        /* Either there is no more sound, either there was an error while trying to unqueue next sound (corrupted sound queue).
           If sound_unqueue_active() is empty or unqueue failed, make sure audio is turned off. */
        gpio_put(BUZZER, 0);
      }
      else
      {
        if (DebugBitMask & DEBUG_SOUND_QUEUE)
          log_printf(__LINE__, __func__, "- A-Unqueued:            %5u   %5u\n", ActiveMSeconds, ActiveRepeatCount);

        /* If RepeatCount is 0 ("SILENT"), we wanted to wait for specified duration without any sound. */
        if (ActiveRepeatCount != SILENT) gpio_put(BUZZER, 1);
        FlagActiveSound   = FLAG_ON;
        CurrentRepeat     = 1;
        ActiveMSecCounter = 0;
      }
    }
  }


#if 0
#ifdef PASSIVE_BUZZER_SUPPORT
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                           Handling of passive buzzer (if user replaced the one installed in the Pico-RGB-Matrix device - or add a new one).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (FlagPassiveSound == FLAG_ON)
  {
    if (DebugBitMask & DEBUG_SOUND_QUEUE)
    {
      if (Frequency == SILENT)
        snprintf(String, sizeof(String), "- P-Silence     (%4u)\n", PassiveMSecCounter + 50);
      else
        snprintf(String, sizeof(String), "- P-Sounding    (%4u)\n", PassiveMSecCounter + 50);

      log_printf(__LINE__, __func__, String);
    }

    /* There is a sound on-going on the passive buzzer, check if it is completed. */
    PassiveMSecCounter += 50;  // 50 milliseconds more since last callback.

    if (PassiveMSecCounter >= PassiveMSeconds)
    {
      if (DebugBitMask & DEBUG_SOUND_QUEUE)
        log_printf(__LINE__, __func__, "- P-Shutoff\n");

      /* Current sound on passive buzzer is over. Turn sound Off to make a cut with next sound. */
      pwm_on_off(PWM_SOUND, FLAG_OFF);

      /* No active sound for now. */
      FlagPassiveSound = FLAG_OFF;

      /* Reset sound elapsed time for now. */
      PassiveMSecCounter = 0;
    }
  }
  else
  {
    /* If we asked passive sound queue to wait for active sound queue to complete and sound queue is still active, skip this callback cycle. */
    if (FlagPassiveSound == FLAG_WAIT)
    {
      /* Check if active sound queue is done for now. */
      if ((SoundActiveHead != SoundActiveTail) || (FlagActiveSound == FLAG_ON) || (CurrentRepeat != 0))
      {
        if (DebugBitMask & DEBUG_SOUND_QUEUE)
          log_printf(__LINE__, __func__, "- P-Waiting\n");

        /* Active sound queue not done yet. */
        return TRUE;
      }
      else
      {
        /* Active sound queue done for now, short pause before triggering passive buzzer. */
        FlagPassiveSound = FLAG_ON;
        PassiveMSeconds  = 400;  // 400 milliseconds pause between active buzzer and passive buzzer.

        return TRUE;
      }
    }


    /* Check if there are more sounds to play on passive buzzer. Request frequency and duration for next sound. */
    if (sound_unqueue_passive(&Frequency, &PassiveMSeconds) == 0xFF)
    {
      /* Either there is no more sound for passive buzzer, either there was an error while trying to unqueue next sound (corrupted sound queue). */
      /* If sound_unqueue_passive() failed, make sure audio PWM is turned off. */
      pwm_on_off(PWM_SOUND, FLAG_OFF);
      FlagPassiveSound = FLAG_OFF;
    }
    else
    {
      if (DebugBitMask & DEBUG_SOUND_QUEUE)
        log_printf(__LINE__, __func__, "- P-Unqueued:            %5u   %5u\n", Frequency, PassiveMSeconds);

      /* If frequency is 0 ("SILENT"), we wanted to wait for specified duration without any sound. */
      if (Frequency == SILENT)
      {
        if (PassiveMSeconds == WAIT_4_ACTIVE)
          FlagPassiveSound   = FLAG_WAIT;
        else
          FlagPassiveSound   = FLAG_ON;
      }
      else
      {
        /* Set new sound frequency... */
        pwm_set_frequency(Frequency);

        /* ...and turn On sound. */
        pwm_on_off(PWM_SOUND, FLAG_ON);
        FlagPassiveSound   = FLAG_ON;
      }
      PassiveMSecCounter = 0;
    }
  }
#endif  // PASSIVE_BUZZER_SUPPORT
#endif  // 0


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                Mechanism to find the actual time spent in this callback routine.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (TargetCallback == CALLBACK_50MS)
  {
    if (CallbackCounter == 0) AbsoluteExitTime = get_absolute_time();
  }

  return true;
}





/* $PAGE */
/* $TITLE=callback_1000msec_timer() */
/* ============================================================================================================================================================= *\
                                                       One-second callback to update date and time on LED matrix.
\* ============================================================================================================================================================= */
bool callback_1000msec_timer(struct repeating_timer *)
{
  static UINT8 ColumnNumber0;
  static UINT8 ColumnNumber1;
  static UINT8 PreviousDay;

  INT16 ReturnCode;

  UINT16 Loop1UInt16;
  static UINT16 WatchDogCore0Previous;
  static UINT16 WatchDogCore1Previous;

  datetime_t DateTime;

  struct human_time HumanTime;
  struct tm TmTime;


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                               Mechanism to evaluate the actual time spent in this callback function.
                         Make an evaluation every 2 seconds so that the main endless system loop can process the data between each reading.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (TargetCallback == CALLBACK_1000MS)
  {
    ++CallbackCounter;
    if (CallbackCounter >= 2)
    {
      CallbackCounter = 0;
      AbsoluteEntryTime = get_absolute_time();
    }
  }



/// #ifdef NTP_SUPPORT
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                  Update Unix time representing local time and local copy of UTC time.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Update local value of UTC time and Local time. */
  ++StructNTP.UTCTime;
  ++StructNTP.LocalTime;



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                         Check if it is time to change from day light saving time to normal time or vice-versa.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if ((StructNTP.UTCTime == StructNTP.DSTStart) || (StructNTP.UTCTime == StructNTP.DSTEnd))
  {
    if (StructNTP.UTCTime == StructNTP.DSTStart)
    {
      StructNTP.FlagSummerTime     = FLAG_ON;
      ActiveConfig0.FlagSummerTime = FLAG_ON;
    }

    if (StructNTP.UTCTime == StructNTP.DSTEnd)
    {
      StructNTP.FlagSummerTime     = FLAG_OFF;
      ActiveConfig0.FlagSummerTime = FLAG_OFF;
    }


    /* Take into account local time difference with UTC time and daylight saving time status to adjust local time on RGB Matrix display. */
    convert_unix_time(StructNTP.UTCTime + (StructNTP.DeltaTime * 60) + (StructNTP.FlagSummerTime * (StructNTP.ShiftMinutes * 60)), &TmTime, &HumanTime);
    ds3231_set_time(&HumanTime);

    /* Set Pico's internal real-time clock with date and time retrieved from DS3231 real-time clock IC. */
    DateTime.hour  = HumanTime.Hour;
    DateTime.min   = HumanTime.Minute;
    DateTime.sec   = HumanTime.Second;
    DateTime.dotw  = HumanTime.DayOfWeek;
    DateTime.day   = HumanTime.DayOfMonth;
    DateTime.month = HumanTime.Month;
    DateTime.year  = HumanTime.Year;

    rtc_set_datetime(&DateTime);  // set current time on Pico's real-time clock.


  
#if defined(MQTT_SUPPORT) && defined(MQTT_TIME_SERVER)
    /* If this device is designated as the MQTT Time Server for SLASH Smart Home ecosystem, broadcast adjusted time to all device of the ecosystem. */
    mqtt_broadcast_time();
#endif  // MQTT_TIME_SERVER 
  }
/// #endif  // NTP_SUPPORT



#ifdef WATCHDOG_SUPPORT
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                               Watchdog mechanism to recover from a RGB Matrix endless loop thread crash (for either core0 or core1).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Check if core 0 endless loop has cranked up core 0 watchdog counter. */
  if (WinBot == WIN_TIME)
  {
    /* Check if core 0 thread has changed the watchdog counter since last cycle. */
    if (WatchDogCore0 != WatchDogCore0Previous)
    {
      /* Watchdog counter for core 0 has changed, core 0 endless loop. Thread is still alive. */
      WatchDogCore0Previous = WatchDogCore0;
      WatchDogCore0Miss     = 0;  // core 0 thread is still alive, reset cumulative misses.

      /* If watchdog countdown already began to show up on WIN_TIME window border, reset it. */
      if (ColumnNumber0)
      {
        RGB_matrix_set_color(Window[WIN_TIME].StartRow, Window[WIN_TIME].StartColumn, Window[WIN_TIME].StartRow, Window[WIN_TIME].EndColumn, Window[WIN_TIME].BorderColor);
        ColumnNumber0 = 0;
      }
    }
    else
    {
      /* Main core 0 thread seems not to be alive. Let some time before triggering a Firmware restart). */
      ++WatchDogCore0Miss;
      if (WatchDogCore0Miss >= WATCHDOG_SECONDS)
      {
        software_reset(0);
      }

      /* Display an incremental indicator on LED display to show "how far we are" from a Firmware restart. */
      /* NOTE: Watchdog for core 0 shows up on top border of WinTime window. */
      ColumnNumber0 = (UINT8)((WatchDogCore0Miss / (WATCHDOG_SECONDS / (MAX_COLUMNS / 2))) - 0.5);

      if (ColumnNumber0 > 0)
      {
        /* Change LED color to white on the left side of the time window top border line. */
        RGB_matrix_set_color(18, ColumnNumber0, 18, ColumnNumber0, WHITE);

        /* Change LED color to white on the right side of the time window top border line. */
        ColumnNumber0 = (63 - ColumnNumber0);
        RGB_matrix_set_color(18, ColumnNumber0, 18, ColumnNumber0, WHITE);
      }
    }
  }



  /* Check if core 1 endless loop has cranked up core 1 watchdog counter. */
  if (WinBot == WIN_TIME)
  {
    /* Check if core 1 thread has changed the watchdog counter since last cycle. */
    if (WatchDogCore1 != WatchDogCore1Previous)
    {
      /* Watchdog counter for core 1 has changed, core 1 endless loop thread is still alive. */
      WatchDogCore1Previous = WatchDogCore1;
      WatchDogCore1Miss     = 0;  // core 1 thread is still alive, reset cumulative misses.

      /* If watchdog countdown already began to show up on WIN_TIME window border, reset it. */
      if (ColumnNumber1)
      {
        RGB_matrix_set_color(Window[WIN_TIME].EndRow, Window[WIN_TIME].StartColumn, Window[WIN_TIME].EndRow, Window[WIN_TIME].EndColumn, Window[WIN_TIME].BorderColor);
        ColumnNumber1 = 0;
      }
    }
    else
    {
      /* Main core 1 thread seems not to be alive. Let some time before triggering a Firmware restart). */
      ++WatchDogCore1Miss;
      if (WatchDogCore1Miss >= WATCHDOG_SECONDS)
      {
        software_reset(0);
      }

      /* Display an incremental indicator on LED display to show "how far we are" from a Firmware restart. */
      /* NOTE: Watchdog for core 1 shows up on bottom border of WinTime window. */
      ColumnNumber1 = (UINT8)((WatchDogCore1Miss / (WATCHDOG_SECONDS / (MAX_COLUMNS / 2))) - 0.5);

      if (ColumnNumber1 > 0)
      {
        /* Change LED color to white on the left side of the time window bottom border line. */
        RGB_matrix_set_color(Window[WIN_TIME].EndRow, ColumnNumber1, Window[WIN_TIME].EndRow, ColumnNumber1, WHITE);

        /* Change LED color to white on the right side of the time window bottom border line. */
        ColumnNumber1 = (63 - ColumnNumber1);
        RGB_matrix_set_color(Window[WIN_TIME].EndRow, ColumnNumber1, Window[WIN_TIME].EndRow, ColumnNumber1, WHITE);
      }
    }
  }
#endif  // WATCHDOG_SUPPORT



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                           Read date and time from real-time clock IC (DS3231).
                                    NOTE: Time update is done on ShadowBuffer inside endless loop in the core1 main thread context.
                                          This prevent the one-second callback to be too long and generate a little "glitch" during the one-msec
                                          matrix-scan callback.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  ds3231_get_time(&CurrentTime);



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                            Adjust automatic brightness if this option is On now.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* If user turned On Service Light timer, set the brightness to highest value and decrement service light timer. */
  if (ServiceLightTimer != 0)
  {
    /* Decrement the service light timer by one second. */
    --ServiceLightTimer;
  }
  else
  {
    /* Service light is not active... */
    if (ActiveConfig0.FlagAutoBrightness == FLAG_ON) set_auto_brightness(FLAG_OFF);
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                           Manage hourly chime.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if ((CurrentTime.Second == 0) && (CurrentTime.Minute == 0))
  {
    /* Hour has just changed... manage hourly chime as required. */
    if ((ActiveConfig0.ChimeMode == FLAG_ON) ||
       ((ActiveConfig0.ChimeMode == FLAG_DAY) && ((CurrentTime.Hour >= ActiveConfig0.ChimeTimeOn) && (CurrentTime.Hour <= ActiveConfig0.ChimeTimeOff))))
    {
      for (Loop1UInt16 = 0; Loop1UInt16 < 3; ++Loop1UInt16)
      {
        queue_add_active(50, 2);
        queue_add_active(50, SILENT);
      }
      queue_add_active(100, SILENT);  // separate this train of sounds from any another eventual sound requested later on.

#if defined(SOUND_SERVER_DRIVE) && defined(MQTT_SUPPORT)
      INT16 ReturnCode;
      /* Make sure MQTT client is still alive to prevent a crash. */
      if ((StructMQTT.MqttClientInstance != NULL) && (mqtt_client_is_connected(StructMQTT.MqttClientInstance)))
      {
        mqtt_wipe_packet();
        snprintf(StructMQTT.Topic,   sizeof(StructMQTT.Topic),   "SoundServer/SoundCommand/%s", StructMQTT.PicoIdentifier);  // include source of MQTT message as the last topic item.
        snprintf(StructMQTT.Payload, sizeof(StructMQTT.Payload), "6/25/3/1");                                              // set sound level to 25 and play track 1.
        ReturnCode = mqtt_publish(StructMQTT.MqttClientInstance, StructMQTT.Topic, StructMQTT.Payload, strlen(StructMQTT.Payload), 0, 0, mqtt_pub_request_cb, &StructMQTT);
        if (ReturnCode)
          log_printf(__LINE__, __func__, "Error 0x%X while trying to publish on Topic <%s>   Payload: <%s>.\n", ReturnCode, StructMQTT.Topic, StructMQTT.Payload);
      }
#endif  // MQTT_SUPPORT && SOUND_SERVER_DRIVE
    }
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                   Manage half-hour light chime.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if ((CurrentTime.Second == 0) && (CurrentTime.Minute == 30))
  {
    /* We just reached half-hour... manage information as required. */
    if ((ActiveConfig0.ChimeMode == FLAG_ON) ||
       ((ActiveConfig0.ChimeMode == FLAG_DAY) && ((CurrentTime.Hour >= ActiveConfig0.ChimeTimeOn) && (CurrentTime.Hour <= ActiveConfig0.ChimeTimeOff))))
    {
      queue_add_active(50, 2);
      queue_add_active(100, SILENT);

#if defined(SOUND_SERVER_DRIVE) && defined(MQTT_SUPPORT)
      /* Send half-hour chime jingle to sound server. */
      /* Make sure MQTT client is still alive to prevent a crash. */
      if ((StructMQTT.MqttClientInstance != NULL) && (mqtt_client_is_connected(StructMQTT.MqttClientInstance)))
      {
        mqtt_wipe_packet();
        snprintf(StructMQTT.Topic,   sizeof(StructMQTT.Topic),   "SoundServer/SoundCommand/%s", StructMQTT.PicoIdentifier);  // include source of MQTT message as the last topic item.
        snprintf(StructMQTT.Payload, sizeof(StructMQTT.Payload), "6/25/3/2");                                              // set sound level to 25 and play track 2.
        ReturnCode = mqtt_publish(StructMQTT.MqttClientInstance, StructMQTT.Topic, StructMQTT.Payload, strlen(StructMQTT.Payload), 0, 0, mqtt_pub_request_cb, &StructMQTT);
        if (ReturnCode)
          log_printf(__LINE__, __func__, "Error 0x%X while trying to publish on Topic <%s>   Payload: <%s>.\n", ReturnCode, StructMQTT.Topic, StructMQTT.Payload);
      }
#endif  // MQTT_SUPPORT && SOUND_SERVER_DRIVE
    }
    queue_add_active(100, SILENT);  // separate this train of sounds from any another eventual sound requested later on.
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                           Manage reminders.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* At minute change, check if new reminders must be triggered. */
  //1 if (CurrentTime.Second == 0) reminder1_check();

  /* Check if it is time to feed rings for some active alarms (ringer feeding is not always on a minute boundary). */
  //1 reminder1_ring();



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                        Manage calendar events.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* At date change, update bitmask of active calendar events for today. */
  if (CurrentTime.DayOfMonth != PreviousDay)
  {
    /* We will have just checked calendar events for today's date. */
    PreviousDay = CurrentTime.DayOfMonth;

    /* Clear current event bitmask. */
    EventBitMask = 0ll;

    /* Check for eventual today's events. */
    event_check();
  }

  /* If there are some active calendar events today, handle them. */
  if (EventBitMask)
  {
    /* There are some calendar events for today. */
    if ((CurrentTime.Second == 0) && ((CurrentTime.Minute == 12) || (CurrentTime.Minute == 42)))
    {
      /* Feed event ringer every half hour, at xx:12 and xx:42. */
      /* There are some triggered events, scan all events to find those that are active today. */
      for (Loop1UInt16 = 0; Loop1UInt16 < MAX_EVENTS; ++Loop1UInt16)
      {
        if (EventBitMask & (1 << Loop1UInt16))
        {
          /* This calendar event is active. */
          /* Scroll message for this triggered event on RGB matrix. */
          win_scroll(WIN_DAY, 201, 201, 3, 1, FONT_5x7, "%s", ActiveConfig0.Event[Loop1UInt16].Message);

          if ((CurrentTime.Hour >= ActiveConfig0.ChimeTimeOn) && (CurrentTime.Hour <= ActiveConfig0.ChimeTimeOff))
          {
            /* Feed one ringer for all events. */
            queue_add_active(250, 5);
            queue_add_active(400, SILENT);
            queue_add_active(250, 5);
            queue_add_active(5000, SILENT);  // make sure to isolate this sound train from any eventual others that could follow.

#if defined(SOUND_SERVER_DRIVE) && defined(MQTT_SUPPORT)
            /* Send command to SoundServer to play specified jingle if defined. */
            if (ActiveConfig0.Event[Loop1UInt16].Jingle != 0)
            {
              /* Make sure MQTT client is still alive to prevent a crash. */
              if ((StructMQTT.MqttClientInstance != NULL) && (mqtt_client_is_connected(StructMQTT.MqttClientInstance)))
              {
                mqtt_wipe_packet();
                snprintf(StructMQTT.Topic,   sizeof(StructMQTT.Topic),   "SoundServer/SoundCommand/%s", StructMQTT.PicoIdentifier);  // include source of MQTT message as the last topic item.
                snprintf(StructMQTT.Payload, sizeof(StructMQTT.Payload), "6/25/3/%u", ActiveConfig0.Event[Loop1UInt16].Jingle);     // set sound level to 25 and play specified track number.
                ReturnCode = mqtt_publish(StructMQTT.MqttClientInstance, StructMQTT.Topic, StructMQTT.Payload, strlen(StructMQTT.Payload), 0, 0, mqtt_pub_request_cb, &StructMQTT);
                if (ReturnCode)
                  log_printf(__LINE__, __func__, "Error 0x%X while trying to publish on Topic <%s>   Payload: <%s>.\n", ReturnCode, StructMQTT.Topic, StructMQTT.Payload);
              }
            }
#endif  // SOUND_SERVER_DRIVE && MQTT_SUPPORT 
          }
        }
      }
    }
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                              Manage alarms.
                                Keep it at the bottom of the list so that this is what will remain on RGB display at the end of checkings.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* At minute change, check if new alarms must be triggered. */
  if (CurrentTime.Second == 0) alarm_check();

  /* Check if it is time to feed rings for some active alarms (ringer feeding is not always on a minute boundary). */
  alarm_ring();



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                            Manage auto-scrolls.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (CurrentTime.Second == 2)
  {
    /* Check if one of the auto-scrolls defined has reached its repeat period. */
    for (Loop1UInt16 = 0; Loop1UInt16 < MAX_AUTO_SCROLLS; ++Loop1UInt16)
    {
      if ((ActiveConfig0.AutoScroll[Loop1UInt16].Period != 0) && ((CurrentTime.Minute % ActiveConfig0.AutoScroll[Loop1UInt16].Period) == 0))
      {
        /* We reached the repeat period for this auto-scroll -> set the corresponding bit in the bitmask. It will be processed by the main system loop
           when available. This prevent the scrolling to interfere with user operation and it also prevent the scrolling buffer to fill-up if scrolling
           is not currently available. */
        AutoScrollBitMask |= (0x01 << Loop1UInt16);
      }
    }
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                               Manage blinking area of active windows if there are some that are active.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if ((Window[WinTop].FlagBlink) || (Window[WinMid].FlagBlink) || (Window[WinBot].FlagBlink)) RGB_matrix_blink();



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                         Turn-Off endless loop pilots on the first line of LED matrix if it is time to do so.
                                      Also, toggle between red and green color for double-dots warning indicators on RGB display. 
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (CurrentTime.Second % 2)
  {
    pilot_toggle(ShadowBuffer);
    RGB_matrix_set_row_mask(&DisplayMatrix.RowMask, 0, 0);
  }



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                      Mechanism to find the actual time spent in this callback routine.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (TargetCallback == CALLBACK_1000MS)
  {
    if (CallbackCounter == 0)
    {
      AbsoluteExitTime = get_absolute_time();
    }
  }

  return true;
}





/* $PAGE */
/* $TITLE=convert_human_to_tm() */
/* ============================================================================================================================================================= *\
                                                                  Convert "HumanTime" to "tm_time".
\* ============================================================================================================================================================= */
void convert_human_to_tm(struct human_time *HumanTime, struct tm *TmTime)
{
  TmTime->tm_mday  = HumanTime->DayOfMonth;     // tm_mday: 1 to 31
  TmTime->tm_mon   = HumanTime->Month - 1;      // tm_mon:  months since January (0 to 11)
  TmTime->tm_year  = HumanTime->Year - 1900;    // tm_year: years since 1900
  TmTime->tm_wday  = HumanTime->DayOfWeek;      // tm_wday: Sunday = 0 (...)  Saturday = 6
  TmTime->tm_yday  = HumanTime->DayOfYear - 1;  // tm_yday: 0 to 365
  TmTime->tm_hour  = HumanTime->Hour;           // tm_hour: 0 to 23
  TmTime->tm_min   = HumanTime->Minute;         // tm_min:  0 to 59
  TmTime->tm_sec   = HumanTime->Second;         // tm_sec:  0 to 59
  TmTime->tm_isdst = 0;                         // tm_isdst: (if < 0 means not used)   (if > 0 means FLAG_ON)   (if = 0 means FLAG_OFF)

  return;
}





/* $PAGE */
/* $TITLE=convert_human_to_unix() */
/* ============================================================================================================================================================= *\
                                                                  Convert "HumanTime" to "Unix Time".
                                                         NOTE: Unix Time is based on UTC time, not local time.
\* ============================================================================================================================================================= */
UINT64 convert_human_to_unix(struct human_time *HumanTime)
{
  UINT64 UnixTime;

  struct tm TempTime;


  convert_human_to_tm(HumanTime, &TempTime);
  UnixTime = convert_tm_to_unix(&TempTime);

  return UnixTime;
}





/* $PAGE */
/* $TITLE=convert_tm_to_unix() */
/* ============================================================================================================================================================= *\
                                                                     Convert "TmTime" to "Unix Time".
                                                         NOTE: Unix Time is based on UTC time, not local time.
\* ============================================================================================================================================================= */
UINT64 convert_tm_to_unix(struct tm *TmTime)
{
  time_t UnixTime;


  UnixTime = mktime(TmTime);

  return UnixTime;
}





/* $PAGE */
/* $TITLE=convert_unix_time() */
/* ============================================================================================================================================================= *\
                                                             Convert Unix time to tm time and human time.
                      NOTE: DS3231 gives correct value for day-of-year but the convertion is incorrect for leap year... must be investigated.
\* ============================================================================================================================================================= */
void convert_unix_time(time_t UnixTime, struct tm *TmTime, struct human_time *HumanTime)
{
  struct tm TempTime;


  if (DebugBitMask & DEBUG_NTP) log_printf(__LINE__, __func__, "Unix time on entry: %llu\n", UnixTime);

  /* Find tm_time */
  TempTime = *localtime(&UnixTime);


  /*** Transfer to calling structure. Must be optimized. */
  TmTime->tm_hour  = TempTime.tm_hour;
  TmTime->tm_min   = TempTime.tm_min;
  TmTime->tm_sec   = TempTime.tm_sec;
  TmTime->tm_mday  = TempTime.tm_mday;
  TmTime->tm_mon   = TempTime.tm_mon;
  TmTime->tm_year  = TempTime.tm_year;
  TmTime->tm_wday  = TempTime.tm_wday;
  TmTime->tm_yday  = TempTime.tm_yday;
  TmTime->tm_isdst = TempTime.tm_isdst;


  /* Find equivalent in human time. */
  HumanTime->Hour       = TmTime->tm_hour;
  HumanTime->Minute     = TmTime->tm_min;
  HumanTime->Second     = TmTime->tm_sec;
  HumanTime->DayOfMonth = TmTime->tm_mday;
  HumanTime->Month      = TmTime->tm_mon + 1;
  HumanTime->Year       = TmTime->tm_year + 1900;
  HumanTime->DayOfWeek  = TmTime->tm_wday;
  HumanTime->DayOfYear  = TmTime->tm_yday;
  HumanTime->FlagDst    = TmTime->tm_isdst;

#if 0
  if (DebugBitMask & DEBUG_NTP)
  {
    display_human_time("HumanTime after conversion from UnixTime: ", HumanTime);

    log_printf(__LINE__, __func__, "HumanTime->Hour        =   %2.2u\n", HumanTime->Hour);
    log_printf(__LINE__, __func__, "HumanTime->Minute      =   %2.2u\n", HumanTime->Minute);
    log_printf(__LINE__, __func__, "HumanTime->Second      =   %2.2u\n", HumanTime->Second);
    log_printf(__LINE__, __func__, "HumanTime->DayOfMonth  =   %2.2u\n", HumanTime->DayOfMonth);
    log_printf(__LINE__, __func__, "HumanTime->Month       =   %2.2u\n", HumanTime->Month);
    log_printf(__LINE__, __func__, "HumanTime->Year        = %4.4u\n",   HumanTime->Year);
    log_printf(__LINE__, __func__, "HumanTime->DayOfWeek   = %4u\n",     HumanTime->DayOfWeek);
    log_printf(__LINE__, __func__, "HumanTime->DayOfYear   = %4u\n",     HumanTime->DayOfYear);
    log_printf(__LINE__, __func__, "HumanTime->FlagDst     = %4u\n\n\n", HumanTime->FlagDst);
  }
#endif  // 0

  return;
}





/* $PAGE */
/* $TITLE=time_steps_loop() */
/* ============================================================================================================================================================= *\
                                                                Thread to be run on one of Pico's core.
                          This core is in charge of receiving infrared data streams and monitoring hardware interrupts for local buttons.
                                                             This core LED "I'm alive indicators" is yellow.
\* ============================================================================================================================================================= */
void time_steps_loop(void)
{
#ifdef RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // must be turned OFF at all times.
#else  // RELEASE_VERSION
  UINT8 FlagLocalDebug = FLAG_OFF;  // may be turned ON for debug purposes.
#endif  // RELEASE_VERSION

  UCHAR String[128];

  UINT8 IrStepCount;
  UINT8 LastDisplayedSecond;

  UINT16 FunctionNumber;
  UINT16 LastServiceTimer;
  UINT16 Loop1UInt16;
  UINT16 Loop2UInt16;
  UINT16 ReturnCode;

  UINT64 CurrentTimer;
  UINT64 LastTimer1Sec;
  UINT64 LastTimer2Sec;
  UINT64 LastTimer5Sec;
  UINT64 LastTimer10Sec;
  UINT64 LastTimer15Sec;
  UINT64 LastTimer30Sec;
  UINT64 LastTimer1Min;
  UINT64 LastTimer10Min;
  UINT64 LastTimer60Min;
  UINT64 WatchdogCoreTimer;

  FLOAT DegreeC;
  FLOAT DegreeF;


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                      Before starting this core's endless loop as is, set the Interrupt Service Routines that will be taken care of by this core.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_CORE) log_printf(__LINE__, __func__, "Entering core %u context()\n", get_core_num());

  ReturnCode = (flash_safe_execute_core_init());
  if (ReturnCode == true)
    log_printf(__LINE__, __func__, "flash_safe_execute_core_init() executed successfully (returned: %d)\n", ReturnCode);
  else
    log_printf(__LINE__, __func__, "Error with flash_safe_execute_core_init() returned: %d\n", ReturnCode);

  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before launching ISR for IR sensor.\n");
    sleep_ms(1000);  // slow down startup sequence for debug purposes.
  }

  /* Let the IR sensor be initialized even if we don't use the remote control since it is
     the base irq service routine eventual infrared glitches will simply be ignored. */
  gpio_set_irq_enabled_with_callback(IR_RX, GPIO_IRQ_EDGE_FALL | GPIO_IRQ_EDGE_RISE, true, (gpio_irq_callback_t)&isr_signal_trap);


  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Adding button <DOWN> to ISR callback.\n");
    sleep_ms(1000);  // slow down startup sequence for debug purposes.
  }
  gpio_set_irq_enabled(BUTTON_DOWN_GPIO, GPIO_IRQ_EDGE_RISE | GPIO_IRQ_EDGE_FALL, true);


  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Adding button <SET> to ISR callback.\n");
    sleep_ms(1000);  // slow down startup sequence for debug purposes.
  }
  gpio_set_irq_enabled(BUTTON_SET_GPIO, GPIO_IRQ_EDGE_RISE | GPIO_IRQ_EDGE_FALL, true);


  /* Since the gpio callback has been set above for infrared sensor, simply add other GPIO's to the same callback. */
  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Adding button <UP> to ISR callback.\n");
    sleep_ms(1000);  // slow down startup sequence for debug purposes.
  }
  gpio_set_irq_enabled(BUTTON_UP_GPIO, GPIO_IRQ_EDGE_RISE | GPIO_IRQ_EDGE_FALL, true);


  /* Initialize all time step timers on entry. */
  IrStepCount         = 0;
  LastDisplayedSecond = 61;  // invalid value to force an update on entry.
  LastServiceTimer    = 0;
  CurrentTimer        = time_us_64();
  LastTimer1Sec       = CurrentTimer;
  LastTimer2Sec       = CurrentTimer;
  LastTimer5Sec       = CurrentTimer;
  LastTimer10Sec      = CurrentTimer;
  LastTimer15Sec      = 0ll;  // force entry in 15-sec time step on first pass.
  LastTimer30Sec      = CurrentTimer;
  LastTimer1Min       = CurrentTimer;
  LastTimer10Min      = CurrentTimer;
  LastTimer60Min      = CurrentTimer;
  WatchdogCoreTimer   = CurrentTimer;

  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                Main forever loop for this Pico's core.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Entering time steps endless loop on core %u (yellow indicator)\n", get_core_num());
  sleep_ms(1000);  // slow down startup sequence for debug purposes.

  while (1)
  {
    if (FlagLocalDebug) log_printf(__LINE__, __func__, "Core %u loop start.\n", get_core_num());
    CurrentTimer = time_us_64();
    while (FlagStopCore)
    {
      if (FlagStopCore == FLAG_ON)
      {
        // ++FlagStopCore;  // display message only once.
        // log_printf(__LINE__, __func__, "Entering core %u stop.\n", get_core_num());
      }
      sleep_ms(300);
    }



#ifdef ZIGBEE_SUPPORT
    /* ========================================================================================================================================================= *\
                                                                      Initialize ZigBee protocol.
    \* ========================================================================================================================================================= */
#else // ZIGBEE_SUPPORT
    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                             NOTE: Since ZigBee protocol is not supported yet, let's fake that initialization has been successful so that
                                   the double-dots indicator on LED display will not be red to indicate a ZigBee error.      
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    FlagHealthZigBee = FLAG_ON;
#endif  // ZIGBEE_SUPPORT



    /* ========================================================================================================================================================= *\
                         Check if real-time clock IC has changed the second count since last loop cycle (updated by the one-second callback).
    \* ========================================================================================================================================================= */
    if (CurrentTime.Second != LastDisplayedSecond)
    {
      LastDisplayedSecond = CurrentTime.Second;
      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering check for real-time clock change.\n");


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                               Update day-of-week, date and time in ShadowBuffer. FrameBuffer will then be updated by the 1-msec callback.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      RGB_matrix_display_time();


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                   Update Service Light logic if it is active.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if (WinTop == WIN_LIGHT)
      {
        /* Service Light is currently active. */
        if (ServiceLightTimer != LastServiceTimer)
        {
          /* It is time to update the count-down on LED matrix. */
          LastServiceTimer = ServiceLightTimer;  // seconds count-down has changed since last loop cycle.
          RGB_matrix_printf(ShadowBuffer, 1, 99, FONT_5x7, " %u ", ServiceLightTimer);
          RGB_matrix_set_row_mask(&DisplayMatrix.RowMask, 1, 7);
          DisplayMatrix.FlagUpdate = FLAG_ON;

          /* Check if Service Light Timer is down to zero. */
          if (ServiceLightTimer == 0)
          {
            if (DebugBitMask & DEBUG_SERVICE)
            {
              log_printf(__LINE__, __func__, "ServiceLightTimer value decremented down to: %3u sec\n", ServiceLightTimer);
              log_printf(__LINE__, __func__, "Gonna close WIN_LIGHT window.\n");
            }
          
            if (ActiveConfig0.FlagAutoBrightness == FLAG_ON)
            {
              set_auto_brightness(FLAG_ON);  // restore LED matrix brightness to automatic control.
              if (DebugBitMask & DEBUG_SERVICE) log_printf(__LINE__, __func__, "Just reset auto-brightness.\n");
            }
            else
            {
              RGB_matrix_set_brightness(ActiveConfig0.BrightnessLevel);  // restore LED matrix brightness to "steady" setting.
              if (DebugBitMask & DEBUG_SERVICE) log_printf(__LINE__, __func__, "Just reset steady brightness.\n");
            }

            TimerLastServiceLight = 0ll;  // reset service light request time.
            win_close(WIN_LIGHT, FLAG_ON);
          }
        }
      }



      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                             Manage endless loop pixel indicator pilots.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if ((WinTop == WIN_DAY) || (WinTop == WIN_LIGHT))
      {
        /* Blinking pixels to indicate that endless loop in current core context is still running. */
        if (((CurrentTime.Second & 0x07) == 0x02) || ((CurrentTime.Second & 0x07) == 0x06))
        {
          pilot_set_color(YELLOW);  // core in charge of most time steps: color = YELLOW.
          pilot_toggle(ShadowBuffer);
          RGB_matrix_set_row_mask(&DisplayMatrix.RowMask, 0, 0);
          DisplayMatrix.FlagUpdate = FLAG_ON;
        }
      }



      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                    Check if it is time to change RGB Matrix color if Golden flag is On.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if ((ActiveConfig0.FlagGoldenAge) && ((CurrentTime.Hour >= ActiveConfig0.GoldenMorningStart) || (CurrentTime.Hour < ActiveConfig0.GoldenNightStart))) 
        refresh_matrix_colors();

      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting time step indicating that the seconds have changed on the clock.\n\n");
    }





#ifdef REMOTE_SUPPORT
    /* ========================================================================================================================================================= *\
                                                    Check if something has been received from remote control buttons.
    \* ========================================================================================================================================================= */
    /* Turn On infrared LED indicators on RGB matrix when the infrared data stream begins. */
    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                        Manage infrared indicator.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering check for IR stream reception.\n");

    if ((IrTimer) && (WinBot == WIN_TIME))
    {
      if (CurrentTimer < (IrTimer + 500000ll))
      {
        /* First delay interval to indicate that we received an infrared burst (IR indicators are blue). */
        if ((DebugBitMask & DEBUG_IR) && (IrStepCount == 0))
        {
          ++IrStepCount;
          log_printf(__LINE__, __func__, "First IR delay interval for IR burst.\n");
        }

        /* One-second interval since we received an IR burst. */
        RGB_matrix_set_pixel(FrameBuffer, IR_INDICATOR_START_ROW, IR_INDICATOR_START_COLUMN, IR_INDICATOR_END_ROW, IR_INDICATOR_END_COLUMN);  // second row.
        RGB_matrix_set_color(IR_INDICATOR_START_ROW, IR_INDICATOR_START_COLUMN, IR_INDICATOR_END_ROW, IR_INDICATOR_END_COLUMN, BLUE);         // both rows
      }

      if ((CurrentTimer > (IrTimer + 500000ll)) && (CurrentTimer < (IrTimer + 1500000ll)))
      {
        /* Second delay interval after we received an infrared burst (indicator will indicate valid or invalid IR stream: GREEN / RED). */
        if ((DebugBitMask & DEBUG_IR) && (IrStepCount == 1))
        {
          ++IrStepCount;
          log_printf(__LINE__, __func__, "Second IR delay interval for IR burst.\n");
        }

        /* Two-second interval since we received an IR burst. */
        RGB_matrix_set_pixel(FrameBuffer, IR_INDICATOR_START_ROW, IR_INDICATOR_START_COLUMN, IR_INDICATOR_END_ROW, IR_INDICATOR_END_COLUMN);  // second row.
        if (IrFlagSuccess == FLAG_ON)
          RGB_matrix_set_color(IR_INDICATOR_START_ROW, IR_INDICATOR_START_COLUMN, IR_INDICATOR_END_ROW, IR_INDICATOR_END_COLUMN, GREEN); // valid IR data stream
        else
          RGB_matrix_set_color(IR_INDICATOR_START_ROW, IR_INDICATOR_START_COLUMN, IR_INDICATOR_END_ROW, IR_INDICATOR_END_COLUMN, RED);   // bad IR data stream
      }

      if (CurrentTimer > (IrTimer + 1500000ll))
      {
        /* Three-second interval after we received an infrared burst. */
        if ((DebugBitMask & DEBUG_IR) && (IrStepCount == 3))
        {
          IrStepCount = 0;
          log_printf(__LINE__, __func__, "Three-second interval for IR burst.\n");
        }

        /* Reset IrFlagSuccess and IrTimer to be prepared for next IR burst. */
        IrFlagSuccess = 0x02;  // undefined result.
        IrTimer       = 0ll;

        /* Reset color of WIN_TIME border color. */
        RGB_matrix_set_color(Window[WIN_TIME].StartRow, Window[WIN_TIME].StartColumn, Window[WIN_TIME].StartRow, Window[WIN_TIME].EndColumn, Window[WIN_TIME].BorderColor);

        /* Clear pixels of the extra line used for IR indicator. */
        RGB_matrix_clear_pixel(FrameBuffer, IR_INDICATOR_END_ROW, IR_INDICATOR_START_COLUMN, IR_INDICATOR_END_ROW, IR_INDICATOR_END_COLUMN);
      }

      /* If infrared remote control support is enabled, check if data has been received by infrared sensor. */
      if (IrBuffer[0] != IR_LO_LIMIT)
      {
        if (DebugBitMask & DEBUG_IR) log_printf(__LINE__, __func__, "Button %s (%u) has been pressed on remote control...\n", ButtonName[IrBuffer[0]], IrBuffer[0]);
      }
    }

    if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting check for IR stream reception.\n\n");
#endif  // REMOTE_SUPPORT



    /* ========================================================================================================================================================= *\
                                   Check if something has been received either from local buttons and / or from remote control buttons.
    \* ========================================================================================================================================================= */
    if (FlagLocalDebug)
    {
      log_printf(__LINE__, __func__, "Entering button check (local and remote control).\n");
      sleep_ms(300);
    }

    if (ButtonBuffer[0] != BUTTON_NONE)
    {
      if (DebugBitMask & DEBUG_BUTTON)
      {
        if (DebugBitMask & DEBUG_IR) log_printf(__LINE__, __func__, "Button %s (%u) has been pressed on remote control...\n", ButtonName[ButtonBuffer[0]], ButtonBuffer[0]);

        switch (ButtonBuffer[0])
        {
          case (BUTTON_SET):
            log_printf(__LINE__, __func__, "Button <Set> quick press...\n");
          break;

          case (BUTTON_SET_LONG):
            log_printf(__LINE__, __func__, "Button <Set> long press...\n");
          break;

          case (BUTTON_DOWN):
            log_printf(__LINE__, __func__, "Button <Down> quick press...\n");
          break;

          case (BUTTON_DOWN_LONG):
            log_printf(__LINE__, __func__, "Button <Down> long press...\n");
          break;

          case (BUTTON_UP):
            log_printf(__LINE__, __func__, "Button <Up> quick press...\n");
          break;

          case (BUTTON_UP_LONG):
            log_printf(__LINE__, __func__, "Button <Up> long press...\n");
          break;
        }
      }
    }

    /* Handle an eventual button press, either from local buttons or from remote control. */
    if ((IrBuffer[0] != BUTTON_NONE) && (ButtonBuffer[0] == BUTTON_NONE))
    {
      /* Local buttons have priority over remote control buttons. So, only if there is no local button press, process any eventual remote button press. */
      ButtonBuffer[0] = IrBuffer[0];
    }

    /* Handle "first-pressed" eligible buttons. */
    switch (ButtonBuffer[0])
    {
      case (BUTTON_SET):
      case (BUTTON_UP_LONG):
        process_button(ButtonBuffer[0]);
      break;

      default:
        /* For now, only <Set> button is valid for a first press. */
        IrBuffer[0]     = BUTTON_NONE;
        ButtonBuffer[0] = BUTTON_NONE;
      break;
    }

    if (FlagLocalDebug)
    {
      log_printf(__LINE__, __func__, "Exiting button check (local and remote control).\n\n");
      sleep_ms(300);
    }



#ifdef WATCHDOG_SUPPORT
    /* ========================================================================================================================================================= *\
                                                                              Watchdog timer.
    \* ========================================================================================================================================================= */
    if ((CurrentTimer - WatchdogCoreTimer) > 999900ll)
    {
      WatchdogCoreTimer = CurrentTimer;
      if (FlagLocalDebug)
      {
        log_printf(__LINE__, __func__, "Entering watchdog management.\n");
        sleep_ms(300);
      }
  
      /* NOTE: Watchdog timer has been set slightly faster than one second. This is to make sure that the WatchDogCore0 variable
               will have been incremented when the callback tests its value and prevent a miss. In fact, one miss is not really
               important and everything would return to normal within the next few cycles. The idea of making it a little faster
               is to prevent a white LED that would turn On for a few seconds on the display if there is a miss. */
      ++WatchDogCore0;
      if (DebugBitMask & DEBUG_WATCHDOG) log_printf(__LINE__, __func__, "                       Core %u count: %5u\n", get_core_num(), WatchDogCore0);
    }

    if (FlagLocalDebug)
    {
      log_printf(__LINE__, __func__, "Exiting watchdog management.\n\n");
      sleep_ms(300);
    }
#endif  // WATCHDOG_SUPPORT





    /* ========================================================================================================================================================= *\
                                    1-second time step and schedule mark. Put here functions that we want to execute every second.
    \* ========================================================================================================================================================= */
    if ((CurrentTimer - LastTimer1Sec) >= 1000000ll)
    {
      LastTimer1Sec = CurrentTimer;
      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 1-second time step.\n");
      // log_printf(__LINE__, __func__, "Core 0: 1-second heartbeat.\n");


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                            Optionally display current local value of UTC time.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
#ifdef NTP_SUPPORT
      if (DebugBitMask & DEBUG_DST_TIME) log_printf(__LINE__, __func__, "StructNTP.LocalTime: %llu   StructNTP.UTCTime: %llu   DeltaTime: %d   DST start: %llu   DST end: %llu\n", StructNTP.LocalTime, StructNTP.UTCTime, StructNTP.DeltaTime, StructNTP.DSTStart, StructNTP.DSTEnd);
#endif  // NTP_SUPPORT


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                           Keep track of time spent in the target callback routine.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if (is_nil_time(AbsoluteExitTime) == false)
      {
        CallbackDuration[CallbackDurationPointer] = absolute_time_diff_us(AbsoluteEntryTime, AbsoluteExitTime);
        ++CallbackDurationPointer;
        if (CallbackDurationPointer >= MAX_CALLBACK_DURATION_UNITS) CallbackDurationPointer = 0;
        AbsoluteEntryTime = nil_time;
        AbsoluteExitTime  = nil_time;
      }


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                          Check if it is time to execute an auto-scroll now.
                                   NOTE: AutoScrollBitMask is set in the 1000 msec callback. This way, we are sure not to miss a cycle.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if (WinTop == WIN_DAY)
      {
        for (Loop1UInt16 = 0; Loop1UInt16 < MAX_AUTO_SCROLLS; ++Loop1UInt16)
        {
          if ((DebugBitMask & DEBUG_SCROLL) && (Loop1UInt16 == 0)) log_printf(__LINE__, __func__, "Checking auto-scroll's (Active bit mask: 0x%2.2X)\n", AutoScrollBitMask);
          if (AutoScrollBitMask & (0x01 << Loop1UInt16))
          {
            /* It is time to execute this auto-scroll. */
            if (DebugBitMask & DEBUG_SCROLL) log_printf(__LINE__, __func__, "Auto-scroll number %u flagged to be executed...(0x%2.2X)\n", Loop1UInt16, AutoScrollBitMask);
            for (Loop2UInt16 = 0; Loop2UInt16 < MAX_ITEMS; ++Loop2UInt16)
            {
              if (DebugBitMask & DEBUG_SCROLL) log_printf(__LINE__, __func__, "Validating item %2u   FunctionId: %3u\n", Loop2UInt16, ActiveConfig0.AutoScroll[Loop1UInt16].FunctionId[Loop2UInt16]);
              if (ActiveConfig0.AutoScroll[Loop1UInt16].FunctionId[Loop2UInt16] != 0)
              {
                /* This function ID is a valid one in this auto-scroll, execute it. */
                FunctionNumber = get_function_number(ActiveConfig0.AutoScroll[Loop1UInt16].FunctionId[Loop2UInt16], String);
                if (FunctionNumber != MAX_FUNCTIONS)
                {
                  if (DebugBitMask & DEBUG_SCROLL) log_printf(__LINE__, __func__, "Executing item  %2u   Function ID: %3u   Function number: %3u   FunctionName: %s   pointer: %p\n", Loop2UInt16, ActiveConfig0.AutoScroll[Loop1UInt16].FunctionId[Loop2UInt16], FunctionNumber, Function[FunctionNumber].Name, Function[FunctionNumber].Pointer);
                  Function[FunctionNumber].Pointer();
                }
              }
            }

            /* Reset this function in the bitmask once this cycle is over. */
            AutoScrollBitMask &= ~(0x01 << Loop1UInt16);
          }
        }
      }



      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                  Check if we are in the first loop cycle.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
#ifdef NTP_SUPPORT
      if ((is_nil_time(StructNTP.UpdateTime)) && (StructWiFi.FlagHealth))
      {
        log_printf(__LINE__, __func__, "First loop cycle for ntp_check()\n");
        ntp_check();
      }
#endif  // NTP_SUPPORT

      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting 1-second time step.\n\n");
    }





    /* ========================================================================================================================================================= *\
                                  2-seconds time step and schedule mark. Put here functions that we want to execute every 2 seconds.
    \* ========================================================================================================================================================= */
    if ((CurrentTimer - LastTimer2Sec) >= 2000000ll)
    {
      LastTimer2Sec = CurrentTimer;
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 2-seconds time step.\n");

      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting 2-seconds time step.\n");
    }





    /* ========================================================================================================================================================= *\
                                    5-seconds time step and schedule mark. Put here functions that we want to execute every 5 seconds.
    \* ========================================================================================================================================================= */
    if ((CurrentTimer - LastTimer5Sec) >= 5000000ll)
    {
      LastTimer5Sec = CurrentTimer;
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 5-seconds time step.\n");
      // if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting 5-seconds time step.\n");
    }





    /* ========================================================================================================================================================= *\
                                  10-seconds time step and schedule mark. Put here functions that we want to execute every 10 seconds.
    \* ========================================================================================================================================================= */
    if ((CurrentTimer - LastTimer10Sec) >= 10000000ll)
    {
      LastTimer10Sec = CurrentTimer;
      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 10-seconds time step.\n");
      // log_printf(__LINE__, __func__, "Core 0: 10-seconds heartbeat.\n");

#ifdef DEVELOPER_VERSION
      if (stdio_usb_connected())
      {
        // log_printf(__LINE__, __func__, "10-seconds heartbeat... Absolute time reference: %6llu   WatchDogCore0: %4u\n", (time_us_64() / 1000000ll), WatchDogCore0);

        if (DebugBitMask & DEBUG_REMINDER)
        {
          util_uint64_to_binary_string(Reminder1BitMask, MAX_REMINDERS1, String);
          log_printf(__LINE__, __func__, "Reminder1BitMask:       0x%10.10llX   [%s]\n", Reminder1BitMask, String);
        }


        if (DebugBitMask & DEBUG_SCROLL)
        {
          UINT8 Dum1UInt8;

          Dum1UInt8 = get_scroll_number();
          // log_printf(__LINE__, __func__, "Received %u from get_scroll_number)\n", Dum1UInt8);
          if (Dum1UInt8 != MAX_ACTIVE_SCROLL)
          {
            log_printf(__LINE__, __func__, "Total length of scrolling message: %4u (active scroll number: %u     window: %s)\n", strlen(ActiveScroll[Dum1UInt8]->Message), Dum1UInt8, Window[ActiveScroll[Dum1UInt8]->Owner].Name);
            sleep_ms(20);  // prevent communication override.
            log_printf(__LINE__, __func__, "Current pointer in ASCII message:  %4u (remaining characters to be scrolled: %u)\n", ActiveScroll[Dum1UInt8]->AsciiBufferPointer, strlen(&ActiveScroll[Dum1UInt8]->Message[ActiveScroll[Dum1UInt8]->AsciiBufferPointer]));
            sleep_ms(20);  // prevent communication override.
            log_printf(__LINE__, __func__, "Text remaining to be scrolled:\n");
            sleep_ms(20);  // prevent communication override.
            log_printf(__LINE__, __func__, "---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------\n");
            sleep_ms(20);  // prevent communication override.
            // log_printf(__LINE__, __func__, "%s\n", ActiveScroll[Dum1UInt8]->Message);  // display complete message.
            log_printf(__LINE__, __func__, "%s\n", &ActiveScroll[Dum1UInt8]->Message[ActiveScroll[Dum1UInt8]->AsciiBufferPointer]);  // display what remains to be scrolled.
            sleep_ms(20);  // prevent communication override.
            log_printf(__LINE__, __func__, "---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------\n\n\n\n");
            sleep_ms(20);  // prevent communication override.
          }
        }
      }
#endif  // DEVELOPER_VERSION
      // mem_display();
      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting 10-seconds time step.\n\n");
    }





    /* ========================================================================================================================================================= *\
                                15-seconds time step and schedule mark. Put here functions that we want to execute every 15 seconds.
    \* ========================================================================================================================================================= */
    if ((LastTimer15Sec == 0ll) || ((CurrentTimer - LastTimer15Sec) >= 15000000ll))
    {
      LastTimer15Sec = CurrentTimer;

      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 15-seconds time step...\n");


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                 Check Wi-Fi (network) connection health.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      ReturnCode = wifi_check_connection();
      if (ReturnCode)
      {
        if (FlagLocalDebug)
        {
          log_printf(__LINE__, __func__, "Problem with Wi-Fi connection...\n");
        }
      }

      /* If wifi_init() was a little long, watchdog may have turned On a few white LEDs. Restore original color. */
      if (LastTimer15Sec == 0ll)
      {
        refresh_matrix_colors();
      }



#ifdef MQTT_SUPPORT
      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                         Check MQTT connection health.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if (StructWiFi.FlagHealth)
      {
        ReturnCode = mqtt_check_connection(StructWiFi.FlagHealth);
        switch (ReturnCode)
        {
          case (0):
            // if (FlagLocalDebug)
            // {
            //   log_printf(__LINE__, __func__, "MQTT connection OK.\n");
            // }
          break;

          case (1):
            if (StructMQTT.FlagStartupOver)
              log_printf(__LINE__, __func__, "MQTT connection just restored, proceed with mqtt_initialization() and mqtt_device_subscribe().\n");
            else
              log_printf(__LINE__, __func__, "MQTT connection has just been established, proceed with mqtt_initialization() and mqtt_device_subscribe().\n");
            mqtt_initialization();
            mqtt_device_subscribe();
          break;

          default:
            log_printf(__LINE__, __func__, "Problem with MQTT connection.\n");
          break;
        }
      }
#endif  // MQTT_SUPPORT
    }





    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                30-seconds time step and schedule mark. Put here functions that we want to execute every 30 seconds.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((CurrentTimer - LastTimer30Sec) >= 30000000ll)
    {
      LastTimer30Sec = CurrentTimer;
      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 30-seconds time step.\n");

      if (DebugBitMask & DEBUG_ALARM)
      {
        /* Display alarms bitmask. */
        util_uint64_to_binary_string((UINT64)AlarmBitMask, MAX_ALARMS, String);
        log_printf(__LINE__, __func__, "AlarmBitMask: [%s] (0x%4.4X)\n", String, AlarmBitMask);

        /* Display alarm current count-down value for every alarm. */
        for (Loop1UInt16 = 0; Loop1UInt16 < MAX_ALARMS; ++Loop1UInt16)
        {
          log_printf(__LINE__, __func__, "ActiveAlarm[%u].CountDown: %4u\n", Loop1UInt16, ActiveAlarm[Loop1UInt16].CountDown);
        }
      }


      if (DebugBitMask & DEBUG_EVENT)
      {
        /* Display triggered events bitmask. */
        util_uint64_to_binary_string((UINT64)EventBitMask, MAX_EVENTS, String);
        log_printf(__LINE__, __func__, "EventBitMask: [%s] (0x%16.16X)\n", String, EventBitMask);

        /* Display Event data for triggered events. */
        for (Loop1UInt16 = 0; Loop1UInt16 < MAX_EVENTS; ++Loop1UInt16)
        {
          if (Loop1UInt16 & (1 << Loop1UInt16))
          {
            log_printf(__LINE__, __func__, "Triggered event Number %u\n", Loop1UInt16);
            log_printf(__LINE__, __func__, "Event day:    %u\n",    ActiveConfig0.Event[Loop1UInt16].Day);
            log_printf(__LINE__, __func__, "Event month:  %u\n",    ActiveConfig0.Event[Loop1UInt16].Month);
            log_printf(__LINE__, __func__, "Event jingle: %u\n",    ActiveConfig0.Event[Loop1UInt16].Jingle);
            log_printf(__LINE__, __func__, "Event message: <%s>\n", ActiveConfig0.Event[Loop1UInt16].Message);
          }
        }
      }
      // log_printf(__LINE__, __func__, "Core 0: 30-seconds heartbeat.\n");

      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Exiting 30-seconds time step.\n");
    }






    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                    1-minute time step and schedule mark. Put here functions that we want to execute every minute.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((CurrentTimer - LastTimer1Min) >= 60000000ll)
    {
      LastTimer1Min = CurrentTimer;
      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 1-minute time step.\n");
      // log_printf(__LINE__, __func__, "Time steps loop: 1-minute heartbeat.\n");

      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                        Refresh inside temperature.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      ds3231_get_temperature(&DegreeC, &DegreeF);

      /* Indoor temperature handling. */
      Alternate[ALT_POS_INS_TEMP].StartLine = 202;
      Alternate[ALT_POS_INS_TEMP].Type      = ALT_DISPLAY;
      snprintf(Alternate[ALT_POS_INS_TEMP].Text, sizeof(Alternate[ALT_POS_INS_TEMP].Text), "%s: %.2f%cC", $INSIDE, DegreeC, 0x80);
      Alternate[ALT_POS_INS_TEMP].Duration  = 660000l;  // (in msec) 11 minutes validity.
      Alternate[ALT_POS_INS_TEMP].SeedTime  = CurrentTimer;


// This section is planned to implement remainders and it is not currently implemented.
#if 0
#ifdef DEVELOPER_VERSION
      if (stdio_usb_connected())
      {
        /* log_printf(__LINE__, __func__, " 1-minute heartbeat: Absolute time reference %8llu min\n", time_us_64() / 60000000ll); */


        if (DebugBitMask & DEBUG_REMINDER)
        {
          util_uint64_to_binary_string(Reminder1BitMask, MAX_REMINDERS1, String);
          log_printf(__LINE__, __func__, "Reminder1BitMask:                    0x%10.10llX   [%s]\n", Reminder1BitMask, String);
        }


#ifdef NTP_SUPPORT
        if (DebugBitMask & DEBUG_NTP)
        {
          INT64 DeltaTime;

          UINT64 Dum1UInt64;

          DeltaTime = (absolute_time_diff_us(get_absolute_time(), StructNTP.UpdateTime) / 1000000ll);
          Dum1UInt64 = get_absolute_time();
          if (DebugBitMask & DEBUG_NTP)
          {
            log_printf(__LINE__, __func__, "Absolute time:  %12llu usec   (%llu sec)\n", Dum1UInt64, Dum1UInt64 / 1000000);
            log_printf(__LINE__, __func__, "UpdateTime:     %12llu usec   (%llu sec)\n", StructNTP.UpdateTime, StructNTP.UpdateTime / 1000000);
            if (DeltaTime >= 0)
            {
              log_printf(__LINE__, __func__, "Time remaining: %12lld sec   (%lld minutes)\n\n", DeltaTime, DeltaTime / 60);
            }
            else
            {
              log_printf(__LINE__, __func__, "Time over:      %12lld sec\n", llabs(DeltaTime));
              log_printf(__LINE__, __func__, "(NTP will update on next 10-min heartbeat, in %llf minutes)\n\n", (600000000ll - (CurrentTimer - LastTimer10Min)) / 60000000.0);
            }
          }
        }
#endif  // NTP_SUPPORT
      }
#endif  // DEVELOPER_VERSION
#endif  // 0
    }





    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                  10-minutes time step and schedule mark. Put here functions that we want to execute every 10 minutes.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((LastTimer10Min == 0ll) || ((CurrentTimer - LastTimer10Min) >= 600000000ll))
    {
      LastTimer10Min = CurrentTimer;
      if (FlagLocalDebug)
      {
        log_printf(__LINE__, __func__, "Entering 10-minutes time step.\n");
      }

#ifdef DEVELOPER_VERSION
      if (stdio_usb_connected())
      {
        if (LastTimer10Min < 10000000ll)
          log_printf(__LINE__, __func__, "10-minute time step: Currently during initial startup sequence: %8llu sec\n", CurrentTimer / 1000000ll);
        else
          log_printf(__LINE__, __func__, "10-minute time step: Absolute time reference (in minutes):  -------> %8llu min\n", CurrentTimer / 60000000ll);
      }
#endif  // DEVELOPER_VERSION



#ifdef NTP_SUPPORT
      ntp_check();
#endif  // NTP_SUPPORT
    }





    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                      1-hour time step and schedule mark. Put here functions that we want to execute every hour.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((LastTimer60Min == 0ll) || ((CurrentTimer - LastTimer60Min) >= 3600000000ll))
    {
      LastTimer60Min = CurrentTimer;
      if (FlagLocalDebug) log_printf(__LINE__, __func__, "Entering 1-hour time step.\n");
      log_printf(__LINE__, __func__, "Core 0: 1-hour heartbeat.\n");
      

#if defined(MQTT_SUPPORT) && defined(MQTT_TIME_SERVER)
      /* Last time broadcast is more than 24 hours ago. */
      if ((CurrentTimer - LastBroadcastTime) >= 86400000000ll)
      {
        mqtt_broadcast_time();
      }
#endif  // MQTT_TIME_SERVER
    }

    sleep_ms(1);  // slow down main system loop.
  }

  return;
}





/* $PAGE */
/* $TITLE=terminal_handling_loop() */
/* ============================================================================================================================================================= *\
                                                               Endless loop to be run on one of Pico's core.
                                                               This core LED "I'm alive indicators" is cyan.
\* ============================================================================================================================================================= */
void terminal_handling_loop()
{
  UCHAR String[32];

  UINT8 LastAltNumber;  // remove this one when integrated in 50msec callback.
  UINT8 LastDisplayedSecond;

  UINT16 Loop1UInt16;

  UINT64 CurrentTimer;
  UINT64 LastTerminalMenu;
  UINT64 LastTimer1Sec;
  UINT64 LastTimer15Sec;
  UINT64 LastTimer30Sec;
  UINT64 WatchdogCoreTimer;

  // datetime_t DateTime;


  log_printf(__LINE__, __func__, "Entering terminal handling endless loop on core %u (cyan indicator).\n", get_core_num());

  if (DebugBitMask & DEBUG_STARTUP)
  {
    log_printf(__LINE__, __func__, "Before entering core %u endless loop.\n", get_core_num());
    sleep_ms(1000);  // slow down startup sequence for debug purposes.
  }


  CurrentTimer        = time_us_64();
  LastTerminalMenu    = 0ll;
  LastTimer1Sec       = CurrentTimer;
  LastTimer15Sec      = CurrentTimer;
  LastTimer30Sec      = CurrentTimer;
  WatchdogCoreTimer   = CurrentTimer;
  LastAltNumber       = MAX_ALTERNATES - 1;
  LastDisplayedSecond = 61;  // force a change in current second reading on first pass.

  while (1)
  {
    CurrentTimer = time_us_64();


    /* If user pressed a key other than <ESC> on external terminal, branch to term_menu() function. */
    /* NOTE: Endless loop is suspended while user navigate the terminal menu / submenus. User must check "watchdog white LEDs" on RGB matrix to prevent a reboot. */
    input_string(String, 1, 10l);  // wait for a keystroke to display main terminal menu.
    if (String[0] != 0x1B)
    {
      log_printf(__LINE__, __func__, "Switching to terminal menu...\n");
      FlagTerminalOpen = FLAG_ON;       // indicate that user is currently navigating menus and submenus.
      term_menu();
      LastTerminalMenu = time_us_64();  // indicate time when menus and submenus have been closed.
      FlagTerminalOpen = FLAG_OFF;      // user is done navigating menus and submenus.
    }



#ifdef WATCHDOG_SUPPORT
    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                           Watchdog timer.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((CurrentTimer - WatchdogCoreTimer) > 999900ll)
    {
      WatchdogCoreTimer = CurrentTimer;

      /* NOTE: Watchdog timer has been set slightly faster than one second. This is to make sure that the WatchDogCore1 variable
               will have been incremented when the callback tests its value and prevent a miss. In fact, one miss is not really
               important and everything would return to normal within the next few cycles. The idea of making it a little faster
               is to prevent a white LED that would otherwise be turned On for a few seconds on the RGB display if there is a miss. */
      ++WatchDogCore1;
      if (DebugBitMask & DEBUG_WATCHDOG) log_printf(__LINE__, __func__, "                       Core%u count: %5u\n", get_core_num(), WatchDogCore1);
    }
#endif  // WATCHDOG_SUPPORT





    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                        Check if real-time clock IC has changed the seconds (updated by the one-second callback).
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if (CurrentTime.Second != LastDisplayedSecond)
    {
      LastDisplayedSecond = CurrentTime.Second;

      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                     Manage endless loop pixel indicator pilots for "core is alive".
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if ((WinTop == WIN_DAY) || (WinTop == WIN_LIGHT))
      {
        /* Blinking pixels to indicate that endless loop in this core context is still running. */
        if (((CurrentTime.Second & 0x07) == 0x00) || ((CurrentTime.Second & 0x07) == 0x04))
        {
          pilot_set_color(CYAN);  // this core color = CYAN.
          pilot_toggle(ShadowBuffer);
          RGB_matrix_set_row_mask(&DisplayMatrix.RowMask, 0, 0);
          DisplayMatrix.FlagUpdate = FLAG_ON;
        }
      }
    }





    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                           1-second time step. Put here functions that we want to execute every second.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((CurrentTimer - LastTimer1Sec) > 1000000ll)
    {
      LastTimer1Sec = CurrentTimer;


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                          Keep track of time spent in the target callback routine.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if (is_nil_time(AbsoluteExitTime) == false)
      {
        CallbackDuration[CallbackDurationPointer] = absolute_time_diff_us(AbsoluteEntryTime, AbsoluteExitTime);
        // TargetTime[CallbackDurationPointer] = (DateTime.min << 8) + DateTime.sec;
        ++CallbackDurationPointer;
        if (CallbackDurationPointer >= MAX_CALLBACK_DURATION_UNITS) CallbackDurationPointer = 0;  // rollback to beginning.
        AbsoluteEntryTime = nil_time;
        AbsoluteExitTime  = nil_time;
      }


#ifdef ALTERNATE_SUPPORT
      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                        Handling of Alternate display.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if (Window[WinMid].CountDown)
      {
        /* WinMid window has an active Alternate count-down. */
        if (Window[WinMid].CountDown > 1000)
        {
          /* More than 1 sec (1000 msec) remains for current Alternate display. */
          Window[WinMid].CountDown -= 1000;
        }
        else
        {
          Window[WinMid].CountDown = 0;
          win_close(WinMid, FLAG_OFF);
          LastAlternateEnd = CurrentTimer;
          RGB_matrix_set_row_mask(&DisplayMatrix.RowMask, 9, 15);
          DisplayMatrix.FlagUpdate = FLAG_ON;
        }
      }
      else
      {
        UINT8 TotalActiveAlt = 0;
        if (CurrentTimer > (LastAlternateEnd + 5000000ll))
        {
          /* Last Alternate display was closed more than 5 seconds old, display next Alternate if there is one. */
          Loop1UInt16 = LastAltNumber + 1;
          if (Loop1UInt16 >= MAX_ALTERNATES) Loop1UInt16 = 0;  // if reaching out-of-bound, revert to 0.
          do
          {
            if (Alternate[Loop1UInt16].Type)
            {
              ++TotalActiveAlt;
              /* This Alternate is active, check if it must be declared obsolete. */
              if (CurrentTimer > (Alternate[Loop1UInt16].SeedTime + (Alternate[Loop1UInt16].Duration * 1000)))
              {
                /* This Alternate is obsolete, reset it. */
                ++Loop1UInt16;
                if (Loop1UInt16 == LastAltNumber) break;
                if (Loop1UInt16 >= MAX_ALTERNATES) Loop1UInt16 = 0;
                continue;  // proceed with checking next Alternate.
              }
              else
              {
                /* This Alternate is not obsolete, display it. */
                win_open(WIN_LINE2, FLAG_OFF, FLAG_OFF);
                win_printf(WIN_LINE2, 202, 99, FONT_5x7, "%s", Alternate[Loop1UInt16].Text);
                Window[WIN_LINE2].CountDown = 3000;  // initialize 3 seconds countdown.
                LastAltNumber = Loop1UInt16;
                break;
              }
            }
            else
            {
              ++Loop1UInt16;
              if (Loop1UInt16 == LastAltNumber) break;
              if (Loop1UInt16 >= MAX_ALTERNATES) Loop1UInt16 = 0;
              continue;  // proceed with checking next Alternate.
            }
          } while (Loop1UInt16 != LastAltNumber);
          if (!TotalActiveAlt) LastAltNumber = MAX_ALTERNATES - 1;
        }
        else
        {
        }
      }
#endif  // ALTERNATE_SUPPORT
    }





    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                 15-second time step and schedule mark. Put here functions that we want to execute every 15 seconds.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((CurrentTimer - LastTimer15Sec) > 15000000ll)
    {
      LastTimer15Sec = CurrentTimer;
    }





    /* --------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                  30-second time step and schedule mark. Put here functions that we want to execute every 30 seconds.
    \* --------------------------------------------------------------------------------------------------------------------------------------------------------- */
    if ((CurrentTimer - LastTimer30Sec) > 30000000ll)
    {
      LastTimer30Sec = CurrentTimer;


      /* ------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                              Check if flash configuration has been changed.
          NOTE: Do not check configuration while user navigates configuration since he may be currently setting up parameters (and so, modifying configuration).
             Also, wait 15 seconds after user leave terminal menus before checking configuration since user may return inside menus to change more parameters.
      \* ------------------------------------------------------------------------------------------------------------------------------------------------------- */
      if ((FlagTerminalOpen == FLAG_OFF) && ((CurrentTimer - LastTerminalMenu) > 15000000ll))
      {
        if (DebugBitMask & DEBUG_FLASH)
        {
          log_printf(__LINE__, __func__, "Validating current active (RAM) configurations with flash (saved) ones.\n");
        }
        /* Check if RGB Matrix active configuration has been changed from the one read from flash. */
        flash_check_config(0);  // configuration 0 (main configuration data).
        flash_check_config(1);  // configuration 1 (reminders).
      }
    }

	  /* Slow down system loop to keep Pico cool, but not too much to prevent modifying the "I'm alive" cyan indicators timing on RGB matrix. */
    sleep_ms(50);
  }

	return;
}




/* $PAGE */
/* $TITLE=debug_pixel() */
/* ============================================================================================================================================================= *\
                                                                Turn On a pixel for debug purpose.
                                                     See an example of its use during the start-up sequence.
                             This could be used to test some behavior when there must not be a terminal connected to the system.
\* ============================================================================================================================================================= */
void debug_pixel(UINT8 RowNumber, UINT8 ColumnNumber, UINT8 Color)
{
  RGB_matrix_set_color(RowNumber, ColumnNumber, RowNumber, ColumnNumber, Color);
  RGB_matrix_set_pixel(FrameBuffer, RowNumber, ColumnNumber, RowNumber, ColumnNumber);

  return;
}





/* $PAGE */
/* $TITLE=display_alarm() */
/* ============================================================================================================================================================= *\
                                                                Display specified alarm number.
\* ============================================================================================================================================================= */
void display_alarm(UINT8 AlarmNumber)
{
  UCHAR DayMask[11];
  UCHAR String[61];

  UINT8 Loop1UInt8;


  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Entering display_alarm()\n");

  /* Prepare a string indicating if this alarm is On or Off. */
  if (ActiveConfig0.Alarm[AlarmNumber].FlagStatus)
    snprintf(String, sizeof(String), "<<<<< ON >>>>>");
  else
    String[0] = 0x00;

  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "------------------------------ Alarm number %u ------------------------------\n", AlarmNumber + 1);
  log_printf(__LINE__, __func__, "Alarm[%2.2u].Status:             %2.2u     (00 = Off   01 = On)     %s\n",        AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].FlagStatus, String);
  log_printf(__LINE__, __func__, "Alarm[%2.2u].Hour:               %2.2u\n",                                        AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].Hour);
  log_printf(__LINE__, __func__, "Alarm[%2.2u].Minute:             %2.2u\n",                                        AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].Minute);


  /* Display target days-of-week. */
  util_uint64_to_binary_string(ActiveConfig0.Alarm[AlarmNumber].DayMask, 8, DayMask);
  snprintf(String, sizeof(String), "Alarm[%2.2u].DayMask:      %s        (0x%2.2X) ", AlarmNumber + 1, DayMask, ActiveConfig0.Alarm[AlarmNumber].DayMask);

  /* Display short name of all days-of-week selected for this alarms (those selected in the bit mask). */
  for (Loop1UInt8 = 0; Loop1UInt8 < 7; ++Loop1UInt8)
  {
    if (ActiveConfig0.Alarm[AlarmNumber].DayMask & (1 << Loop1UInt8))
      snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "%s ", ShortDay[Loop1UInt8]);
  }
  log_printf(__LINE__, __func__, "%s\n", String);


  log_printf(__LINE__, __func__, "Alarm[%2.2u].NumberOfBeeps:     %3u\n",                           AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].NumberOfBeeps);
  log_printf(__LINE__, __func__, "Alarm[%2.2u].BeepMSec:          %3u msec\n",                      AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].BeepMSec);
  log_printf(__LINE__, __func__, "Alarm[%2.2u].RepeatPeriod:     %4u seconds\n",                    AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].RepeatPeriod);
  log_printf(__LINE__, __func__, "Alarm[%2.2u].RingDuration:     %4u seconds (global ring time)\n", AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].RingDuration);


  /* Display message for this alarm. */
  log_printf(__LINE__, __func__, "Alarm[%2.2u].Message:               <", AlarmNumber + 1);
  /* Make sure we display only printable characters in case flash has not been initalized properly for some reason. */
  for (Loop1UInt8 = 0; Loop1UInt8 < sizeof(ActiveConfig0.Alarm[AlarmNumber].Message); ++Loop1UInt8)
  {
    if  (ActiveConfig0.Alarm[AlarmNumber].Message[Loop1UInt8] == 0x00) break;  // get out of <for> loop when reaching end-of-string.
    if ((ActiveConfig0.Alarm[AlarmNumber].Message[Loop1UInt8] >= 0x20) && (ActiveConfig0.Alarm[AlarmNumber].Message[Loop1UInt8] <= 0x7E))
      printf("%c", ActiveConfig0.Alarm[AlarmNumber].Message[Loop1UInt8]);
    else
      printf("?");
  }
  printf(">\n");


  /* Display number of scrolls at each ring-time. */
  log_printf(__LINE__, __func__, "Alarm[%2.2u].NumberOfScrolls:   %3u\n\n", AlarmNumber + 1, ActiveConfig0.Alarm[AlarmNumber].NumberOfScrolls);
  log_printf(__LINE__, __func__, Separator);


  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting display_alarm()\n");

  return;
}





/* $PAGE */
/* $TITLE=display_alternate() */
/* ============================================================================================================================================================= *\
                                                           Display Alternate structures current status.
\* ============================================================================================================================================================= */
void display_alternate(void)
{
  UINT8 Loop1UInt8;

  UINT64 CurrentTimer;


  CurrentTimer = time_us_64();

  // log_printf(__LINE__, __func__, " \n\n\n");
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "<120>Alternate status\n");
  log_printf(__LINE__, __func__, Separator);

  log_printf(__LINE__, __func__, "Current timer: %llu\n\n", CurrentTimer);


  for (Loop1UInt8 = 0; Loop1UInt8 < MAX_ALTERNATES; ++Loop1UInt8)
  {
    log_printf(__LINE__, __func__, "Number      %2.2u\n", Loop1UInt8);
    log_printf(__LINE__, __func__, "Start line: %u\n",     Alternate[Loop1UInt8].StartLine);
    log_printf(__LINE__, __func__, "Type:       %u\n",     Alternate[Loop1UInt8].Type);
    log_printf(__LINE__, __func__, "Text:       <%s>\n",   Alternate[Loop1UInt8].Text);
    log_printf(__LINE__, __func__, "Duration:   %lu\n",    Alternate[Loop1UInt8].Duration);
    log_printf(__LINE__, __func__, "Seed time:  %llu  (%llu seconds ago)\n\n", Alternate[Loop1UInt8].SeedTime, ((CurrentTimer / 1000000) - (Alternate[Loop1UInt8].SeedTime / 1000000)));
  }
  log_printf(__LINE__, __func__, Separator);

  return;
}





/* $PAGE */
/* $TITLE=display_ambient_light_value() */
/* ============================================================================================================================================================= *\
                                                          Display instantaneous and hysteresis light values.
\* ============================================================================================================================================================= */
void display_ambient_light_value(void)
{
  UINT8 Loop1UInt16;

  UINT16 CurrentLightValue;
  UINT16 Dum1UInt16;
  UINT16 HighestLight;
  UINT16 LightRange;
  UINT16 LowestLight;
  UINT16 PwmLoLimit;
  UINT16 PwmHiLimit;
  UINT16 PwmRange;


  UINT64 TotalValues;


  /* Initialisations. */
  LightRange = LIGHT_HI_LIMIT - LIGHT_LO_LIMIT;
  PwmLoLimit = PWM_LO_LIMIT;
  PwmHiLimit = PWM_HI_LIMIT;
  PwmRange   = PWM_HI_LIMIT - PWM_LO_LIMIT;
  CurrentLightValue = get_light_value();


  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "<120>Brightness and ambient light information\n");
  log_printf(__LINE__, __func__, Separator);

  if (ActiveConfig0.FlagAutoBrightness)
    log_printf(__LINE__, __func__, "Auto brightness is:                      On\n");
  else
    log_printf(__LINE__, __func__, "Auto brightness is:                     Off\n");

  /* Check if "Service light" is On or Off. */
  if (ServiceLightTimer != 0) log_printf(__LINE__, __func__, "Service light remaining time:       %4u sec\n", ServiceLightTimer);

  log_printf(__LINE__, __func__, "Brightness absolute limits:    Low:    %4u     High: %4u     Range: %4u\n", BRIGHTNESS_LO_LIMIT, BRIGHTNESS_HI_LIMIT, BRIGHTNESS_HI_LIMIT - BRIGHTNESS_LO_LIMIT);
  log_printf(__LINE__, __func__, "Brightness limit settings:     Low:    %4u     High: %4u     Range: %4u\n", ActiveConfig0.BrightnessLoLimit, ActiveConfig0.BrightnessHiLimit, ActiveConfig0.BrightnessHiLimit - ActiveConfig0.BrightnessLoLimit);
  log_printf(__LINE__, __func__, "Brightness steady setting:             %4u\n",                              ActiveConfig0.BrightnessLevel);
  log_printf(__LINE__, __func__, "Light sensor limits:           Low:    %4u     High: %4u     Range: %4u\n", LIGHT_LO_LIMIT, LIGHT_HI_LIMIT, LightRange);
  log_printf(__LINE__, __func__, "Current ambient light value:           %4u\n", CurrentLightValue);

  if (ActiveConfig0.FlagAutoBrightness)
  {
    log_printf(__LINE__, __func__, "Average ambient light (hysteresis):    %4u     (last %u seconds)\n", AverageAmbientLight, BRIGHTNESS_HYSTERESIS_SECONDS);
    log_printf(__LINE__, __func__, "Average ambient light is above low limit by: %4d units\n", (AverageAmbientLight - LIGHT_LO_LIMIT));
  }
  else
    log_printf(__LINE__, __func__, "Average ambient light:                  N/A     (auto-brightness is turned Off)\n");

  log_printf(__LINE__, __func__, "Current brightness level:              %4u\n",     BrightnessLevel);
  log_printf(__LINE__, __func__, "PWM range / Light range:             %4.4f\n",     ((float)PwmRange / LightRange));
  log_printf(__LINE__, __func__, "Ratio light / PWM:                     %4u\n",     (UINT16)((AverageAmbientLight - LIGHT_LO_LIMIT) * ((float)PwmRange / LightRange)));
  log_printf(__LINE__, __func__, "PWM limit settings:            Low:    %4u     High: %4u     Range: %4u\n", PwmLoLimit, PwmHiLimit, PwmRange);
  log_printf(__LINE__, __func__, "PWM level:                             %4u\n",     Pwm[PWM_ID_BRIGHTNESS].Level);
  log_printf(__LINE__, __func__, "PWM high limit - PWM level:            %4u\n", PWM_HI_LIMIT - Pwm[PWM_ID_BRIGHTNESS].Level);
  log_printf(__LINE__, __func__, Separator);

  TotalValues  = 0ll;
  HighestLight = 0;
  LowestLight  = 0;

  log_printf(__LINE__, __func__, "<120>Ambient light values for the last %u seconds (hysteresis):\n", BRIGHTNESS_HYSTERESIS_SECONDS);
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, " ");
  for (Loop1UInt16 = 0; Loop1UInt16 < BRIGHTNESS_HYSTERESIS_SECONDS; ++Loop1UInt16)
  {
    printf("[%3u]- %4u  ", Loop1UInt16 + 1, AmbientLight[Loop1UInt16]);
    if (((Loop1UInt16 + 1) % 10) == 0) log_printf(__LINE__, __func__, " \n");
    if (AmbientLight[Loop1UInt16] > HighestLight) HighestLight = AmbientLight[Loop1UInt16];
    if ((LowestLight == 0) || (AmbientLight[Loop1UInt16] < LowestLight)) LowestLight = AmbientLight[Loop1UInt16];
    TotalValues += AmbientLight[Loop1UInt16];
  }
  log_printf(__LINE__, __func__, Separator);
  Dum1UInt16 = (UINT16)(TotalValues / BRIGHTNESS_HYSTERESIS_SECONDS);
  printf("Sum of all light readings: %llu\n\n", TotalValues);
  printf("During last hysteresis period:\n");
  printf("Lowest  light value: %u\n",     LowestLight);
  printf("Average light value: %u\n",     Dum1UInt16);
  printf("Highest light value: %u\n\n\n", HighestLight);
  log_printf(__LINE__, __func__, Separator);

  return;
}





/* $PAGE */
/* $TITLE=display_auto_scroll() */
/* ============================================================================================================================================================= *\
                                                            Display auto-scrolls defined in the system.
\* ============================================================================================================================================================= */
void display_auto_scroll(UINT8 AutoScrollNumber)
{
  UCHAR String[65];

  UINT8 Loop1UInt8;

  UINT16 FunctionNumber;


  log_printf(__LINE__, __func__, Separator1);
  log_printf(__LINE__, __func__, "Auto-scroll number %u.\n",     AutoScrollNumber + 1);
  log_printf(__LINE__, __func__, "Scroll period: %u minutes.\n", ActiveConfig0.AutoScroll[AutoScrollNumber].Period);
  log_printf(__LINE__, __func__, "Items being scrolled:\n");
  log_printf(__LINE__, __func__, " Item   Function    Function           Function\n");
  log_printf(__LINE__, __func__, "Number   Number        ID                Name\n");
  log_printf(__LINE__, __func__, "------  --------    --------   -------------------------\n");


  /* Display all items to be scrolled with this auto-scroll. */
  for (Loop1UInt8 = 0; Loop1UInt8 < MAX_ITEMS; ++Loop1UInt8)
  {
    /* If this item is a valid FunctionNumber, display the corresponding FunctionId. */
    if (ActiveConfig0.AutoScroll[AutoScrollNumber].FunctionId[Loop1UInt8] == 0)
    {
      log_printf(__LINE__, __func__, "  %2u       ---         %3u      -----------------------\n", Loop1UInt8 + 1, ActiveConfig0.AutoScroll[AutoScrollNumber].FunctionId[Loop1UInt8]);
    }
    else
    {
      /* Display FunctionNumber. */
      FunctionNumber = get_function_number(ActiveConfig0.AutoScroll[AutoScrollNumber].FunctionId[Loop1UInt8], String);

      if (FunctionNumber == MAX_FUNCTIONS)
      {
        log_printf(__LINE__, __func__, "  %2u       ---         %3u      -----------------------\n", Loop1UInt8 + 1, ActiveConfig0.AutoScroll[AutoScrollNumber].FunctionId[Loop1UInt8]);
      }
      else
      {
        log_printf(__LINE__, __func__, "  %2u      (%3u)        %3u      %s\n", Loop1UInt8 + 1, FunctionNumber, ActiveConfig0.AutoScroll[AutoScrollNumber].FunctionId[Loop1UInt8], String);
      }
    }
  }
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, " \n");
  log_printf(__LINE__, __func__, " \n");

  return;
}





/* $PAGE */
/* $TITLE=display_event() */
/* ============================================================================================================================================================= *\
                                                                Display specified event number.
\* ============================================================================================================================================================= */
void display_event(UINT8 EventNumber)
{
  UINT8 Loop1UInt8;


  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Entering display_event()\n");

  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "------------------------- Event number %u -------------------------\n", EventNumber + 1);
  log_printf(__LINE__, __func__, "Event[%2.2u].Day:        %2.2u\n",      EventNumber + 1, ActiveConfig0.Event[EventNumber].Day);
  log_printf(__LINE__, __func__, "Event[%2.2u].Month:      %2.2u (%s)\n", EventNumber + 1, ActiveConfig0.Event[EventNumber].Month, ShortMonth[ActiveConfig0.Event[EventNumber].Month]);
  log_printf(__LINE__, __func__, "Event[%2.2u].Jingle:     %2.2u\n",      EventNumber + 1, ActiveConfig0.Event[EventNumber].Jingle);



  /* Display message for this event. */
  log_printf(__LINE__, __func__, "Event[%2.2u].Message:    <", EventNumber + 1);
  for (Loop1UInt8 = 0; Loop1UInt8 < sizeof(ActiveConfig0.Event[EventNumber].Message); ++Loop1UInt8)
  {
    if  (ActiveConfig0.Event[EventNumber].Message[Loop1UInt8] == 0x00) break;  // get out of <for> loop when reaching end-of-string.
    if ((ActiveConfig0.Event[EventNumber].Message[Loop1UInt8] >= 0x20) && (ActiveConfig0.Event[EventNumber].Message[Loop1UInt8] <= 0x7E))
      printf("%c", ActiveConfig0.Event[EventNumber].Message[Loop1UInt8]);
    else
      printf("?");
  }
  printf(">\n\n");
  log_printf(__LINE__, __func__, Separator);

  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting display_event()\n");

  return;
}





