/* $PAGE */
/* $TITLE=function_auto_scroll() */
/* ============================================================================================================================================================= *\
                                                            Function to display auto-scrolls info.
\* ============================================================================================================================================================= */
void function_auto_scroll(void)
{
  UCHAR FunctionName[31];
  UCHAR String[512];

  UINT8 Loop1UInt8;
  UINT8 Loop2UInt8;

  UINT16 FunctionNumber;


  for (Loop1UInt8 = 0; Loop1UInt8 < MAX_AUTO_SCROLLS; ++Loop1UInt8)
  {
    /* Check if this auto-scroll is active. */
    if (ActiveConfig0.AutoScroll[Loop1UInt8].Period != 0)
    {
      snprintf(String, sizeof(String), "Auto-scroll %u active - Period: %u minutes   ", Loop1UInt8 + 1, ActiveConfig0.AutoScroll[Loop1UInt8].Period);

      /* Scroll this part on first line of LED matrix. */
      win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "%s", String);
      String[0] = 0x00;  // reinitialize as null string.

      /* Scan all "items" of this auto-scroll. */
      for (Loop2UInt8 = 0; Loop2UInt8 < MAX_ITEMS; ++Loop2UInt8)
      {
        if (ActiveConfig0.AutoScroll[Loop1UInt8].FunctionId[Loop2UInt8] == 0) continue;  // this item is not initialized, skip it.
        FunctionNumber = get_function_number(ActiveConfig0.AutoScroll[Loop1UInt8].FunctionId[Loop2UInt8], FunctionName);  // find function number for this item.
        if (FunctionNumber != MAX_FUNCTIONS) snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "Item %u - %s   ", Loop2UInt8 + 1, Function[FunctionNumber].Name);
      }

      /* Add this text to the text sent to the scroll engine above. */
      win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "%s", String);
    }
  }

  return;
}





/* $PAGE */
/* $TITLE=function_bootsel() */
/* ============================================================================================================================================================= *\
                                                       Reset Pico in bootsel mode to upload a new Formware.
\* ============================================================================================================================================================= */
void function_bootsel(void)
{
  UINT32 IdleTime;


  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Make a long press on the <Set> button to reset the Pico in bootsel mode");

  /* Initializations. */
  IdleTime = 0l;


  // log_printf(__LINE__, __func__, "Before entering while loop. IdleTime: %lu   (BUTTON_TIME_OUT * 1000): %u\n", IdleTime, (BUTTON_TIME_OUT * 1000));
  while (IdleTime < (BUTTON_TIME_OUT * 1000))
  {
    /* Local button superseeds remote control buttons. */
    if (ButtonBuffer[0] != BUTTON_NONE)
    {
      log_printf(__LINE__, __func__, "Assigning %u to IrBuffer[0]\n", ButtonBuffer[0]);
      IrBuffer[0] = ButtonBuffer[0];
    }


    switch (IrBuffer[0])
    {
      case (BUTTON_SET_LONG):
        // log_printf(__LINE__, __func__, "Entering case BUTTON_LONG_SET\n");
        /* Unassigned windows to prevent something to be displayed. */
        WinTop = WIN_UNDEFINED;
        WinMid = WIN_UNDEFINED;
        WinBot = WIN_UNDEFINED;
        RGB_matrix_cls(FrameBuffer);
        RGB_matrix_set_brightness(0);
        pwm_on_off(PWM_ID_BRIGHTNESS, FLAG_OFF);
        save_and_disable_interrupts();
        reset_usb_boot(0l, 0l);
      break;

      default:
        // log_printf(__LINE__, __func__, "User pressed button %s (%u). Cancel Pico bootsel...\n", ButtonName[IrBuffer[0]], IrBuffer[0]);
        IrBuffer[0]     = BUTTON_NONE;  // reset IR buffer to receive next data.
        ButtonBuffer[0] = BUTTON_NONE;
     break;

     case (BUTTON_NONE):
        /* No new remote control button received, pause and increment idle time. */
        sleep_ms(300);
        IdleTime += 300l;

        if (DebugBitMask & DEBUG_IR)
        {
          if ((IdleTime % 1000l) == 0)
            log_printf(__LINE__, __func__, "IrBuffer[0] is BUTTON_NONE... Increment current timeout delay...(%5lu VS %5u)\n", IdleTime, (BUTTON_TIME_OUT * 1000));
        }
      break;
    }
  }

  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting function_bootsel()\n");

  return;
}





/* $PAGE */
/* $TITLE=function_brightness() */
/* ============================================================================================================================================================= *\
                                                   Function to display brightness and ambient light information.
\* ============================================================================================================================================================= */
void function_brightness(void)
{
  UCHAR String[256];


  if (DebugBitMask & DEBUG_BRIGHTNESS) log_printf(__LINE__, __func__, "Entering function_brightness()\n");

  /* Scroll current setting for auto-brightness. */
  if (ActiveConfig0.FlagAutoBrightness == FLAG_ON)
    snprintf(String, sizeof(String), "Auto brightness On   ");
  else
    snprintf(String, sizeof(String), "Auto brightness Off   ");


  /* Check if "Service light" is On or Off. */
  if (ServiceLightTimer) snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "Service light remaining time: %u sec.   ", ServiceLightTimer);

  /* Add instant ambient light value. */
  snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "Instant light: %u   ", get_light_value());

  /* If FlagAutoBrightness is On (ambient light history has been recorded), display hysteresis value. */
  if (ActiveConfig0.FlagAutoBrightness) snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "Hysteresis: %u   ", AverageAmbientLight);

  /* Add brightness settings (Low / High / Steady). */
  snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "Brightness settings - Low: %u   High: %u   Steady: %u   ",
          ActiveConfig0.BrightnessLoLimit, ActiveConfig0.BrightnessHiLimit, ActiveConfig0.BrightnessLevel);

  /* Add current brightness level. */
  snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "Brightness level: %u   ", BrightnessLevel);

  /* Add current PWM level. */
  snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "PWM Level: %u   ", Pwm[PWM_ID_BRIGHTNESS] .Level);

  /* Scroll everything on first line of LED matrix. */
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "%s", String);

  if (DebugBitMask & DEBUG_BRIGHTNESS) log_printf(__LINE__, __func__, "Exiting function_brightness()\n");

  return;
}





