/* $PAGE */
/* $TITLE=function_dst_set() */
/* ============================================================================================================================================================= *\
                                                             Function to ajust the daylight saving time.
\* ============================================================================================================================================================= */
void function_dst_set(void)
{
  UCHAR Dum1UChar[7];

  UINT8 EndColumnDST;
  UINT8 EndColumnDeltaTime;
  UINT8 EndRow;
  UINT8 FlagRefresh;
  UINT8 ItemNumber;
  UINT8 PreviousItemNumber;
  UINT8 StartColumnDST;
  UINT8 StartColumnDeltaTime;
  UINT8 StartRow;

  UINT32 IdleTime;


  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Entering function_dst_set()\n");


  /* Initializations. */
  FlagRefresh = FLAG_ON;
  IdleTime    = 0l;
  ItemNumber  = 0;  // hour is setup first.
  PreviousItemNumber  = 99;  // to force entry in switch case below.
  StartRow            = 20;
  EndRow              = 29;
  StartColumnDST      = 24;
  StartColumnDeltaTime = 21;
  EndColumnDST        = 41;
  EndColumnDeltaTime   = 43;


  log_printf(__LINE__, __func__, "Before win_cls(202)\n");
  win_cls(WIN_SETUP);
  win_printf(WIN_SETUP, 201, 99, FONT_5x7, "%s", $SET);

  log_printf(__LINE__, __func__, "Before entering while loop. IdleTime: %lu   (BUTTON_TIME_OUT * 1000): %u\n", IdleTime, (BUTTON_TIME_OUT * 1000));
  while (IdleTime < (BUTTON_TIME_OUT * 1000))
  {
    /* Blink item being adjusted. */
    if (ItemNumber != PreviousItemNumber)
    {
      PreviousItemNumber = ItemNumber;
      switch (ItemNumber)
      {
        case (0):
          /* First cycle, blink <DST Country> being adjusted. */
          log_printf(__LINE__, __func__, "Blinking DST Country\n");
          win_part_cls(WIN_SETUP, 18, 29);  // include lines containing infrared pilot.
          win_part_cls(WIN_SETUP, 202, 202);
          win_printf(WIN_SETUP, 202, 99, FONT_5x7, "%s", $COUNTRY_CODE);
          // win_printf(WIN_SETUP, 203, StartColumnDST, FONT_8x10, "%2.2u", ActiveConfig0.DSTCountry);
          win_blink(WIN_SETUP, StartRow, StartColumnDST, EndRow, EndColumnDST);
        break;

        case (1):
          /* Blink <DeltaTime> being adjusted. */
          log_printf(__LINE__, __func__, "Blinking DeltaTime\n");
          win_part_cls(WIN_SETUP, 18, 29);  // include lines containing infrared pilot.
          win_part_cls(WIN_SETUP, 202, 202);
          win_printf(WIN_SETUP, 202, 99, FONT_5x7, "%s", $DELTA_TIME);
          // win_printf(WIN_SETUP, 203, StartColumnDeltaTime, FONT_8x10, "%3.3d", ActiveConfig0.DeltaTime);
          win_blink(WIN_SETUP, StartRow, StartColumnDeltaTime, EndRow, EndColumnDeltaTime);
        break;
      }
    }


    /* Local button superseeds remote control buttons. */
    if (ButtonBuffer[0] != BUTTON_NONE)
    {
      log_printf(__LINE__, __func__, "Assigning %u to IrBuffer[0]\n", ButtonBuffer[0]);
      IrBuffer[0] = ButtonBuffer[0];
    }


    /* Check if there is a need to refresh the display. */
    if (FlagRefresh)
    {
      /* Reset IrBuffer and ButtonBuffer to receive next data. */
      IrBuffer[0]     = BUTTON_NONE;
      ButtonBuffer[0] = BUTTON_NONE;

      switch (ItemNumber)
      {
        case (0):
          /* Update what should be displayed in the blink buffer. */
          win_part_cls(WIN_SETUP, 18, 29);  // include the pilot IR line .
          RGB_matrix_cls(BlinkBuffer);  // clear the blink buffer before putting next data to blink.
          RGB_matrix_printf(BlinkBuffer, StartRow, 99, FONT_8x10, "%u", ActiveConfig0.DSTCountry);
        break;

        case (1):
          /* Update what should be displayed in the blink buffer. */
          win_part_cls(WIN_SETUP, 18, 29);  // include the pilot IR line .
          RGB_matrix_cls(BlinkBuffer);  // clear the blink buffer before putting next data to blink.
          if (ActiveConfig0.DeltaTime > 0)
          {
            RGB_matrix_printf(BlinkBuffer, StartRow, 99, FONT_8x10, "+%d", ActiveConfig0.DeltaTime);
          }
          else
          {
            RGB_matrix_printf(BlinkBuffer, StartRow, 99, FONT_8x10, "%d", ActiveConfig0.DeltaTime);
          }
        break;
      }
      FlagRefresh = FLAG_OFF;
    }


    switch (IrBuffer[0])
    {
      case (BUTTON_SET_LONG):
        win_blink_off(WIN_SETUP, 0, 0, 31, 63);
        IdleTime = (BUTTON_TIME_OUT * 1000);  // force an exit from while loop.
      break;

      case (BUTTON_SET):
        log_printf(__LINE__, __func__, "Entering case BUTTON_SET\n");
        IdleTime = 0l;              // reset idle time when receiving a new infrared data stream.
        ++ItemNumber;               // switch to next item to be adjusted: hour / minute / second
        if (ItemNumber == 2) ItemNumber = 0;  // revert to country code when we're done with DeltaTime.
        FlagRefresh = FLAG_ON;
        while ((Window[WIN_SETUP].BlinkOnTimer == 0ll) || ((time_us_64() - Window[WIN_SETUP].BlinkOnTimer) > 900000ll));  // make sure we change between Hour / Minute / Second only when current digit is turned On.
      break;

      case (IR_0):
      case (IR_1):
      case (IR_2):
      case (IR_3):
      case (IR_4):
      case (IR_5):
      case (IR_6):
      case (IR_7):
      case (IR_8):
      case (IR_9):
        log_printf(__LINE__, __func__, "Entering numeric digit from remote control.\n");
        IdleTime = 0l;  // reset idle time when receiving a new infrared data stream.

        switch (ItemNumber)
        {
          case (0):
            /* Initialize Dum1UChar with digits of current DST Country. */
            sprintf(Dum1UChar, "%2.2u", ActiveConfig0.DSTCountry);

            /* Slide digits one position to the left and make digit just received the last digit of item being entered. */
            Dum1UChar[0] = Dum1UChar[1];
            Dum1UChar[1] = IrBuffer[0] + 36;  // convert IR code received to ASCII digit.

            ActiveConfig0.DSTCountry = atoi(Dum1UChar);
          break;

          case (1):
            /* Initialize Dum1UChar with digits of current DeltaTime. */
            sprintf(Dum1UChar, "%d", ActiveConfig0.DeltaTime);

            /* Slide digits one position to the left and make digit just received the last digit of item being entered. */
            Dum1UChar[0] = Dum1UChar[1];
            Dum1UChar[1] = IrBuffer[0] + 36;  // convert IR code received to ASCII digit.

            ActiveConfig0.DeltaTime = atoi(Dum1UChar);
          break;
        }

        log_printf(__LINE__, __func__, "Current status of item digits: %u %u %u %u %u\n", Dum1UChar[0], Dum1UChar[1], Dum1UChar[2], Dum1UChar[3], Dum1UChar[4]);
        log_printf(__LINE__, __func__, "Received digit IR%u\n", (IrBuffer[0]));
        log_printf(__LINE__, __func__, "Received one more digit: %u  (0x%2.2X)   Item: %u\n", IrBuffer[0], IrBuffer[0], atoi(Dum1UChar));

        FlagRefresh = FLAG_ON;
      break;

      case (BUTTON_UP):
        /* User pressed the <Up> button ("CH+"). */
        IdleTime = 0l;  // reset idle time when receiving a new infrared data stream.

        log_printf(__LINE__, __func__, "User pressed <BUTTON_UP>\n");
        if (ItemNumber == 0)
        {
          ++ActiveConfig0.DSTCountry;
          if (ActiveConfig0.DSTCountry >= DST_HI_LIMIT) ActiveConfig0.DSTCountry = DST_NONE;
          log_printf(__LINE__, __func__, "Changing DST Country to %2.2u\n", ActiveConfig0.DSTCountry);
        }

        if (ItemNumber == 1)
        {
          ActiveConfig0.DeltaTime += 10;
          if (ActiveConfig0.DeltaTime > 840) ActiveConfig0.DeltaTime = -720;
          log_printf(__LINE__, __func__, "Changing delta time to %3d\n", ActiveConfig0.DeltaTime);
        }
        FlagRefresh = FLAG_ON;
      break;

      case (BUTTON_DOWN):
        /* User pressed <Down> button ("CH-"). */
        IdleTime = 0l;  // reset idle time when receiving a new infrared data stream.

        log_printf(__LINE__, __func__, "User pressed <BUTTON_DOWN>\n");
        if (ItemNumber == 0)
        {
          --ActiveConfig0.DSTCountry;
          /* If we go under zero, revert to highest value. */
          if (ActiveConfig0.DSTCountry > DST_HI_LIMIT) ActiveConfig0.DSTCountry = DST_HI_LIMIT - 1;
          log_printf(__LINE__, __func__, "Changing DST Country to %2.2u\n", ActiveConfig0.DSTCountry);
        }

        if (ItemNumber == 1)
        {
          ActiveConfig0.DeltaTime -= 10;
          if (ActiveConfig0.DeltaTime < -720) ActiveConfig0.DeltaTime = 840;
          log_printf(__LINE__, __func__, "Changing delta time to %3.2d\n", ActiveConfig0.DeltaTime);
        }
        FlagRefresh = FLAG_ON;
      break;

      default:
      case (BUTTON_NONE):
        /* No new remote control button received, pause and increment idle time. */
        sleep_ms(300);
        IdleTime += 300l;

        if (DebugBitMask & DEBUG_IR)
        {
          if ((IdleTime % 1000l) == 0)
            log_printf(__LINE__, __func__, "IrBuffer[0] is BUTTON_NONE... Incrementing current timeout delay...(%5lu VS %5u)\n", IdleTime, (BUTTON_TIME_OUT * 1000));
        }
      break;
    }
  }

  win_close(WIN_SETUP, FLAG_ON);

  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting function_dst_set())\n");

  return;
}





