/* $PAGE */
/* $TITLE=function_events_day() */
/* ============================================================================================================================================================= *\
                                                         Function to display calendar events of the day.
\* ============================================================================================================================================================= */
void function_events_day(void)
{
  UCHAR String[65];

  UINT16 EventCounter16;
  UINT16 Loop1UInt16;


  EventCounter16 = 0;
  for (Loop1UInt16 = 0; Loop1UInt16 < MAX_EVENTS; ++Loop1UInt16)
  {
    String[0] = 0x00;  // initialize as null string.
    if (ActiveConfig0.Event[Loop1UInt16].Day   != CurrentTime.DayOfMonth) continue;
    if (ActiveConfig0.Event[Loop1UInt16].Month != CurrentTime.Month)  continue;
    ++EventCounter16;
    snprintf(String, sizeof(String), "%2.2u-%s: %s   ", ActiveConfig0.Event[Loop1UInt16].Day, ShortMonth[ActiveConfig0.Event[Loop1UInt16].Month], ActiveConfig0.Event[Loop1UInt16].Message);
    win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "%s", String);
  }

  switch (EventCounter16)
  {
    case (0):
      snprintf(String, sizeof(String), "No event defined for today");
    break;

    case (1):
      snprintf(String, sizeof(String), "1 event defined for today");
    break;

    default:
      snprintf(String, sizeof(String), "%u events defined for today", EventCounter16);
    break;
  }
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "%s", String);

  return;
}





/* $PAGE */
/* $TITLE=function_events_month() */
