/* $PAGE */
/* $TITLE=function_golden_set() */
/* ============================================================================================================================================================= *\
                                                               Function for golden age mode setup.
\* ============================================================================================================================================================= */
void function_golden_set(void)
{
  // UINT8 FlagRefresh;
  UINT8 Loop1UInt8;
  UINT8 StartColumn;
  UINT8 EndColumn;
  UINT8 StartRow;
  UINT8 EndRow;

  UINT32 IdleTime;


  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Entering function_golden_set()\n");

  /* Initializations. */
  // FlagRefresh = FLAG_ON;
  IdleTime    = 0l;
  StartRow    = 20;
  EndRow      = 29;
  StartColumn = 20;
  EndColumn   = 43;


  log_printf(__LINE__, __func__, "Before entering while loop. IdleTime: %lu   (BUTTON_TIME_OUT * 1000): %u\n", IdleTime, (BUTTON_TIME_OUT * 1000));

  while (IdleTime < (BUTTON_TIME_OUT * 1000))
  {
    win_printf(WIN_SETUP, 201, 99, FONT_5x7, "%s", $SET);
    win_printf(WIN_SETUP, 202, 99, FONT_5x7, "%s", $GOLDEN_AGE_SET);

    /* Display current setting of Golden Age option. */
    if (ActiveConfig0.FlagGoldenAge)
      win_printf(WIN_SETUP, 203, 99, FONT_8x10, "ON");
    else
      win_printf(WIN_SETUP, 203, 99, FONT_8x10, "OFF");

    /* Blink item being adjusted. */
    RGB_matrix_cls(BlinkBuffer);
    win_blink(WIN_SETUP, StartRow, StartColumn, EndRow, EndColumn);


    /* Local button superseeds remote control buttons. */
    if (ButtonBuffer[0] != BUTTON_NONE)
    {
      log_printf(__LINE__, __func__, "Assigning %u to IrBuffer[0]\n", ButtonBuffer[0]);
      IrBuffer[0] = ButtonBuffer[0];
    }


    switch (IrBuffer[0])
    {
      case (BUTTON_SET):
      case (BUTTON_SET_LONG):
        log_printf(__LINE__, __func__, "Entering case BUTTON_SET\n");
        win_blink_off(WIN_SETUP, 0, 0, 31, 63);
        IdleTime = (BUTTON_TIME_OUT * 1000);  // force an exit from while loop.
        while ((Window[WIN_SETUP].BlinkOnTimer == 0ll) || ((time_us_64() - Window[WIN_SETUP].BlinkOnTimer) > 900000ll));  // make sure we change between Hour / Minute / Second only when current digit is turned On.
      break;

      case (BUTTON_UP):
      case (BUTTON_DOWN):
        /* User pressed the <Up> or <Down> button ("CH+"). */
        IdleTime = 0l;  // reset idle time when receiving a new infrared data stream.

        /* Reset IrBuffer and ButtonBuffer to receive next data. */
        IrBuffer[0]     = BUTTON_NONE;
        ButtonBuffer[0] = BUTTON_NONE;

        log_printf(__LINE__, __func__, "User pressed <BUTTON_UP>\n");
        if (ActiveConfig0.FlagGoldenAge)
        {
          ActiveConfig0.FlagGoldenAge = FLAG_OFF;
          for (Loop1UInt8 = 0; Loop1UInt8 < 4; ++Loop1UInt8)
            DoubleDotsCurrentColor[Loop1UInt8] = Window[WIN_TIME].InsideColor;
        }
        else
        {
          ActiveConfig0.FlagGoldenAge = FLAG_ON;

          for (Loop1UInt8 = 0; Loop1UInt8 < 4; ++Loop1UInt8)
            DoubleDotsCurrentColor[Loop1UInt8] = GoldenAgeCurrentColor;
        }

        // FlagRefresh = FLAG_ON;
      break;


      default:
      case (BUTTON_NONE):
        /* No new remote control button received, pause and increment idle time. */
        sleep_ms(300);
        IdleTime += 300l;

        if (DebugBitMask & DEBUG_IR)
        {
          if ((IdleTime % 1000l) == 0)
            log_printf(__LINE__, __func__, "IrBuffer[0] is BUTTON_NONE... Increment current timeout delay...(%5lu VS %5u)\n", IdleTime, (BUTTON_TIME_OUT * 1000));
        }
      break;
    }
  }

  win_close(WIN_SETUP, FLAG_ON);

  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting function_golden_set()\n");

  return;
}





