/* $PAGE */
/* $TITLE=function_network_data() */
/* ============================================================================================================================================================= *\
                                                                  Function to display network info.
\* ============================================================================================================================================================= */
void function_network_data(void)
{
  UCHAR String[128];

  UINT8 Loop1UInt8;


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                             Wi-Fi data
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  /* Scroll info about WiFi. */
  if (StructWiFi.FlagHealth == FLAG_ON)
    strcpy(String, "Good");
  else
    strcpy(String, "Problems");
  
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Wi-Fi health: %s (%lu)   ", String, ActiveConfig0.TotalWiFiErrors);
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Device IP: %s   ",          ip4addr_ntoa(&StructWiFi.PicoIPAddress));

  strcpy(String, "Device MAC: ");
  for (Loop1UInt8 = 0; Loop1UInt8 < sizeof(StructWiFi.MacAddress); ++Loop1UInt8)
  {
    snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "%2.2X", StructWiFi.MacAddress[Loop1UInt8]);
    if (Loop1UInt8 < (sizeof(StructWiFi.MacAddress) - 1))
      snprintf(&String[strlen(String)], sizeof(String) - strlen(String), ":");    // MAC address separator.
    else
      snprintf(&String[strlen(String)], sizeof(String) - strlen(String), "   ");  // three trailing spaces.
  }
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, String);

  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Host name: %s   ", StructWiFi.ExtraHostName);


  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                              NTP data
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
#ifdef NTP_SUPPORT
  /* Scroll info about NTP. */
  if (StructNTP.FlagHealth == FLAG_ON)
    strcpy(String, "Good");
  else
    strcpy(String, "Problems");
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "NTP health: %s - %s (%lu) %lu - %lu   ScanCount: %u   ", String, ip4addr_ntoa(&StructNTP.ServerAddress), ActiveConfig0.TotalNTPErrors, StructNTP.ReadCycles, StructNTP.PollCycles, StructNTP.ScanCount);
#else  // NTP_SUPPORT
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "NTP protocol is not supported in this version of Firmware");
#endif  // NTP_SUPPORT



  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                             MQTT data
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
#ifdef MQTT_SUPPORT
  /* Scroll info about MQTT. */
  if ((StructMQTT.MqttClientInstance) && (mqtt_client_is_connected(StructMQTT.MqttClientInstance) == true))
  {
    StructMQTT.FlagHealth = FLAG_ON;
    strcpy(String, "Good");
  }
  else
  {
    StructMQTT.FlagHealth = FLAG_OFF;
    strcpy(String, "Problems");
  }
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "MQTT health: %s (%lu)   ", String, ActiveConfig0.TotalMQTTErrors);
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Broker IP: %s   ",         ip4addr_ntoa(&StructMQTT.BrokerAddress));
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Pico IP: %s   ",           ip4addr_ntoa(&StructMQTT.PicoIPAddress));
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Pico Unique ID: %s   ",    StructMQTT.PicoUniqueId);
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Device ID: %s   ",         StructMQTT.PicoIdentifier);
#else  // MQTT_SUPPORT
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "MQTT protocol is not supported in this version of Firmware");
#endif  // MQTT_SUPPORT



#ifdef ZIGBEE_SUPPORT
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                             ZigBee data
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
#else  // ZIGBEE_SUPPORT
  /* Scroll eventual problems with ZigBee. */
  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "ZigBee not supported in this version");
#endif  // ZIGBEE_SUPPORT

  return;
}





