/* $PAGE */
/* $TITLE=function_police() */
/* ============================================================================================================================================================= *\
                                                              Function to simulate police lights.
\* ============================================================================================================================================================= */
void function_police(void)
{
  UINT8 Flashes;
  UINT8 FlipFlop;
  UINT8 Loop1UInt8;
  UINT8 Loop2UInt8;

  UINT64 StartTimer;


  win_open(WIN_TEST, FLAG_ON, FLAG_OFF);
  win_cls(WIN_TEST);

  FlipFlop   = 0;
  StartTimer = time_us_64();

  RGB_matrix_set_color( 0,  0, 15, 63,  RED);  // top half.
  RGB_matrix_set_color(16,  0, 31, 63, BLUE);  // bottom half.


  while (1)
  {
    /* Randomize a number of flashes between 1 and 3. */
    // Flashes = ((rand() % 3) + 1);
    Flashes = 2;

    /* Alternate between red and blue. */
    if (FlipFlop)
    {
      /* Strobe the top half matrix. */
      FlipFlop = 0;

      for (Loop2UInt8 = 0; Loop2UInt8 < (MAX_ROWS / 2); ++Loop2UInt8)
      {
        FrameBuffer[Loop2UInt8] = 0xFFFFFFFFFFFFFFFFll;
        FrameBuffer[(MAX_ROWS / 2) + Loop2UInt8] = 0x00ll;
      }
    }
    else
    {
      /* Strobe the bottom half matrix. */
      FlipFlop = 1;

      for (Loop2UInt8 = 0; Loop2UInt8 < (MAX_ROWS / 2); ++Loop2UInt8)
      {
        FrameBuffer[Loop2UInt8] = 0x00ll;
        FrameBuffer[(MAX_ROWS / 2) + Loop2UInt8] = 0xFFFFFFFFFFFFFFFFll;
      }
    }

    RGB_matrix_set_brightness(BRIGHTNESS_HI_LIMIT);
    for (Loop1UInt8 = 0; Loop1UInt8 < Flashes; ++Loop1UInt8)
    {
      pwm_on_off(PWM_ID_BRIGHTNESS, FLAG_ON);
      sleep_ms(120);
      pwm_on_off(PWM_ID_BRIGHTNESS, FLAG_OFF);
      // RGB_matrix_set_brightness(BRIGHTNESS_LO_LIMIT);
      sleep_ms(120);
    }

    if (time_us_64() > (StartTimer + (3 * 60 * 1000000ll))) break;  // stop after 3 minutes.
    if (IrBuffer[0] != BUTTON_NONE) break;  // stop if user pressed a remote control button.
    sleep_ms(200);
  }

  win_close(WIN_TEST, FLAG_ON);

  return;
}





/* $PAGE */
/* $TITLE=function_reboot() */
/* ============================================================================================================================================================= *\
                                                        Function to reboot the RGB matrix device.
\* ============================================================================================================================================================= */
void function_reboot(void)
{
  UINT32 IdleTime;


  win_scroll(WinTop, 201, 201, 1, 1, FONT_5x7, "Make a long press on the <Set> button to reboot the RGB matrix");

  /* Initializations. */
  IdleTime = 0l;


  log_printf(__LINE__, __func__, "Before entering while loop. IdleTime: %lu   (BUTTON_TIME_OUT * 1000): %u\n", IdleTime, (BUTTON_TIME_OUT * 1000));
  while (IdleTime < (BUTTON_TIME_OUT * 1000))
  {
    /* Local button superseeds remote control buttons. */
    if (ButtonBuffer[0] != BUTTON_NONE)
    {
      log_printf(__LINE__, __func__, "Assigning %u to IrBuffer[0]\n", ButtonBuffer[0]);
      IrBuffer[0] = ButtonBuffer[0];
    }


    switch (IrBuffer[0])
    {
      case (BUTTON_SET_LONG):
        log_printf(__LINE__, __func__, "Entering case BUTTON_LONG_SET\n");
        RGB_matrix_cls(FrameBuffer);

        /* Log the restart. */
        log_printf(__LINE__, __func__, " \n\n\n\n\n%2.2u-%s-%4.4u - %2.2u:%2.2u:%2.2u - RGB Matrix restarted by user (remote or local button)...\n\n\n\n\n", CurrentTime.DayOfMonth, ShortMonth[CurrentTime.Month], CurrentTime.Year, CurrentTime.Hour, CurrentTime.Minute, CurrentTime.Second);
        no_op(500l);

        software_reset(0);
      break;

      default:
        log_printf(__LINE__, __func__, "User pressed button %s (%u). Cancel RGB matrix reboot...\n", ButtonName[IrBuffer[0]], IrBuffer[0]);
        IrBuffer[0]     = BUTTON_NONE;  // reset IR buffer to receive next data.
        ButtonBuffer[0] = BUTTON_NONE;
     break;

     case (BUTTON_NONE):
        /* No new remote control button received, pause and increment idle time. */
        sleep_ms(300);
        IdleTime += 300l;

        if (DebugBitMask & DEBUG_IR)
        {
          if ((IdleTime % 1000l) == 0)
            log_printf(__LINE__, __func__, "IrBuffer[0] is BUTTON_NONE... Increment current timeout delay...(%5lu VS %5u)\n", IdleTime, (BUTTON_TIME_OUT * 1000));
        }
      break;
    }
  }

  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting function_reboot())\n");

  return;
}





/* $PAGE */
/* $TITLE=function_search() */
/* ============================================================================================================================================================= *\
                                                    Find the function number correspondint to this function ID.
\* ============================================================================================================================================================= */
UINT16 function_search(UINT16 FunctionId)
{
  UINT16 Loop1UInt16;


  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Entering function_search()\n");

  for(Loop1UInt16 = 0; Loop1UInt16 < MAX_FUNCTIONS; ++Loop1UInt16)
  {
    if (Function[Loop1UInt16].Id == FunctionId)
    {
      /* Function ID has been found, return function number. */
      return Loop1UInt16;
    }
  }

  if (DebugBitMask & DEBUG_FLOW) log_printf(__LINE__, __func__, "Exiting function_search()\n");

  /* Function ID has not been found, return MAX_FUNCTIONS as an error message. */
  return MAX_FUNCTIONS;
}





