/* $PAGE */
/* $TITLE=term_time_setup()) */
/* ============================================================================================================================================================ *\
                                                                  Terminal submenu for time setup.
\* ============================================================================================================================================================ */
void term_time_setup(void)
{
  UCHAR String[31];

  struct human_time HumanTime;


  /* First, get current time from real-time clock IC (DS3231). */
  ds3231_get_time(&HumanTime);

  log_printf(__LINE__, __func__, " \n\n\n\nTime setup\n\n");
  log_printf(__LINE__, __func__, "Current time is: %2.2u:%2.2u:%2.2u\n", HumanTime.Hour, HumanTime.Minute, HumanTime.Second);

  log_printf(__LINE__, __func__, "Enter Hour (or <Enter> for no change)   [%2u]: ", HumanTime.Hour);
  input_string(String, sizeof(String), 60000l);
  if (String[0] != 0x0D) HumanTime.Hour = atoi(String);


  log_printf(__LINE__, __func__, "Enter Minute (or <Enter> for no change) [%2.2u]: ", HumanTime.Minute);
  input_string(String, sizeof(String), 60000l);
  if (String[0] != 0x0D) HumanTime.Minute = atoi(String);


  log_printf(__LINE__, __func__, "Enter Second (or <Enter> for no change) [%2.2u]: ", HumanTime.Second);
  input_string(String, sizeof(String), 60000l);
  if (String[0] != 0x0D) HumanTime.Second = atoi(String);

  ds3231_set_time(&HumanTime);
  log_printf(__LINE__, __func__, "Real time clock IC has been set to: %2.2u:%2.2u:%2.2u\n", HumanTime.Hour, HumanTime.Minute, HumanTime.Second);
  log_printf(__LINE__, __func__, "Press <Enter> to continue: ");
  input_string(String, 1, 60000l);

  return;
}





