  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                       Turn Off pixels row by row and column by column for the specified LED matrix area (using direct FrameBuffer access).
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
  log_printf(__LINE__, __func__, "Press <Enter> to turn Off pixels one by one using direct FrameBuffer access\n");
  log_printf(__LINE__, __func__, "or <ESC> to return to menu: ");
  input_string(String, 1, 60000l);
  if (String[0] == 0x1B) return;

  /* Determine the matrix area to be turned Off. */
  StartRow    =  9;
  EndRow      = 22;
  StartColumn = 20;
  EndColumn   = 43;

  /* Turn On all LEDs on entry. */
  memset(FrameBuffer, 0xFF, 256);

  /* Turn Off pixels in the specified matrix area, row by row and column by column. */
  log_printf(__LINE__, __func__, "LED matrix area defined to be turned Off: StartRow:  %2u     StartColumn:  %2u     EndRow:  %2u     EndColumn:  %2u\n\n", StartRow, StartColumn, EndRow, EndColumn);

  for (RowNumber = StartRow; RowNumber <= EndRow; ++RowNumber)
	{
    for (ColumnNumber = StartColumn; ColumnNumber <= EndColumn; ++ColumnNumber)
    {
      log_printf(__LINE__, __func__, "Turn Off pixel - Row: %2u   Column: %2u\n", RowNumber, ColumnNumber);
      FrameBuffer[RowNumber] &= ~(0x01ll << ColumnNumber);
      log_printf(__LINE__, __func__, "Press <Enter> to turn Off next pixel or <ESC> to exit test: ");
      sleep_ms(100);  // to prevent communication override if user keep pressing <Enter>.
      input_string(String, 1, 60000l);
      if (String[0] == 0x1B)
      {
        /* Erase LED matrix before exiting. */
        RGB_matrix_cls(FrameBuffer);
        break;
      }
    }
    printf("\n");
    if (String[0] == 0x1B) break;  // exit outer loop.
  }
  log_printf(__LINE__, __func__, " \n\n\n");



