    RGB_matrix_set_brightness(0);           // turn Off brightness.

    RGB_matrix_cls(ShadowBuffer);

    /* Display ASCII value on LED display. */
    RGB_matrix_printf(ShadowBuffer, 17, 40, FONT_5x7, "%3.3u", AsciiValue);

    /* Draw a bigger blue box. */
    RGB_matrix_set_color(StartRow, StartColumn, EndRow, EndColumn, BLUE);
    RGB_matrix_set_pixel(ShadowBuffer, StartRow, StartColumn, EndRow, EndColumn);

    /* Then, draw a smaller green box inside the blue box. */
    RGB_matrix_set_color(StartRow + 2, StartColumn + 2, EndRow - 2, EndColumn - 2, GREEN);
    RGB_matrix_set_pixel(ShadowBuffer, StartRow + 2, StartColumn + 2, EndRow - 2, EndColumn - 2);

    /* Draw a red box for character bitmap width only. */
    RGB_matrix_set_color(StartRow + 4, StartColumn + 4, EndRow - 4, EndColumn - 4, RED);
    RGB_matrix_set_pixel(ShadowBuffer, StartRow + 4, StartColumn + 4, EndRow - 4, EndColumn - 4);

    /* Finally, display ASCII character in inside the red box. */
    RGB_matrix_display(ShadowBuffer, StartRow + 4, StartColumn + 4, AsciiValue, FONT_5x7, 0);

    /* Display the same ASCII character to the right of the larger blue box. */
    RGB_matrix_display(ShadowBuffer, StartRow + 4, StartColumn + 22, AsciiValue, FONT_5x7, 0);

    RGB_matrix_set_row_mask(&DisplayMatrix.RowMask, StartRow, EndRow);
    DisplayMatrix.FlagUpdate = FLAG_ON;


