  /* Print some text in each section of the matrix. */
  win_printf(WIN_TEST,  0, 99, FONT_8x10, "12345678");
  win_printf(WIN_TEST, 11, 99, FONT_8x10, "12345678");
  win_printf(WIN_TEST, 22, 99, FONT_8x10, "12345678");



  /* Retrieve system clock (Pico is 125 MHz). */
  SystemClock = clock_get_hz(clk_sys);

  log_printf(__LINE__, __func__, " \n\n\n");
  log_printf(__LINE__, __func__, "WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING\n\n");
  log_printf(__LINE__, __func__, "Be careful while changing PWM parameters. You could go beyond operational values and jeopardize the life span of the LEDs...\n");
  log_printf(__LINE__, __func__, "Be prepared to turn Off the Pico-SLASH-Display power supply if ever you realize that the LEDs are overbright and you can't quickly\n");
  log_printf(__LINE__, __func__, "restore the situation.\n\n");
  log_printf(__LINE__, __func__, "WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING - - - WARNING\n\n");
  log_printf(__LINE__, __func__, "Press <Enter> to continue: ");
  input_string(String, 1, 60000l);


  /* Keep track of current FlagAutoBrightness setting. */
  FlagOriginal = ActiveConfig0.FlagAutoBrightness;
  ActiveConfig0.FlagAutoBrightness = FLAG_OFF;
  log_printf(__LINE__, __func__, " \n\n\n");
  if (FlagOriginal)
    log_printf(__LINE__, __func__, "Auto brightness original setting was On (0x%2.2X)\n", FlagOriginal);
  else
    log_printf(__LINE__, __func__, "Auto brightness original setting was Off (0x%2.2X)\n", FlagOriginal);
  log_printf(__LINE__, __func__, "Auto brightness is turned Off during the tests.\n");
  log_printf(__LINE__, __func__, "PWM level is currently set to: %2u\n\n", Pwm[PWM_ID_BRIGHTNESS].Level);


  while (1)
  {
    pwm_display_parameters();
    display_ambient_light_value();
    printf("\n\n");

    log_printf(__LINE__, __func__, "1) Set PWM divider.\n");
    log_printf(__LINE__, __func__, "2) Set PWM wrap.\n");
    log_printf(__LINE__, __func__, "3) Set PWM level.\n");
    log_printf(__LINE__, __func__, "4) Set matrix color.\n");
    log_printf(__LINE__, __func__, "5) Turn Off matrix.\n");
    log_printf(__LINE__, __func__, "6) Turn On matrix.\n\n");



    String[0] = '0';
    String[1] = 0x00;
    while (atoi(String) == 0)
    {
      log_printf(__LINE__, __func__, "Enter your choice or <ESC> to exit test: ");
      input_string(String, sizeof(String), 60000l);
      if (String[0] == 0x1B)
      {
        /* Restore ActiveConfig0.FlagAutoBrightness original setting. */
        ActiveConfig0.FlagAutoBrightness = FlagOriginal;
        if (FlagOriginal)
          log_printf(__LINE__, __func__, "ActiveConfig0.FlagAutoBrightness setting has been restored to On (0x%2.2X)\n", ActiveConfig0.FlagAutoBrightness);
        else
          log_printf(__LINE__, __func__, "ActiveConfig0.FlagAutoBrightness setting has been restored to Off (0x%2.2X)\n", ActiveConfig0.FlagAutoBrightness);

        log_printf(__LINE__, __func__, "Press <Enter> to return to menu: ");
        input_string(String, 1, 60000l);
        return;
      }

      if ((atoi(String) == 0) || (atoi(String) > 6))
      {
        log_printf(__LINE__, __func__, "Invalid choice... try again\n");
        String[0] = '0';
        String[1] = 0x00;
      }
    }

    switch (atoi(String))
    {
      case (1):
        /* Set divider. */
        log_printf(__LINE__, __func__, "Enter PWM clock divider value (float) or <ESC> to return to test menu: ");
        input_string(String, sizeof(String), 60000l);
        if (String[0] == 0x1B) break;
        if (String[0] != 0x0D)
        {
          Pwm[PWM_ID_BRIGHTNESS].ClockDivider = atof(String);
          log_printf(__LINE__, __func__, "Setting PWM divider to: %f\n", Pwm[PWM_ID_BRIGHTNESS].ClockDivider);
          Pwm[PWM_ID_BRIGHTNESS].Clock = (UINT32)(SystemClock / Pwm[PWM_ID_BRIGHTNESS].ClockDivider);  // keep track of resulting clock frequency.
          pwm_set_clkdiv(Pwm[PWM_ID_BRIGHTNESS].Slice, Pwm[PWM_ID_BRIGHTNESS].ClockDivider);
        }
      break;

      case (2):
        /* Set wrap. */
        log_printf(__LINE__, __func__, "Enter PWM wrap value (UINT16) or <ESC> to return to test menu: ");
        input_string(String, sizeof(String), 60000l);
        if (String[0] == 0x1B) break;
        if (String[0] != 0x0D)
        {
          Pwm[PWM_ID_BRIGHTNESS].Wrap = atoi(String);
          log_printf(__LINE__, __func__, "Setting PWM wrap to: %u\n", Pwm[PWM_ID_BRIGHTNESS].Wrap);
          pwm_set_wrap(Pwm[PWM_ID_BRIGHTNESS].Slice, Pwm[PWM_ID_BRIGHTNESS].Wrap);
        }
      break;

      case (3):
        /* Set level. */
        log_printf(__LINE__, __func__, "Enter PWM level (UINT16) or <ESC> to return to test menu: ");
        input_string(String, sizeof(String), 60000l);
        if (String[0] == 0x1B) break;
        if (String[0] != 0x0D)
        {
          Pwm[PWM_ID_BRIGHTNESS].Level = atoi(String);  // indicate current PWM values.
          log_printf(__LINE__, __func__, "Setting PWM level to: %u\n", Pwm[PWM_ID_BRIGHTNESS].Level);

          /* Set PWM level. */
          CLK_HIGH;
          pwm_set_chan_level(Pwm[PWM_ID_BRIGHTNESS].Slice, Pwm[PWM_ID_BRIGHTNESS].Channel, Pwm[PWM_ID_BRIGHTNESS].Level);
          CLK_LOW;
        }
      break;

      case (4):
        /* Set color. */
        log_printf(__LINE__, __func__, "Enter matrix color to set (ASCII text) or <ESC> to return to test menu: ");
        input_string(String, sizeof(String), 60000l);
        if (String[0] == 0x1B) break;
        if (String[0] != 0x0D)
        {
          if (strcmp(util_to_lower(String), "red")     == 0) RGB_matrix_set_color(0, 0, 31, 63, RED);
          if (strcmp(util_to_lower(String), "green")   == 0) RGB_matrix_set_color(0, 0, 31, 63, GREEN);
          if (strcmp(util_to_lower(String), "blue")    == 0) RGB_matrix_set_color(0, 0, 31, 63, BLUE);
          if (strcmp(util_to_lower(String), "cyan")    == 0) RGB_matrix_set_color(0, 0, 31, 63, CYAN);
          if (strcmp(util_to_lower(String), "magenta") == 0) RGB_matrix_set_color(0, 0, 31, 63, MAGENTA);
          if (strcmp(util_to_lower(String), "yellow")  == 0) RGB_matrix_set_color(0, 0, 31, 63, YELLOW);
          if (strcmp(util_to_lower(String), "white")   == 0) RGB_matrix_set_color(0, 0, 31, 63, WHITE);
        }
      break;

      case (5):
        /* Turn Off matrix. */
        log_printf(__LINE__, __func__, "Press <Enter> to blank LED matrix or <ESC> to exit test: ");
        input_string(String, 1, 60000l);
        if (String[0] == 0x1B) break;
        RGB_matrix_cls(FrameBuffer);
      break;

      case (6):
        /* Turn On matrix. */
        log_printf(__LINE__, __func__, "Press <Enter> to turn On all LED matrix or <ESC> to exit test: ");
        input_string(String, 1, 60000l);
        if (String[0] == 0x1B) break;
        memset(FrameBuffer, 0xFF, 256);
      break;
    }
  }
  log_printf(__LINE__, __func__, " \n\n\n");

  return;





