  /* $PAGE */
  /* $TITLE=Test9 */
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                                  Test number 9.
                                                                        Power supply requirement tests.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
Test9:
  /* Power supply requirement tests. */
  log_printf(__LINE__, __func__, " \n\n\n");
  log_printf(__LINE__, __func__, "Entering Test number 9\n");
  log_printf(__LINE__, __func__, "Power supply requirement.\n\n\n");
  log_printf(__LINE__, __func__, "=== IMPORTANT === This test will turn On ALL pixels on the LED matrix display\n");
  log_printf(__LINE__, __func__, "                  It is recommended to proceed quickly with this test in order\n");
  log_printf(__LINE__, __func__, "                  not to overload the device electronics. Even more important\n");
  log_printf(__LINE__, __func__, "                  is to use an adequate power supply able to provide the current\n");
  log_printf(__LINE__, __func__, "                  required by the device. Do not rely on the current provided by\n");
  log_printf(__LINE__, __func__, "                  connecting the RGB-Matrix to your computer's USB port as you\n");
  log_printf(__LINE__, __func__, "                  could blow up the computer's USB port it is connected to...\n");
  log_printf(__LINE__, __func__, "                  Connect an Amp-meter to the RGB matrix to see the power supply\n");
  log_printf(__LINE__, __func__, "                  required for the different scenarios.\n\n\n\n\n");


  log_printf(__LINE__, __func__, "Press <Enter> to continue or <ESC> to exit this test: ");
  input_string(String, 1, 60000l);
  if (String[0] == 0x1B) return;
  RGB_matrix_cls(FrameBuffer);


  /* Announce test number. */
  RGB_matrix_set_color(0, 0, 31, 63, BLUE);
  win_printf(WIN_TEST, 2, 99, FONT_5x7, "Test 9");

  for (Loop1UInt8 = 0; Loop1UInt8 < 7; ++Loop1UInt8)
  {
    switch (Loop1UInt8)
    {
      case (0):
        RGB_matrix_set_color(0, 0, 31, 63, BLUE);  // blue, around 195 mA
      break;

      case (1):
        RGB_matrix_set_color(0, 0, 31, 63, GREEN);  // green, around 315 mA
      break;

      case (2):
        RGB_matrix_set_color(0, 0, 31, 63, RED);  // red, around 550 mA
      break;

      case (3):
        RGB_matrix_set_color(0, 0, 31, 63, BLUE + GREEN);  // cyan, around 480 mA
      break;

      case (4):
        RGB_matrix_set_color(0, 0, 31, 63, BLUE + RED);  // magenta, around 625 mA
      break;

      case (5):
        RGB_matrix_set_color(0, 0, 31, 63, GREEN + RED);  // yellow, round 680 mA
      break;

      case (6):
        RGB_matrix_set_color(0, 0, 31, 63, BLUE + GREEN + RED);  // white, around 730 mA
      break;
    }

    log_printf(__LINE__, __func__, "Press <Enter> to turn On all LEDs on RGB-Matrix\n");
    log_printf(__LINE__, __func__, "or <ESC> to exit test: ");
    input_string(String, 1, 60000l);
    if (String[0] == 0x1B) return;

    log_printf(__LINE__, __func__, "NOTE: === Current PWM level is: %u ===\n\n", Pwm[PWM_ID_BRIGHTNESS].Level);
    log_printf(__LINE__, __func__, "LED matrix will automatically turn Off after 5 seconds.\n");
    RGB_matrix_set_pixel(FrameBuffer, 0, 0, 31, 63);
    sleep_ms(5000);  // limit exposure time to 5 seconds to prevent overload.
    RGB_matrix_cls(FrameBuffer);
    log_printf(__LINE__, __func__, "Press <Enter> to proceed with next color\n");
    log_printf(__LINE__, __func__, "or <ESC> to exit test: ");
    input_string(String, 1, 60000l);
    if (String[0] == 0x1B) return;
  }

  return;





  /* $PAGE */
  /* $TITLE=Test10 */
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                              Test number 10.
                                                                         Active buzzer sound queue
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
Test10:
  /* Active buzzer sound queue. */
  log_printf(__LINE__, __func__, " \n\n\n");
  log_printf(__LINE__, __func__, "Entering Test number 10\n");
  log_printf(__LINE__, __func__, "Active buzzer sound queue tests.\n");


  win_printf(WIN_TEST, 2, 99, FONT_5x7, "Test 10");


  log_printf(__LINE__, __func__, " \n\nActive buzzer sound queue tests.\n");

  Length = 50;      // default to 50 msec.
  RepeatCount = 3;  // default to 3 repeats.

  while(1)
  {
    log_printf(__LINE__, __func__, "Enter the length of the sounds (in msec, between 50 - 5000), <ESC> to exit test or <Enter> to keep [%u msec]: ", Length);
    input_string(String, sizeof(String), 60000l);
    if (String[0] == 0x1B) return;
    if (String[0] != 0x0D) Length = atoi(String);
    if (Length < 50)   Length = 50;
    if (Length > 5000) Length = 5000;

    log_printf(__LINE__, __func__, "Enter the repeat count, <ESC> to exit test or <Enter> to keep [%u times]: ", RepeatCount);
    input_string(String, sizeof(String), 60000l);
    if (String[0] == 0x1B) return;
    if (String[0] != 0x0D) RepeatCount = atoi(String);

    /* Queue the specified sound sequence. */
    queue_add_active(Length, RepeatCount);

    /* Wait till we are done with current sound sequence. */
    while (queue_free_active() != (MAX_ACTIVE_SOUND_QUEUE - 1))
    {
      sleep_ms(50);
    };
  }

   return;





