  /* $PAGE */
  /* $TITLE=Test12 */
  /* ----------------------------------------------------------------------------------------------------------------------------------------------------------- *\
                                                                             Test number 12.
                                                             Enter bootsel mode (upload-ready) by software.
  \* ----------------------------------------------------------------------------------------------------------------------------------------------------------- */
Test12:
  UINT8 *FlashAddress;

  INT16 ReturnCode;


  /* Flash operation tests. */
  log_printf(__LINE__, __func__, " \n\n\n");
  log_printf(__LINE__, __func__, Separator);
  log_printf(__LINE__, __func__, "<120>Entering Test number 12\n");
  log_printf(__LINE__, __func__, "<120>Flash operation tests.\n");
  log_printf(__LINE__, __func__, Separator);


  win_printf(WIN_TEST, 2, 99, FONT_5x7, "Test 12");

  log_printf(__LINE__, __func__, "Press <G> to erase flash area 0x%X\n", FlashConfig[0]);
  log_printf(__LINE__, __func__, "or <ESC> to cancel operation: ");
  input_string(String, 1, 60000l);
  if ((String[0] == 'G') || (String[0] == 'g'))
  {
    /* Display flash content before erasing. */
    log_printf(__LINE__, __func__, "Optionally display flash data before erasing flash.\n");
    util_display_data(FlashConfig[0], FLASH_SECTOR_SIZE, FLAG_ON);
    sleep_ms(300);

    /* Erase specified flash sector. */
    log_printf(__LINE__, __func__, "Before flash_safe_execute()\n");
    no_op(100);
    FlashTargetOffset = FlashConfigOffset[0];
    ReturnCode = flash_safe_execute(flash_safe_erase, NULL, 500);
    if (DebugBitMask & DEBUG_FLASH) log_printf(__LINE__, __func__, "Returning from flash_safe_execute(), ReturnCode: %d\n", ReturnCode);

    /* Display flash content after erasing. */
    log_printf(__LINE__, __func__, "Optionally display flash data after erasing flash.\n");
    util_display_data(FlashConfig[0], FLASH_SECTOR_SIZE, FLAG_ON);
    sleep_ms(300);
  }



  log_printf(__LINE__, __func__, "Press <G> to write 0x55 in a whole flash sector beginning at flash offset 0x%X\n", FlashConfig[1]);
  log_printf(__LINE__, __func__, "or <ESC> to cancel operation: ");
  input_string(String, 1, 60000l);
  if ((String[0] == 'G') || (String[0] == 'g'))
  {
    /* Display flash content before writing to flash. */
    log_printf(__LINE__, __func__, "Optionally display flash data before writing 0x55 to flash.\n");
    FlashAddress = (UINT8 *)(XIP_BASE + FlashConfigOffset[1]);
    util_display_data(FlashAddress, FLASH_SECTOR_SIZE, FLAG_ON);
    sleep_ms(30);
    log_printf(__LINE__, __func__, "Returning from flash content display...\n");
  
    /* Writing to specified flash sector. */
    FlashTargetOffset = FlashConfigOffset[1];
    log_printf(__LINE__, __func__, "Before flash_safe_execute()\n");
    log_printf(__LINE__, __func__, "FLAG_ON: 0x%2.2X   FLAG_OFF: 0x%2.2X\n", FLAG_ON, FLAG_OFF);
    no_op(100);
    ReturnCode = flash_safe_execute(flash_safe_write, NULL, 500);
    no_op(100);
    if (DebugBitMask & DEBUG_FLASH) log_printf(__LINE__, __func__, "Returning from flash_safe_execute(), ReturnCode: %d     FlagStopCore: 0x%2.2X\n", ReturnCode);
  
    /* Display flash content after writing. */
    log_printf(__LINE__, __func__, "Optionally display flash data after writing to flash.\n");
    util_display_data(FlashAddress, FLASH_SECTOR_SIZE, FLAG_ON);
    sleep_ms(300);
  }

  return;
 






